diffs.replacement:
{
  "name": "Hellycat",
  "description": "A hand-controlled game where you catch a mischievous cat on a paper canvas using your webcam.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import GameEngine from './components/GameEngine';
import { GameState } from './types';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('start');

  return (
    <div className="w-full h-screen flex flex-col items-center justify-center overflow-hidden relative paper-texture selection:bg-none select-none">

      {gameState === 'start' && (
        <div className="z-10 text-center p-8 bg-white/80 backdrop-blur-sm rounded-xl border-4 border-gray-800 shadow-xl max-w-md mx-4">
          <h1 className="text-6xl font-bold mb-4 text-gray-800 tracking-tighter">Hellycat</h1>
          <p className="text-2xl text-gray-700 mb-6 leading-relaxed">
            Use your <span className="font-bold text-orange-600">HAND</span> to catch the cat!
            <br/>
            <span className="text-sm block mt-2 text-gray-600">
              1. Pinch index & thumb to GRAB.<br/>
              2. Drag the cat to the BATHTUB.<br/>
              3. Watch out when it gets MANIC!
            </span>
          </p>
          <button 
            onClick={() => setGameState('playing')}
            className="px-8 py-4 bg-gray-800 text-white text-3xl rounded-lg hover:bg-gray-700 hover:scale-105 transition-all transform border-2 border-transparent hover:border-gray-900 shadow-lg"
          >
            Start Game
          </button>
        </div>
      )}

      {gameState === 'playing' && (
        <GameEngine onGameOver={() => setGameState('gameover')} onWin={() => setGameState('win')} />
      )}

      {gameState === 'gameover' && (
        <div className="z-10 text-center p-8 bg-white/90 rounded-xl border-4 border-red-800 shadow-2xl animate-bounce">
          <h2 className="text-5xl font-bold text-red-600 mb-2">You Died!</h2>
          <p className="text-xl text-gray-700 mb-6">The cat scratched you too much.</p>
          <button 
            onClick={() => setGameState('start')}
            className="px-6 py-3 bg-red-600 text-white text-2xl rounded hover:bg-red-700 transition"
          >
            Try Again
          </button>
        </div>
      )}

      {gameState === 'win' && (
        <div className="z-10 text-center p-8 bg-white/90 rounded-xl border-4 border-blue-600 shadow-2xl">
          <h2 className="text-5xl font-bold text-blue-600 mb-2">Clean Cat!</h2>
          <p className="text-xl text-gray-700 mb-6">You successfully washed the hellycat.</p>
          <button 
            onClick={() => setGameState('start')}
            className="px-6 py-3 bg-blue-600 text-white text-2xl rounded hover:bg-blue-700 transition"
          >
            Play Again
          </button>
        </div>
      )}

      <div className="absolute bottom-4 text-gray-500/50 text-sm">
        Powered by MediaPipe & Gemini
      </div>
    </div>
  );
};

export default App;

export type GameState = 'start' | 'playing' | 'gameover' | 'win';

export type CatMode = 'idle' | 'run' | 'manic' | 'caught';

export interface Point {
  x: number;
  y: number;
}

export interface CatEntity {
  x: number;
  y: number;
  vx: number;
  vy: number;
  mode: CatMode;
  angle: number;
  scale: number;
  thought?: string;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
}

// MediaPipe Types (Simplified)
export interface WindowWithMediaPipe extends Window {
  Hands: any;
  Camera: any;
  drawConnectors: any;
  drawLandmarks: any;
  HAND_CONNECTIONS: any;
}

export const CANVAS_WIDTH = 1280;
export const CANVAS_HEIGHT = 720;

export const CAT_RADIUS = 40;
export const GRAB_THRESHOLD = 50; // Distance between fingers to trigger grab
export const CATCH_DISTANCE = 60; // Distance between grab center and cat
export const MAX_HP = 10;

// Bathtub Zone
export const BATHTUB = {
  x: CANVAS_WIDTH - 250,
  y: CANVAS_HEIGHT - 200,
  width: 220,
  height: 180
};

export const COLORS = {
  bg: '#d2b48c',
  ink: '#2d2d2d',
  pencilWhite: '#f0f0f0',
  red: '#e74c3c',
  blue: '#3498db'
};

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private bgmOscillators: OscillatorNode[] = [];
  private isMuted: boolean = false;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.3;
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  playMeow(pitch = 1) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800 * pitch, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400 * pitch, this.ctx.currentTime + 0.4);

    gain.gain.setValueAtTime(0.2, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.4);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.4);
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // White noise buffer
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    // Filter to make it hiss-like
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // Short burst of noise
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  startBGM() {
    if (!this.ctx || !this.masterGain || this.bgmOscillators.length > 0 || this.isMuted) return;
    // Simple cheerful arpeggio loop
    const notes = [440, 554, 659, 554, 440, 330, 440, 554]; // A major ish
    let noteIndex = 0;

    const playNextNote = () => {
      if (!this.ctx || !this.masterGain || this.isMuted) return;
      const osc = this.ctx.createOscillator();
      const gain = this.ctx.createGain();

      osc.type = 'triangle';
      osc.frequency.value = notes[noteIndex];
      noteIndex = (noteIndex + 1) % notes.length;

      gain.gain.setValueAtTime(0.05, this.ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

      osc.connect(gain);
      gain.connect(this.masterGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 0.25);

      osc.onended = () => {
        // Disconnect cleanly
        osc.disconnect();
        gain.disconnect();
      };

      // Schedule next note using setTimeout for simplicity in this context, 
      // though AudioContext scheduling is more precise.
      setTimeout(playNextNote, 250);
    };

    playNextNote();
  }
}

export const audio = new AudioService();

import { GoogleGenAI } from "@google/genai";
import { CatMode } from "../types";

let ai: GoogleGenAI | null = null;
if (process.env.API_KEY) {
  ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

export const generateCatThought = async (mode: CatMode, hp: number): Promise<string> => {
  if (!ai) return mode === 'manic' ? "HISSSS!" : "Meow~";

  try {
    const prompt = `
      You are a hand-drawn cat in a game called 'Hellycat'. 
      Current state: ${mode}. 
      Player HP: ${hp}/10. 
      The player is trying to grab you with their hand to give you a bath.

      Generate a very short, funny, sassy thought bubble text (max 6 words).
      If Manic: be angry.
      If Idle: be smug or bored.
      If Caught: be panicked.
      If Run: be mocking.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        maxOutputTokens: 20,
        temperature: 1.2,
      }
    });

    return response.text?.trim() || "Meow?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Meow...";
  }
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Camera } from '@mediapipe/camera_utils';
import { Hands, Results } from '@mediapipe/hands';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  COLORS, 
  MAX_HP, 
  GRAB_THRESHOLD, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, WindowWithMediaPipe, Particle, Point } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");

  // Game State Refs (Mutable for loop performance)
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handPosRef = useRef<Point | null>(null);
  const isPinchingRef = useRef<boolean>(false);
  const particlesRef = useRef<Particle[]>([]);
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Helper: Create Particles
  const spawnParticles = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      particlesRef.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        color
      });
    }
  };

  // Helper: Draw Cat
  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);
    // Wobble animation
    const wobble = Math.sin(Date.now() / 100) * 0.1 * (cat.mode === 'run' ? 2 : 1);
    ctx.rotate(cat.angle + wobble);
    ctx.scale(cat.scale, cat.scale);

    // Body
    ctx.beginPath();
    ctx.strokeStyle = COLORS.ink;
    ctx.lineWidth = 3;
    ctx.fillStyle = cat.mode === 'manic' ? COLORS.red : '#FFF';

    // Rough circle for body
    ctx.beginPath();
    ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    // Ears
    ctx.beginPath();
    ctx.moveTo(-20, -25);
    ctx.lineTo(-30, -50);
    ctx.lineTo(-5, -35);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(20, -25);
    ctx.lineTo(30, -50);
    ctx.lineTo(5, -35);
    ctx.fill();
    ctx.stroke();

    // Face
    ctx.fillStyle = COLORS.ink;

    // Eyes
    if (cat.mode === 'manic') {
      // Angry eyes
      ctx.beginPath();
      ctx.moveTo(-15, -10);
      ctx.lineTo(-5, -5);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(15, -10);
      ctx.lineTo(5, -5);
      ctx.stroke();
    } else if (cat.mode === 'caught') {
      // X eyes
      ctx.font = '20px Arial';
      ctx.fillText('x', -18, -5);
      ctx.fillText('x', 8, -5);
    } else {
      // Cute dots
      ctx.beginPath();
      ctx.arc(-10, -10, 3, 0, Math.PI * 2);
      ctx.arc(10, -10, 3, 0, Math.PI * 2);
      ctx.fill();
    }

    // Mouth
    ctx.beginPath();
    if (cat.mode === 'manic') {
      ctx.moveTo(-5, 5);
      ctx.lineTo(0, 0); // Open mouth jagged?
      ctx.lineTo(5, 5);
      ctx.lineTo(0, 10);
      ctx.fill();
    } else {
      ctx.moveTo(0, 0);
      ctx.lineTo(-5, 5);
      ctx.moveTo(0, 0);
      ctx.lineTo(5, 5);
      ctx.stroke();
    }

    // Whiskers
    ctx.beginPath();
    ctx.moveTo(-20, 0); ctx.lineTo(-40, -5);
    ctx.moveTo(-20, 5); ctx.lineTo(-40, 5);
    ctx.moveTo(20, 0); ctx.lineTo(40, -5);
    ctx.moveTo(20, 5); ctx.lineTo(40, 5);
    ctx.stroke();

    // Tail
    ctx.beginPath();
    ctx.moveTo(35, 10);
    ctx.bezierCurveTo(60, 10, 60, -30, 35, -20);
    ctx.stroke();

    ctx.restore();
  };

  // Helper: Draw Bathtub
  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
    ctx.strokeStyle = COLORS.blue;
    ctx.lineWidth = 4;
    ctx.setLineDash([10, 5]); // Sketchy line dash

    ctx.fillRect(BATHTUB.x, BATHTUB.y, BATHTUB.width, BATHTUB.height);
    ctx.strokeRect(BATHTUB.x, BATHTUB.y, BATHTUB.width, BATHTUB.height);

    // Text
    ctx.fillStyle = COLORS.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATHTUB", BATHTUB.x + 60, BATHTUB.y + 100);

    ctx.setLineDash([]);
    ctx.restore();
  };

  // Logic: Update Cat
  const updateCat = (cat: CatEntity, hand: Point | null, pinching: boolean) => {
    const now = Date.now();

    // 1. Check Win Condition
    if (
      cat.x > BATHTUB.x && 
      cat.x < BATHTUB.x + BATHTUB.width && 
      cat.y > BATHTUB.y && 
      cat.y < BATHTUB.y + BATHTUB.height &&
      !pinching // Drop into tub
    ) {
      audio.playSplash();
      onWin();
      return;
    }

    // 2. Grabbing Logic
    if (hand && pinching) {
      const dist = Math.hypot(cat.x - hand.x, cat.y - hand.y);
      if (dist < CATCH_DISTANCE) {
        cat.mode = 'caught';
        cat.x = hand.x;
        cat.y = hand.y + 20; // Hang below hand
        cat.vx = 0;
        cat.vy = 0;

        // Reset manic if caught
        if (manicTimer.current > 0) manicTimer.current = 0;
        return;
      }
    } else {
      if (cat.mode === 'caught') {
        cat.mode = 'run'; // Released
        cat.vx = (Math.random() - 0.5) * 20;
        cat.vy = (Math.random() - 0.5) * 20;
      }
    }

    // 3. Manic Mode Logic
    if (frameCount.current % 600 === 0 && Math.random() > 0.7 && cat.mode !== 'caught') {
      cat.mode = 'manic';
      manicTimer.current = 300; // 5 seconds (60fps)
      audio.playHiss();
      // Trigger Gemini thought for manic
      generateCatThought('manic', hpRef.current).then(t => setCatThought(t));
      lastThoughtTime.current = now;
    }

    if (manicTimer.current > 0) {
      manicTimer.current--;
      if (manicTimer.current <= 0) {
        cat.mode = 'idle';
      }
    }

    // 4. Movement Logic
    const speed = cat.mode === 'manic' ? 8 : (cat.mode === 'run' ? 5 : 2);

    if (cat.mode === 'manic' && hand) {
      // Chase player
      const dx = hand.x - cat.x;
      const dy = hand.y - cat.y;
      const dist = Math.hypot(dx, dy);

      if (dist < 30) {
        // Attack!
        if (frameCount.current % 30 === 0) { // Throttle damage
          hpRef.current -= 1;
          setCurrentHp(hpRef.current);
          spawnParticles(cat.x, cat.y, COLORS.red, 5);
          audio.playScratch();
          if (hpRef.current <= 0) onGameOver();
          // Bounce back
          cat.vx = -dx * 0.5;
          cat.vy = -dy * 0.5;
        }
      } else {
        cat.vx += (dx / dist) * 0.5;
        cat.vy += (dy / dist) * 0.5;
      }
    } else if (hand) {
      // Avoid player
      const dx = cat.x - hand.x;
      const dy = cat.y - hand.y;
      const dist = Math.hypot(dx, dy);

      if (dist < 200) {
        cat.mode = 'run';
        cat.vx += (dx / dist) * 0.8;
        cat.vy += (dy / dist) * 0.8;
      } else if (cat.mode === 'run') {
        // Slow down eventually
        cat.vx *= 0.95;
        cat.vy *= 0.95;
        if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
      }
    }

    // Random wandering if idle
    if (cat.mode === 'idle') {
      if (Math.random() < 0.05) {
        cat.vx += (Math.random() - 0.5) * 2;
        cat.vy += (Math.random() - 0.5) * 2;
      }
    }

    // Apply Velocity
    cat.vx = Math.max(Math.min(cat.vx, speed), -speed);
    cat.vy = Math.max(Math.min(cat.vy, speed), -speed);
    cat.x += cat.vx;
    cat.y += cat.vy;

    // Boundary bounce
    if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
    if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
    if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
    if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }

    // Periodic Gemini Thought
    if (now - lastThoughtTime.current > 12000 && cat.mode !== 'caught') {
      generateCatThought(cat.mode, hpRef.current).then(t => setCatThought(t));
      lastThoughtTime.current = now;
      if (Math.random() > 0.5 && cat.mode === 'idle') {
         audio.playMeow(1.2); // Smug meow
      }
    }
  };

  // MediaPipe Setup
  useEffect(() => {
    audio.resume();
    audio.startBGM();

    const win = window as unknown as WindowWithMediaPipe;
    if (!videoRef.current || !canvasRef.current) return;

    const hands = new win.Hands({
      locateFile: (file: string) => {
        return `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`;
      }
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5
    });

    hands.onResults((results: Results) => {
      // Update logic inside animation frame, but we capture hand data here
      if (results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];

        // MediaPipe coords are 0-1, map to canvas
        // Note: Camera is mirrored, so 1-x
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        const ix = (1 - indexTip.x) * CANVAS_WIDTH;
        const iy = indexTip.y * CANVAS_HEIGHT;
        const tx = (1 - thumbTip.x) * CANVAS_WIDTH;
        const ty = thumbTip.y * CANVAS_HEIGHT;

        // Calculate center of pinch
        const cx = (ix + tx) / 2;
        const cy = (iy + ty) / 2;

        const distance = Math.hypot(ix - tx, iy - ty);
        isPinchingRef.current = distance < GRAB_THRESHOLD;
        handPosRef.current = { x: cx, y: cy };
      } else {
        handPosRef.current = null;
        isPinchingRef.current = false;
      }
    });

    const camera = new win.Camera(videoRef.current, {
      onFrame: async () => {
        if (videoRef.current) {
          await hands.send({ image: videoRef.current });
        }
      },
      width: 640,
      height: 480
    });
    camera.start();

    // Loop
    const render = () => {
      if (!canvasRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      frameCount.current++;

      // Clear
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Draw Bathtub
      drawBathtub(ctx);

      // Update & Draw Cat
      updateCat(catRef.current, handPosRef.current, isPinchingRef.current);
      drawCat(ctx, catRef.current);

      // Draw Hand (Pencil style)
      if (handPosRef.current) {
        ctx.strokeStyle = COLORS.pencilWhite;
        ctx.lineWidth = 5;
        ctx.lineCap = 'round';

        // Draw cursor/hand representation
        ctx.beginPath();
        ctx.arc(handPosRef.current.x, handPosRef.current.y, 10, 0, Math.PI * 2);
        ctx.stroke();

        // Visual feedback for pinch
        if (isPinchingRef.current) {
           ctx.beginPath();
           ctx.arc(handPosRef.current.x, handPosRef.current.y, 25, 0, Math.PI * 2);
           ctx.strokeStyle = COLORS.red;
           ctx.stroke();
        }
      }

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= 0.05;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, 3, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      requestAnimationFrame(render);
    };
    render();

    return () => {
      // Cleanup handled by page refresh mostly in this simple structure
      camera.stop();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      {/* Hidden Video for MP */}
      <video ref={videoRef} className="hidden" />

      {/* Game Canvas */}
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none shadow-inner"
        style={{ mixBlendMode: 'multiply' }}
      />

      {/* UI Overlay */}
      <div className="absolute top-4 left-4 p-4 pointer-events-none">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span>HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all ${i < currentHp ? 'text-red-600 scale-100' : 'text-gray-300 scale-75'}`}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-2 border-black p-4 rounded-xl shadow-lg transition-opacity duration-500"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 80) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap">{catThought}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-2 border-b-2 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      {/* Instructions */}
      <div className="absolute top-4 right-4 text-right pointer-events-none text-gray-700 opacity-60">
        <p>Pinch fingers to GRAB</p>
        <p>Drop in TUB</p>
      </div>
    </div>
  );
};

export default GameEngine;

