import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, Particle, Point } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
}

// Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  paper: '#fdfbf7',
  red: '#e74c3c',
  blue: '#3498db',
  orange: '#e67e22',
  skin: '#f5cba7'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers ---

  // Draw a line with jitter to simulate hand-drawn crayon
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // Draw base line
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // Draw jittery overlay for texture
    ctx.beginPath();
    ctx.lineWidth = width * 0.5;
    ctx.globalAlpha = 0.7;
    const jitter = () => (Math.random() - 0.5) * 2;
    ctx.moveTo(x1 + jitter(), y1 + jitter());
    ctx.lineTo(x2 + jitter(), y2 + jitter());
    ctx.stroke();
    ctx.globalAlpha = 1.0;
  };

  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string) => {
    ctx.save();
    ctx.beginPath();
    ctx.fillStyle = color;
    // Base shape
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    // Scribbles inside
    ctx.strokeStyle = 'rgba(0,0,0,0.1)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    for(let i=0; i<10; i++) {
        const ax = x + (Math.random() - 0.5) * r * 1.5;
        const ay = y + (Math.random() - 0.5) * r * 1.5;
        const bx = x + (Math.random() - 0.5) * r * 1.5;
        const by = y + (Math.random() - 0.5) * r * 1.5;
        ctx.moveTo(ax, ay);
        ctx.lineTo(bx, by);
    }
    ctx.stroke();
    ctx.restore();
  };

  // --- Entity Drawing ---

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body (White porcelain)
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
    ctx.fillStyle = '#d4e6f1';
    ctx.fillRect(x, waterLevel, width, height);

    // Water Scribbles
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 2;
    ctx.beginPath();
    for (let i = x + 10; i < x + width - 10; i += 15) {
        const waveY = waterLevel + 10 + Math.sin(i * 0.1 + frameCount.current * 0.1) * 5;
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 10, waveY);
    }
    ctx.stroke();
    ctx.restore();

    // Rim
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    ctx.strokeRect(x, y, width, height);

    // Bubbles
    if (frameCount.current % 60 < 30) {
        drawScribbleFill(ctx, x + 40, y - 10, 10, '#fff');
        ctx.stroke();
    }
    if (frameCount.current % 50 > 20) {
        drawScribbleFill(ctx, x + width - 30, y - 5, 8, '#fff');
        ctx.stroke();
    }

    // Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATHTUB", x + 60, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Simple Mitten Hand
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    ctx.beginPath();
    if (isGrabbing) {
        // Closed fist (pinching)
        ctx.ellipse(0, 0, 25, 20, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Thumb tucked
        ctx.beginPath();
        ctx.arc(-10, 5, 8, 0, Math.PI * 2);
        ctx.stroke();
    } else {
        // Open hand (palm)
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 20, 0, Math.PI * 2); // Palm
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-15, -5, 5, 15];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -20, 6, 15, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb
        ctx.beginPath();
        ctx.ellipse(-25, 5, 8, 15, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }

    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    if (cat.mode === 'caught') {
        // Dangle physics
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        // Lean forward
        const lean = Math.atan2(cat.vy, cat.vx);
        // Smooth rotation towards velocity
        ctx.rotate(lean * 0.2); // dampen
    } else {
        // Idle breathe
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';
    const bodyColor = isManic ? '#ffcccc' : '#fff';
    const strokeColor = isManic ? CRAYON.red : CRAYON.black;

    // 1. TAIL
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    if (cat.mode === 'caught') {
        // Tail hangs down
        ctx.moveTo(30, 20);
        ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        // Zig zag tail
        ctx.moveTo(35, 10);
        ctx.lineTo(45, -10);
        ctx.lineTo(55, 10);
        ctx.lineTo(65, -10);
    } else if (cat.mode === 'idle') {
        // Wagging tail
        const wag = Math.sin(frameCount.current * 0.1) * 20;
        ctx.moveTo(35, 10);
        ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        // Run tail straight back
        ctx.moveTo(35, 10);
        ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // 2. LEGS
    ctx.lineWidth = 3;
    if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 10;
        // Back legs
        drawCrayonLine(ctx, -20, 20, -20 + legOffset, 40, strokeColor);
        drawCrayonLine(ctx, 20, 20, 20 - legOffset, 40, strokeColor);
    } else if (cat.mode === 'caught') {
        // Dangling legs
        drawCrayonLine(ctx, -15, 25, -20, 45, strokeColor); // Front L
        drawCrayonLine(ctx, 15, 25, 20, 45, strokeColor);   // Front R
        drawCrayonLine(ctx, -10, 35, -15, 65, strokeColor); // Back L
        drawCrayonLine(ctx, 10, 35, 15, 65, strokeColor);   // Back R
    } else {
        // Sitting/Standing
        drawCrayonLine(ctx, -15, 25, -15, 40, strokeColor);
        drawCrayonLine(ctx, 15, 25, 15, 40, strokeColor);
    }

    // 3. BODY
    ctx.beginPath();
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = isManic ? 5 : 3;

    if (isManic) {
        // Spiky body
        ctx.beginPath();
        for (let i = 0; i < Math.PI * 2; i += 0.5) {
            const r = CAT_RADIUS + (Math.random() * 5);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Fluffy circle
        ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }

    // 4. EARS
    ctx.beginPath();
    ctx.fillStyle = bodyColor;
    ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
    ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    ctx.fill();
    ctx.stroke();

    // 5. FACE
    // Eyes
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        ctx.lineWidth = 3;
        // Angry eyebrows
        drawCrayonLine(ctx, -20, -15, -5, -5, CRAYON.red);
        drawCrayonLine(ctx, 20, -15, 5, -5, CRAYON.red);
        // glowing eyes
        ctx.fillStyle = '#ff0';
        ctx.beginPath(); ctx.arc(-12, -8, 4, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(12, -8, 4, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        // X eyes
        ctx.fillStyle = CRAYON.black;
        ctx.font = '20px Arial';
        ctx.fillText('x', -22, 0);
        ctx.fillText('x', 8, 0);
    } else {
        // Cute dots
        ctx.fillStyle = CRAYON.black;
        ctx.beginPath(); ctx.arc(-12, -10, 3, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(12, -10, 3, 0, Math.PI*2); ctx.fill();
    }

    // Mouth & Nose
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 2;
    ctx.beginPath();
    if (isManic) {
        // Hissing mouth
        ctx.moveTo(-10, 5);
        ctx.lineTo(0, 0);
        ctx.lineTo(10, 5);
        ctx.lineTo(0, 15);
        ctx.lineTo(-10, 5);
        ctx.fillStyle = '#000';
        ctx.fill();
    } else {
        // :3 mouth
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); // nose
        ctx.stroke();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 8, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 8, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    ctx.lineWidth = 1;
    drawCrayonLine(ctx, -20, 2, -45, -2, strokeColor, 1);
    drawCrayonLine(ctx, -20, 6, -45, 10, strokeColor, 1);
    drawCrayonLine(ctx, 20, 2, 45, -2, strokeColor, 1);
    drawCrayonLine(ctx, 20, 6, 45, 10, strokeColor, 1);

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      particlesRef.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 12,
        vy: (Math.random() - 0.5) * 12,
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Keyboard Input
    const handleKeyDown = (e: KeyboardEvent) => {
      keysPressed.current[e.code] = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysPressed.current[e.code] = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    // Game Loop
    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // 1. Update Hand (WASD)
      const speed = 8;
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;

      // Friction
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;

      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;

      // Bound Hand
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];

      // 2. Update Cat
      const cat = catRef.current;

      // Check Win
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
        audio.playSplash();
        onWin();
        return;
      }

      // Grab Logic
      const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

      if (isGrabbing && distToHand < CATCH_DISTANCE) {
        if (cat.mode !== 'caught') {
            cat.mode = 'caught';
            // Reset manic if caught
            if (manicTimer.current > 0) manicTimer.current = 0;
        }
        // Follow hand
        cat.x = handRef.current.x;
        cat.y = handRef.current.y + 40; // Dangle below
        cat.vx = 0;
        cat.vy = 0;
      } else {
        if (cat.mode === 'caught') {
            cat.mode = 'run'; // Release
            cat.vx = (Math.random() - 0.5) * 20;
            cat.vy = (Math.random() - 0.5) * 20;
        }
      }

      // Manic Trigger
      if (frameCount.current % 600 === 0 && Math.random() > 0.6 && cat.mode !== 'caught') {
        cat.mode = 'manic';
        manicTimer.current = 240; // 4s
        audio.playHiss();
        generateCatThought('manic', hpRef.current).then(setCatThought);
        lastThoughtTime.current = now;
      }

      if (manicTimer.current > 0) {
        manicTimer.current--;
        if (manicTimer.current <= 0) cat.mode = 'idle';
      }

      // Movement Logic
      if (cat.mode !== 'caught') {
          const moveSpeed = cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2);

          if (cat.mode === 'manic') {
              // Chase Hand
              const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
              cat.vx += Math.cos(angle) * 1;
              cat.vy += Math.sin(angle) * 1;

              if (distToHand < 40 && frameCount.current % 20 === 0) {
                  // Attack
                  hpRef.current--;
                  setCurrentHp(hpRef.current);
                  audio.playScratch();
                  spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                  cat.vx *= -2; // Bounce back
                  cat.vy *= -2;
                  if (hpRef.current <= 0) onGameOver();
              }
          } else {
              // Avoid Hand
              if (distToHand < 250) {
                  cat.mode = 'run';
                  const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                  cat.vx += Math.cos(angle) * 0.8;
                  cat.vy += Math.sin(angle) * 0.8;
              } else if (cat.mode === 'run') {
                  cat.vx *= 0.92;
                  cat.vy *= 0.92;
                  if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
              }

              if (cat.mode === 'idle') {
                   // Random twitch
                   if (Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                   }
              }
          }

          // Physics Apply
          cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
          cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
          cat.x += cat.vx;
          cat.y += cat.vy;

          // Wall Bounce
          if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
          if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
          if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
          if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught') {
          if (cat.mode === 'idle' && Math.random() > 0.6) {
             generateCatThought('idle', hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             audio.playMeow(1.0 + Math.random() * 0.5);
          } else if (cat.mode === 'run' && Math.random() > 0.7) {
             generateCatThought('run', hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
          }
      }

      // --- Draw Frame ---
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Draw Bathtub
      drawBathtub(ctx);

      // Draw Cat
      drawCat(ctx, cat);

      // Draw Hand
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        // Rough particle
        ctx.moveTo(p.x, p.y);
        ctx.lineTo(p.x + 5, p.y + 2);
        ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.1) sepia(0.2)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/50 backdrop-blur rounded-lg border-2 border-black rotate-1">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-red-600 scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
