import { GoogleGenAI } from "@google/genai";
import { CatMode } from "../types";

let ai: GoogleGenAI | null = null;
if (process.env.API_KEY) {
  ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

// Fallback messages when API is unavailable or rate-limited
const FALLBACKS = {
  idle: ["Meow.", "Nap time...", "Boring.", "Prrr...", "Hungry.", "Zzz..."],
  run: ["Can't catch me!", "Too slow!", "Missed!", "Zoom!", "Haha!", "Nope!"],
  manic: ["HISSS!", "GRRR!", "NO BATH!", "WRATH!", "ANGER!", "SCRATCH!"],
  caught: ["UNHAND ME!", "NOOO!", "HELP!", "LET GO!", "MEOOOOW!", "DOOMED!"]
};

let lastCallTime = 0;
const MIN_INTERVAL = 4000; // Minimum 4 seconds between API calls locally
let errorBackoff = 0; // Additional wait time if we hit errors

const getRandomFallback = (mode: CatMode): string => {
  const list = FALLBACKS[mode] || FALLBACKS['idle'];
  return list[Math.floor(Math.random() * list.length)];
};

export const generateCatThought = async (mode: CatMode, hp: number): Promise<string> => {
  // If no key, return fallback immediately
  if (!ai) return getRandomFallback(mode);

  const now = Date.now();

  // Check if we are calling too fast or currently backing off from an error
  if (now - lastCallTime < MIN_INTERVAL + errorBackoff) {
    return getRandomFallback(mode);
  }

  try {
    lastCallTime = now;

    const prompt = `
      You are a hand-drawn cat in a game called 'Hellycat'. 
      Current state: ${mode}. 
      Player HP: ${hp}/10. 
      The player is trying to grab you with their hand to give you a bath.

      Generate a very short, funny, sassy thought bubble text (max 5 words).
      If Manic: be angry/hissing.
      If Idle: be smug/bored/cute.
      If Caught: be panicked/drama queen.
      If Run: be mocking/fast.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        maxOutputTokens: 20,
        temperature: 1.1,
      }
    });

    const text = response.text?.trim();
    if (text) {
      // Reset backoff on success
      errorBackoff = 0;
      return text;
    }
    return getRandomFallback(mode);

  } catch (error: any) {
    // Quietly handle errors and use fallbacks
    console.warn("Gemini API unavailable, using fallback.");

    // Check for rate limit error codes (429)
    if (error.status === 429 || error.code === 429 || (error.message && error.message.includes('429'))) {
       // Exponential backoff: add 10s, max 60s
       errorBackoff = Math.min(errorBackoff + 10000, 60000); 
    }

    return getRandomFallback(mode);
  }
};

export type GameState = 'start' | 'playing' | 'gameover' | 'win';

export type CatMode = 'idle' | 'run' | 'manic' | 'caught';

export type CatType = 'white' | 'black' | 'tuxedo' | 'calico';

export interface Point {
  x: number;
  y: number;
}

export interface CatEntity {
  x: number;
  y: number;
  vx: number;
  vy: number;
  mode: CatMode;
  angle: number;
  scale: number;
  thought?: string;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  text?: string; // For floating text like "OUCH!"
}

// MediaPipe Types (Simplified)
export interface WindowWithMediaPipe extends Window {
  Hands: any;
  Camera: any;
  drawConnectors: any;
  drawLandmarks: any;
  HAND_CONNECTIONS: any;
}

export const CANVAS_WIDTH = 1280;
export const CANVAS_HEIGHT = 720;

export const CAT_RADIUS = 40;
export const GRAB_THRESHOLD = 50; // Distance between fingers to trigger grab
export const CATCH_DISTANCE = 60; // Distance between grab center and cat
export const MAX_HP = 10;

// Bathtub Zone
export const BATHTUB = {
  x: CANVAS_WIDTH - 250,
  y: CANVAS_HEIGHT - 200,
  width: 220,
  height: 180
};

