  rug: '#B5C7D3',        // Muted Blue
  rugOutline: '#94A6B5',
  rugPattern: '#E0E5E9',
  windowFrame: '#A69C8E', // Muted Wood
  windowGlass: '#C8D6D9', // Muted Sky
  wall: '#E8E6E1',
  plantLeaf: '#8FA891',   // Sage Green
  plantPot: '#D4B5B0',    // Dusty Pink
  skin: '#EAC8B8',        // Muted Skin tone
  handOutline: '#5D5650', // Soft Charcoal
  water: '#C0D5DB',       // Greyish Blue water
  waterDeep: '#A0BCC4',
};

