           {/* Animated Cat sitting on top */}
           <div 
             className="absolute -top-32 left-1/2 transform -translate-x-1/2 cursor-pointer transition-transform active:scale-95 z-20"
             onClick={() => audio.playMeow()}
           >
             <StartCat catType={selectedCat} />
           </div>

          <div className="text-center p-8 bg-[#F2F0EB] rounded-lg border-[6px] border-[#4A4A4A] shadow-[12px_12px_0px_0px_rgba(148,166,181,0.4)] mx-4 rotate-1 relative overflow-visible">
            {/* Tape Effect */}
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-32 h-10 bg-[#E0D8C8]/80 transform -rotate-2 backdrop-blur-sm border-l border-r border-white/50"></div>

            <h1 className="text-8xl font-bold mb-4 tracking-tighter text-[#4A4A4A]" style={{ textShadow: '3px 3px 0px #fff' }}>
              Hellycat
            </h1>

            <p className="text-2xl mb-6 font-bold text-[#6D6D6D]">
              Choose your trouble maker:
            </p>

            {/* Cat Selector */}
            <div className="flex justify-center gap-4 mb-8">
              {(['white', 'black', 'tuxedo', 'calico'] as CatType[]).map((type) => (
                <button
                  key={type}
                  onClick={() => {
                    setSelectedCat(type);
                    audio.playMeow(1.2);
                  }}
                  className={`w-16 h-16 rounded-full border-4 transition-all transform hover:scale-110 ${
                    selectedCat === type ? 'border-[#E74C3C] scale-110 ring-4 ring-[#E74C3C]/30' : 'border-[#4A4A4A] bg-white'
                  }`}
                  style={{
                    backgroundColor: type === 'black' ? '#333' : '#fff',
                    backgroundImage: type === 'tuxedo' 
                      ? 'linear-gradient(135deg, #333 50%, #fff 50%)' 
                      : type === 'calico' 
                        ? 'radial-gradient(circle at 30% 30%, #E6A07C 20%, transparent 20%), radial-gradient(circle at 70% 70%, #333 20%, transparent 20%)'
                        : undefined
                  }}
                  title={type}
                />
              ))}
            </div>

            <div className="flex justify-center gap-6 mb-8 text-lg font-bold">
               <div className="flex flex-col items-center bg-white/50 p-3 rounded-xl border-2 border-dashed border-[#A69C8E]">
                 <span className="text-3xl mb-1">⌨️</span>
                 <span className="text-[#8FA891]">WASD</span>
               </div>
               <div className="flex flex-col items-center bg-white/50 p-3 rounded-xl border-2 border-dashed border-[#A69C8E]">
                 <span className="text-3xl mb-1">✊</span>
                 <span className="text-[#8FA891]">SPACE</span>
               </div>
               <div className="flex flex-col items-center bg-white/50 p-3 rounded-xl border-2 border-dashed border-[#A69C8E]">
                 <span className="text-3xl mb-1">🛁</span>
                 <span className="text-[#94A6B5]">TUB</span>
               </div>
            </div>

            <button 
              onClick={() => {
                audio.playMeow();
                setGameState('playing');
              }}
              className="px-10 py-3 bg-[#4A4A4A] text-[#F2F0EB] text-3xl rounded-xl hover:scale-105 hover:bg-[#5D5650] transition-all transform shadow-lg font-bold"
            >
              Start Catching!
            </button>
          </div>
        </div>
      )}

      {gameState === 'playing' && (
        <GameEngine catType={selectedCat} onGameOver={() => setGameState('gameover')} onWin={() => setGameState('win')} />
      )}

      {gameState === 'gameover' && (
        <div className="z-10 text-center p-12 bg-[#F2F0EB] rounded-lg border-[6px] border-[#D4B5B0] shadow-2xl animate-bounce -rotate-1 relative">
           <div className="absolute -top-4 -left-4 w-12 h-12 rounded-full bg-[#EAC8B8] border-2 border-[#D4B5B0]"></div>
           <div className="absolute -bottom-4 -right-4 w-12 h-12 rounded-full bg-[#EAC8B8] border-2 border-[#D4B5B0]"></div>

          <h2 className="text-8xl font-bold text-[#D4B5B0] mb-4 font-sketch">OUCH!</h2>
          <p className="text-3xl text-[#6D6D6D] mb-8">The cat scratched you too much.</p>
          <button 
            onClick={() => setGameState('start')}
            className="px-8 py-4 bg-[#D4B5B0] text-white text-3xl rounded-xl hover:bg-[#c99e98] transition shadow-lg font-bold"
          >
            Try Again
          </button>
        </div>
      )}

      {gameState === 'win' && (
        <div className="z-10 text-center p-12 bg-[#F2F0EB] rounded-lg border-[6px] border-[#94A6B5] shadow-2xl rotate-1 relative">
          <div className="absolute -top-8 left-1/2 transform -translate-x-1/2 text-6xl animate-pulse">✨</div>
          <h2 className="text-7xl font-bold text-[#94A6B5] mb-4">SQUEAKY CLEAN!</h2>
          <p className="text-3xl text-[#6D6D6D] mb-8">You successfully bathed the cat!</p>
          <button 
            onClick={() => setGameState('start')}
            className="px-8 py-4 bg-[#94A6B5] text-white text-3xl rounded-xl hover:bg-[#7e92a3] transition shadow-lg font-bold"
          >
            Play Again
          </button>
        </div>
      )}

      <div className="absolute bottom-4 text-[#A69C8E] font-bold text-lg opacity-50 mix-blend-multiply">
        Powered by Gemini
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE,
  MORANDI
} from '../constants';
import { CatEntity, Particle, Point, CatType } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
  catType: CatType;
}

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const winSequenceRef = useRef<number>(0); 

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); 
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers (Rough texture) ---

  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Texture underlay
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.5;
    ctx.lineWidth = width * 1.5;
    const jitter1 = () => (Math.random() - 0.5) * 2;
    // Broken line effect
    let dist = Math.hypot(x2 - x1, y2 - y1);
    let steps = dist / 5;
    let dx = (x2 - x1) / steps;
    let dy = (y2 - y1) / steps;

    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    for(let i=1; i<=steps; i++) {
        if (Math.random() > 0.2) {
             ctx.lineTo(x1 + dx * i + jitter1(), y1 + dy * i + jitter1());
        } else {
             ctx.moveTo(x1 + dx * i + jitter1(), y1 + dy * i + jitter1());
        }
    }
    ctx.stroke();

    // 2. Main solid line with wobble
    ctx.beginPath();
    ctx.globalAlpha = 0.9;
    ctx.lineWidth = width;
    const jitter2 = () => (Math.random() - 0.5) * 1;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();

    ctx.globalAlpha = 1.0;
  };

  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string) => {
    ctx.save();
    ctx.fillStyle = color;
    // Rough circle
    ctx.beginPath();
    for (let i = 0; i <= Math.PI * 2; i += 0.5) {
        let ro = r + (Math.random() - 0.5) * 2;
        ctx.lineTo(x + Math.cos(i) * ro, y + Math.sin(i) * ro);
    }
    ctx.fill();

    // Internal scribbles
    ctx.strokeStyle = 'rgba(0,0,0,0.05)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    for(let i=0; i<5; i++) {
        const ax = x + (Math.random() - 0.5) * r;
        const ay = y + (Math.random() - 0.5) * r;
        const bx = x + (Math.random() - 0.5) * r;
        const by = y + (Math.random() - 0.5) * r;
        ctx.moveTo(ax, ay);
        ctx.lineTo(bx, by);
    }
    ctx.stroke();
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor (Morandi BG)
    ctx.fillStyle = MORANDI.bg; 
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = MORANDI.floorLines;
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 80) {
        drawCrayonLine(ctx, 0, i, CANVAS_WIDTH, i, MORANDI.floorLines, 2);
    }

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.05);
    ctx.fillStyle = MORANDI.rug; 
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fill();

    ctx.lineWidth = 4;
    ctx.strokeStyle = MORANDI.rugOutline;
    ctx.stroke();

    // Rug pattern (zig zag)
    ctx.beginPath();
    ctx.strokeStyle = MORANDI.rugPattern;
    ctx.lineWidth = 3;
    for(let i = -200; i < 200; i+= 40) {
        ctx.moveTo(i, -100);
        ctx.lineTo(i+20, 100);
    }
    ctx.stroke();
    ctx.restore();

    // Window
    ctx.save();
    ctx.translate(120, 100);
    ctx.fillStyle = MORANDI.windowGlass;
    ctx.fillRect(0, 0, 180, 180);

    ctx.strokeStyle = MORANDI.windowFrame;
    ctx.lineWidth = 6;
    ctx.strokeRect(0, 0, 180, 180);
    drawCrayonLine(ctx, 90, 0, 90, 180, MORANDI.windowFrame, 6);
    drawCrayonLine(ctx, 0, 90, 180, 90, MORANDI.windowFrame, 6);

    // Cloud
    drawScribbleFill(ctx, 40, 40, 25, '#fff');
    drawScribbleFill(ctx, 140, 60, 30, '#fff');
    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 120, 100);
    // Leaves
    ctx.fillStyle = MORANDI.plantLeaf;
    [0, 1, 2].forEach(i => {
        ctx.beginPath();
        ctx.ellipse((i-1)*20, -50 + Math.abs(i-1)*10, 25, 50, (i-1)*0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.strokeStyle = '#5D6D5E';
        ctx.stroke();
    });
    // Pot
    ctx.fillStyle = MORANDI.plantPot;
    ctx.beginPath();
    ctx.moveTo(-25, 0); ctx.lineTo(25, 0); ctx.lineTo(15, 50); ctx.lineTo(-15, 50);
    ctx.fill();
    ctx.strokeStyle = '#8C706B';
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Feet
    const feetColor = '#4A4A4A';
    drawCrayonLine(ctx, x + 25, y + height, x + 25, y + height + 20, feetColor, 4);
    drawCrayonLine(ctx, x + width - 25, y + height, x + width - 25, y + height + 20, feetColor, 4);

    // Tub Body
    ctx.fillStyle = '#FFFFFF';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = MORANDI.waterDeep;
    ctx.lineWidth = 3;
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 45 + Math.sin(frameCount.current * 0.05) * 4;
    ctx.fillStyle = MORANDI.water;
    ctx.fillRect(x, waterLevel, width, height);

    // Ripples
    ctx.strokeStyle = MORANDI.waterDeep;
    ctx.lineWidth = 2;
    for (let i = x + 15; i < x + width - 15; i += 25) {
        const waveY = waterLevel + 10 + Math.sin(i * 0.2 + frameCount.current * 0.1) * 4;
        ctx.beginPath();
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 15, waveY);
        ctx.stroke();
    }
    ctx.restore();

    // Tub Label
    ctx.fillStyle = MORANDI.waterDeep;
    ctx.font = '28px "Patrick Hand"';
    ctx.fillText("BATH", x + 80, y + height - 25);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    ctx.fillStyle = MORANDI.skin;
    ctx.strokeStyle = MORANDI.handOutline;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 32, 28, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Details
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 12, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 28, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        [-20, -7, 7, 20].forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -28, 9, 20, 0, 0, Math.PI * 2);
            ctx.fillStyle = MORANDI.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb
        ctx.beginPath();
        ctx.ellipse(-32, 12, 11, 20, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Animation Transforms
    if (winSequenceRef.current > 0) {
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (cat.mode === 'caught') {
        ctx.rotate(Math.sin(frameCount.current * 0.2) * 0.15);
    } else if (cat.mode === 'run') {
        ctx.rotate(Math.atan2(cat.vy, cat.vx) * 0.3);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.08) * 0.03);
    }

    const isManic = cat.mode === 'manic';

    // --- Determine Colors based on Type & Mode ---
    let bodyColor = '#FFFFFF';
    let strokeColor = '#4A4A4A';
    let eyeColor = '#4A4A4A';

    if (isManic) {
        // Unified Angry Color
        bodyColor = '#DFA6A6'; // Muted Red
        strokeColor = '#8B0000'; // Deep Red
        eyeColor = '#FFFFE0'; // Pale Yellow
    } else {
        switch (catType) {
            case 'black':
                bodyColor = '#3A3A3A';
                strokeColor = '#1A1A1A';
                eyeColor = '#FFFFFF';
                break;
            case 'white':
                bodyColor = '#FFFFFF';
                strokeColor = '#4A4A4A';
                break;
            case 'tuxedo':
            case 'calico':
                bodyColor = '#FFFFFF'; // Base
                strokeColor = '#4A4A4A';
                break;
        }
    }

    // --- TAIL ---
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 6;
    ctx.lineCap = 'round';

    // Tail Logic
    if (isManic) {
         ctx.moveTo(35, 10); ctx.lineTo(55, -25); ctx.lineTo(75, 15); // Spiky
    } else if (catType === 'black' || (catType === 'tuxedo')) {
         // Black tail
         ctx.strokeStyle = '#3A3A3A';
         if (cat.mode === 'caught') {
            ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
         } else {
            const wag = Math.sin(frameCount.current * 0.15) * 15;
            ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
         }
    } else {
         if (cat.mode === 'caught') {
            ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
         } else {
            const wag = Math.sin(frameCount.current * 0.15) * 15;
            ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
         }
    }
    ctx.stroke();

    // --- LEGS ---
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, strokeColor, 4);
    };

    // Leg Animation
    let lo = 0; // Leg offset
    if (cat.mode === 'run' || cat.mode === 'manic') lo = Math.sin(frameCount.current * 0.8) * 10;

    // Back Legs
    drawLeg(-20, 20, -25 + lo, 45);
    drawLeg(20, 20, 25 - lo, 45);

    // --- BODY ---
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky shape
        for (let i = 0; i < Math.PI * 2; i += 0.5) {
            const r = CAT_RADIUS + (Math.random() * 5);
            ctx.lineTo(Math.cos(i) * r, Math.sin(i) * r * 0.85);
        }
    } else {
        ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
    }
    ctx.closePath();
    ctx.fill();

    // --- PATTERNS (If not manic) ---
    if (!isManic) {
        if (catType === 'black') {
            ctx.fillStyle = '#3A3A3A';
            ctx.fill();
        } else if (catType === 'tuxedo') {
            // Black Body Base
            ctx.fillStyle = '#3A3A3A';
            ctx.fill();
            // White Belly
            ctx.fillStyle = '#FFFFFF';
            ctx.beginPath();
            ctx.ellipse(0, 15, 25, 20, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // White base is already there. Add splotches.
            ctx.fillStyle = '#E6A07C'; // Orange
            ctx.beginPath(); ctx.arc(-20, -10, 15, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(15, 20, 12, 0, Math.PI*2); ctx.fill();

            ctx.fillStyle = '#3A3A3A'; // Black
            ctx.beginPath(); ctx.arc(20, -15, 10, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(-10, 25, 8, 0, Math.PI*2); ctx.fill();
        }
    }

    // Body Stroke
    ctx.stroke();

    // --- EARS ---
    // Left Ear
    ctx.beginPath();
    ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
    // Color logic for ears
    if (!isManic) {
       if (catType === 'black' || catType === 'tuxedo') ctx.fillStyle = '#3A3A3A';
       else if (catType === 'calico') ctx.fillStyle = '#E6A07C'; // Orange ear
       else ctx.fillStyle = '#FFFFFF';
    } else {
       ctx.fillStyle = bodyColor;
    }
    ctx.fill(); ctx.stroke();

    // Right Ear
    ctx.beginPath();
    ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    if (!isManic) {
       if (catType === 'black' || catType === 'tuxedo') ctx.fillStyle = '#3A3A3A';
       else if (catType === 'calico') ctx.fillStyle = '#3A3A3A'; // Black ear
       else ctx.fillStyle = '#FFFFFF';
    } else {
       ctx.fillStyle = bodyColor;
    }
    ctx.fill(); ctx.stroke();


    // --- FACE ---
    if (isManic) {
        ctx.strokeStyle = strokeColor; // Dark red
        // Angry Eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, strokeColor, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, strokeColor, 3);
        ctx.fillStyle = eyeColor;
        ctx.beginPath(); ctx.arc(-18, -8, 4, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(18, -8, 4, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -14, 5);
    } else if (winSequenceRef.current > 0) {
        // Happy Eyes
        ctx.strokeStyle = eyeColor;
        ctx.lineWidth = 3;
        ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
    } else {
        // Normal Eyes
        ctx.fillStyle = eyeColor;
        ctx.beginPath(); ctx.arc(-14, -10, 4, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(14, -10, 4, 0, Math.PI*2); ctx.fill();
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        if (catType === 'black' || catType === 'tuxedo') ctx.strokeStyle = '#666'; // Lighter mouth for black cats
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    ctx.strokeStyle = (catType === 'black' || catType === 'tuxedo') && !isManic ? '#888' : strokeColor;
    ctx.lineWidth = 1;
    drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' | 'text' = 'sparkle', text?: string) => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : (type === 'text' ? 2 : 12)),
        vy: (type === 'text' ? -2 : (Math.random() - 0.5) * 12 - (type === 'bubble' ? 2 : 0)),
        life: 1.0,
        color,
        text
      });
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Screen
      drawRoom(ctx);

      // Win Sequence
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        if (frameCount.current % 5 === 0) spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');

        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; p.x += Math.sin(p.y * 0.1) * 0.5; p.life -= 0.01;
            ctx.beginPath();
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) onWin();
        animationFrameId = requestAnimationFrame(loop);
        return; 
      }

      // --- Normal Loop ---

      // Hand Move
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85; handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx; handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // Drop in Tub
      if (
        cat.x > BATHTUB.x && cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing && cat.mode === 'caught'
      ) {
        audio.playSplash();
        winSequenceRef.current = 180;
      }

      // Cat Physics
      if (winSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          if (isGrabbing && distToHand < CATCH_DISTANCE) {
            if (cat.mode !== 'caught') { cat.mode = 'caught'; manicTimer.current = 0; }
            cat.x = handRef.current.x; cat.y = handRef.current.y + 40;
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20; cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Trigger
          if (frameCount.current % 600 === 0 && Math.random() > 0.6 && cat.mode !== 'caught') {
            cat.mode = 'manic'; manicTimer.current = 240; audio.playHiss();
            generateCatThought('manic', hpRef.current).then(setCatThought);
            lastThoughtTime.current = now;
          }
          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Move Logic
          if (cat.mode !== 'caught') {
              const moveSpeed = cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2);
              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1; cat.vy += Math.sin(angle) * 1;

                  // Damage logic
                  if (distToHand < 40 && frameCount.current % 20 === 0) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, '#DFA6A6', 8); // Red sparkles
                      spawnParticles(handRef.current.x, handRef.current.y - 20, '#DFA6A6', 1, 'text', 'OUCH!'); // OUCH text
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) onGameOver();
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8; cat.vy += Math.sin(angle) * 0.8;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4; cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx; cat.y += cat.vy;
              // Bounds
              if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
              if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
          }
      }

      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      drawBathtub(ctx);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Render Particles (Sparkles + Text)
      particlesRef.current.forEach((p) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;

        if (p.text) {
             ctx.fillStyle = '#DFA6A6';
             ctx.font = 'bold 28px "Patrick Hand"';
             ctx.fillText(p.text, p.x, p.y);
        } else {
             ctx.fillStyle = p.color;
             ctx.beginPath();
             ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
             ctx.fill();
        }
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };
    animationFrameId = requestAnimationFrame(loop);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />
      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-[#4A4A4A] rotate-1 shadow-md">
        <div className="text-4xl font-bold text-[#4A4A4A] flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#DFA6A6] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>
      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-[#4A4A4A] p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-[#4A4A4A] whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-[#4A4A4A] transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}
    </div>
  );
};

export default GameEngine;

export type GameState = 'start' | 'playing' | 'gameover' | 'win';

export type CatMode = 'idle' | 'run' | 'manic' | 'caught';

export type CatType = 'white' | 'black' | 'tuxedo' | 'calico';

export interface Point {
  x: number;
  y: number;
}

export interface CatEntity {
  x: number;
  y: number;
  vx: number;
  vy: number;
  mode: CatMode;
  angle: number;
  scale: number;
  thought?: string;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
}

// MediaPipe Types (Simplified)
export interface WindowWithMediaPipe extends Window {
  Hands: any;
  Camera: any;
  drawConnectors: any;
  drawLandmarks: any;
  HAND_CONNECTIONS: any;
}

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, Particle, Point, CatType } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
  catType: CatType;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    const jitter1 = () => (Math.random() - 0.5) * 3;
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 1.5;
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    // Texture
    ctx.strokeStyle = 'rgba(0,0,0,0.1)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    for(let i=0; i<6; i++) {
        const ax = x + (Math.random() - 0.5) * r;
        const ay = y + (Math.random() - 0.5) * r;
        const bx = x + (Math.random() - 0.5) * r;
        const by = y + (Math.random() - 0.5) * r;
        ctx.moveTo(ax, ay);
        ctx.lineTo(bx, by);
    }
    ctx.stroke();
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*2));
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*2));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1);
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();
    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();

    // Window
    ctx.save();
    ctx.translate(100, 100);
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();
    // Clouds
    drawScribbleFill(ctx, 40, 50, 30, '#fff');
    drawScribbleFill(ctx, 150, 80, 40, '#fff');
    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);
    // Leaves
    ctx.fillStyle = CRAYON.green;
    ctx.beginPath();
    ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
    ctx.fill();
    // Pot
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
    ctx.fillStyle = '#a5d8ff';
    ctx.fillRect(x, waterLevel, width, height);

    // Water details
    ctx.strokeStyle = '#74c0fc';
    ctx.lineWidth = 3;
    ctx.beginPath();
    for (let i = x + 10; i < x + width - 10; i += 20) {
        const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 12, waveY);
    }
    ctx.stroke();
    ctx.restore();

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // Color Logic
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    if (isManic) {
        bodyColor = '#ffcccc'; // Angry pink
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00'; // Crazy yellow
    } else {
        switch (catType) {
            case 'black':
                bodyColor = '#3d3d3d';
                strokeColor = '#1a1a1a';
                eyeColor = '#fff';
                break;
            case 'tuxedo':
                bodyColor = '#3d3d3d'; // Base body black
                strokeColor = '#1a1a1a';
                eyeColor = '#fff';
                break;
            case 'calico':
                bodyColor = '#fff';
                strokeColor = CRAYON.black;
                eyeColor = CRAYON.black;
                break;
            case 'white':
            default:
                bodyColor = '#fff';
                strokeColor = CRAYON.black;
                eyeColor = CRAYON.black;
                break;
        }
    }

    // TAIL
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Determine tail path
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS
    ctx.lineWidth = 4;
    ctx.strokeStyle = strokeColor;
    // Helper to draw legs
    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, strokeColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();
    if (isManic) {
        // Spiky
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
    }
    ctx.closePath();
    ctx.fill();

    // Patterns (Only if not manic)
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Calico patches
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange);
            drawScribbleFill(ctx, 18, 10, 10, '#3d3d3d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        }
    }

    ctx.stroke();

    // EARS
    // Left Ear
    ctx.beginPath();
    ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
    ctx.fillStyle = (!isManic && (catType === 'black' || catType === 'tuxedo')) ? '#3d3d3d' : bodyColor;
    ctx.fill();
    ctx.stroke();

    // Right Ear
    ctx.beginPath();
    ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    ctx.fillStyle = (!isManic && (catType === 'black' || catType === 'tuxedo')) ? '#3d3d3d' : bodyColor;
    ctx.fill();
    ctx.stroke();

    // FACE
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = eyeColor;
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else if (winSequenceRef.current > 0) {
        // Happy Eyes ^ ^
        ctx.strokeStyle = eyeColor;
        ctx.lineWidth = 3;
        ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
    } else {
        // Normal dots
        ctx.fillStyle = eyeColor;
        ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        if (catType === 'black' || catType === 'tuxedo') ctx.strokeStyle = '#999'; // Lighter mouth on dark fur

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    ctx.lineWidth = 1;
    ctx.strokeStyle = strokeColor;
    if (!isManic && (catType === 'black' || catType === 'tuxedo')) ctx.strokeStyle = '#999'; // Lighter whiskers on dark fur

    drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
    drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Screen (Draw Room)
      drawRoom(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      }

      // Normal Game Logic

      // 1. Update Hand
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // 2. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
        audio.playSplash();
        winSequenceRef.current = 180; // 3 seconds at 60fps
        // Don't return, let the next frame handle the sequence
      }

      // 3. Cat Physics & AI
      if (winSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // Grab Logic
          if (isGrabbing && distToHand < CATCH_DISTANCE) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40;
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic
          if (frameCount.current % 600 === 0 && Math.random() > 0.6 && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              const moveSpeed = cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2);

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1;
                  cat.vy += Math.sin(angle) * 1;

                  if (distToHand < 40 && frameCount.current % 20 === 0) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) onGameOver();
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8;
                      cat.vy += Math.sin(angle) * 0.8;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries
              if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
              if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}
    </div>
  );
};

