// Mini component to draw the Start Screen Cat
const StartCat: React.FC<{ catType: CatType }> = ({ catType }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const frameRef = useRef(0);

  useEffect(() => {
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;

    const render = () => {
      frameRef.current++;
      const f = frameRef.current;
      ctx.clearRect(0, 0, 300, 200);

      ctx.save();
      ctx.translate(150, 150);
      const scale = 1 + Math.sin(f * 0.05) * 0.02;
      ctx.scale(scale, scale);

      // Colors based on type
      let bodyFill = '#fff';
      let strokeStyle = '#2d2d2d';

      if (catType === 'black') {
        bodyFill = '#3d3d3d';
      } else if (catType === 'tuxedo') {
        bodyFill = '#3d3d3d';
      }

      // Tail Wag
      ctx.beginPath();
      ctx.strokeStyle = (catType === 'black' || catType === 'tuxedo') ? '#3d3d3d' : '#2d2d2d';
      ctx.lineWidth = 4;
      ctx.lineCap = 'round';
      const tailWag = Math.sin(f * 0.1) * 20;
      ctx.moveTo(35, 10);
      ctx.bezierCurveTo(60, 10, 60 + tailWag, -40, 35, -30);
      ctx.stroke();

      // Body Base
      ctx.fillStyle = bodyFill;
      ctx.strokeStyle = '#2d2d2d';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.ellipse(0, 0, 45, 40, 0, 0, Math.PI * 2);
      ctx.fill();

      // Patterns
      if (catType === 'tuxedo') {
        // White belly
        ctx.fillStyle = '#fff';
        ctx.beginPath();
        ctx.ellipse(0, 10, 25, 25, 0, 0, Math.PI * 2);
        ctx.fill();
      } else if (catType === 'calico') {
        // Splotches
        ctx.fillStyle = '#e67e22'; // Orange
        ctx.beginPath(); ctx.arc(-15, -15, 12, 0, Math.PI*2); ctx.fill();
        ctx.fillStyle = '#2d2d2d'; // Black
        ctx.beginPath(); ctx.arc(20, 10, 10, 0, Math.PI*2); ctx.fill();
        ctx.fillStyle = '#e67e22'; 
        ctx.beginPath(); ctx.arc(15, -20, 8, 0, Math.PI*2); ctx.fill();
      }

      ctx.stroke();

      // Ears
      ctx.fillStyle = (catType === 'black' || catType === 'tuxedo') ? '#3d3d3d' : '#fff';
      if (catType === 'calico') ctx.fillStyle = '#fff'; // Simplification for calico ears
      ctx.beginPath();
      ctx.moveTo(-20, -30); ctx.lineTo(-35, -60); ctx.lineTo(-5, -40);
      ctx.fill(); ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(20, -30); ctx.lineTo(35, -60); ctx.lineTo(5, -40);
      ctx.fill(); ctx.stroke();

      // Face (Squinting Happy Eyes)
      const eyeColor = catType === 'black' ? '#fff' : '#2d2d2d';
      ctx.strokeStyle = eyeColor;
      ctx.lineWidth = 3;

      // Left Eye
      ctx.beginPath();
      ctx.moveTo(-25, -10); ctx.lineTo(-15, -20); ctx.lineTo(-5, -10);
      ctx.stroke();
      // Right Eye
      ctx.beginPath();
      ctx.moveTo(5, -10); ctx.lineTo(15, -20); ctx.lineTo(25, -10);
      ctx.stroke();

      // Blush
      ctx.fillStyle = 'rgba(255, 182, 193, 0.6)'; 
      ctx.beginPath(); ctx.arc(-25, 5, 8, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(25, 5, 8, 0, Math.PI*2); ctx.fill();

      // Mouth
      ctx.strokeStyle = eyeColor;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(0, 0); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, 0);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 8, -10, 5);
      ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 8, 10, 5);
      ctx.stroke();

      // Meow Bubble
      if (f % 200 < 60) {
        ctx.fillStyle = '#2d2d2d';
        ctx.font = '24px "Patrick Hand"';
        ctx.fillText("Meow~", 50, -60);
      }

      ctx.restore();
      requestAnimationFrame(render);
    };
    render();
  }, [catType]);

  return <canvas ref={canvasRef} width={300} height={200} className="mx-auto" />;
};

