        <div className="z-10 text-center p-12 bg-white rounded-lg border-[6px] border-blue-500 shadow-2xl -rotate-1 relative">
           <div className="absolute -top-4 -left-4 w-12 h-12 rounded-full bg-blue-200 border-2 border-blue-500"></div>
           <div className="absolute -bottom-4 -right-4 w-12 h-12 rounded-full bg-blue-200 border-2 border-blue-500"></div>

           <h2 className="text-6xl font-bold text-blue-600 mb-4">Squeaky Clean!</h2>
           <p className="text-xl mb-6">You successfully bathed the cat!</p>
           <button 
             onClick={() => setGameState('start')}
             className="px-8 py-3 bg-blue-500 text-white rounded-xl text-2xl font-bold hover:bg-blue-600"
           >
             Play Again
           </button>
        </div>
      )}
    </div>
  );
};

