  const getStyle = (t: CatType) => {
    switch(t) {
      case 'white': return { background: '#fff' };
      case 'black': return { background: '#2d2d2d' };
      case 'tuxedo': return { background: 'linear-gradient(135deg, #2d2d2d 50%, #fff 50%)' };
      case 'calico': return { background: 'radial-gradient(circle at 30% 30%, #ffa94d 20%, transparent 25%), radial-gradient(circle at 70% 60%, #2d2d2d 20%, transparent 25%), #fff' };
      case 'siamese': return { background: 'radial-gradient(circle, #4b3621 30%, #fdf5e6 70%)' }; // Dark center for mask suggestion
      case 'devon': return { background: '#a0a0a0', backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 5px, rgba(0,0,0,0.1) 5px, rgba(0,0,0,0.1) 10px)' }; // Texture
    }
  };

  const labels: Record<CatType, string> = {
    white: 'Snow',
    black: 'Void',
