              Hellycat
            </h1>

            <p className="text-2xl mb-8 leading-relaxed font-bold text-gray-700">
              Can you give the mischievous cat a bath?
            </p>

            <div className="flex justify-center gap-8 mb-10 text-xl font-bold">
               <div className="flex flex-col items-center bg-gray-100 p-4 rounded-xl border-2 border-dashed border-gray-300">
                 <span className="text-4xl mb-2">⌨️</span>
                 <span className="text-orange-600">WASD</span>
                 <span className="text-gray-500 text-sm">Move Hand</span>
               </div>
               <div className="flex flex-col items-center bg-gray-100 p-4 rounded-xl border-2 border-dashed border-gray-300">
                 <span className="text-4xl mb-2">✊</span>
                 <span className="text-orange-600">SPACE</span>
                 <span className="text-gray-500 text-sm">Hold to Grab</span>
               </div>
               <div className="flex flex-col items-center bg-gray-100 p-4 rounded-xl border-2 border-dashed border-gray-300">
                 <span className="text-4xl mb-2">🛁</span>
                 <span className="text-blue-500">TUB</span>
                 <span className="text-gray-500 text-sm">Drop here</span>
               </div>
            </div>

            <button 
              onClick={() => {
                audio.playMeow();
                setGameState('selection');
              }}
              className="px-12 py-4 bg-[#2d2d2d] text-white text-4xl rounded-xl hover:scale-105 hover:bg-orange-500 transition-all transform shadow-lg font-bold"
            >
              Start Catching!
            </button>
          </div>
        </div>
      )}

      {gameState === 'selection' && (
        <div className="z-10 text-center p-12 bg-[#fffdf5] rounded-lg border-[6px] border-[#2d2d2d] shadow-[12px_12px_0px_0px_rgba(52,152,219,0.2)] max-w-4xl mx-4 relative flex flex-col items-center">
          <h2 className="text-5xl font-bold mb-8 text-[#2d2d2d]">Choose Your Cat</h2>

          <div className="grid grid-cols-3 gap-8 mb-10">
            {(['white', 'orange', 'black', 'tuxedo', 'tabby', 'calico', 'siamese', 'sphynx', 'devon'] as CatType[]).map(type => (
              <CatPreviewCircle 
                key={type} 
                type={type} 
                selected={selectedCat === type}
                onClick={() => {
                  setSelectedCat(type);
                  audio.playMeow(1.0 + Math.random() * 0.4);
                }}
              />
            ))}
          </div>

          <div className="mb-10 w-full max-w-md bg-gray-100 p-6 rounded-2xl border-2 border-dashed border-gray-300">
            <label className="block text-2xl font-bold mb-4 text-[#2d2d2d] flex justify-between items-center">
              <span>Temperament</span>
              <span className="bg-orange-500 text-white px-3 py-1 rounded-lg text-lg">{temperament}</span>
            </label>
            <input 
              type="range" 
              min="1" 
              max="10" 
              value={temperament} 
              onChange={(e) => setTemperament(Number(e.target.value))}
              className="w-full h-4 bg-gray-300 rounded-lg appearance-none cursor-pointer accent-orange-500"
            />
            <div className="flex justify-between text-lg font-bold text-gray-500 mt-2">
              <span>Chill</span>
              <span>Spicy</span>
            </div>
          </div>

          <button 
            onClick={() => {
              audio.playMeow(0.8);
              setGameState('playing');
            }}
            className="px-16 py-4 bg-orange-500 text-white text-4xl rounded-xl hover:scale-105 hover:bg-orange-600 transition-all transform shadow-lg font-bold border-4 border-orange-700"
          >
            GO!
          </button>
        </div>
      )}

      {gameState === 'playing' && (
        <GameEngine 
          catType={selectedCat}
          temperament={temperament}
          onGameOver={() => setGameState('gameover')} 
          onWin={() => setGameState('win')} 
        />
      )}

      {gameState === 'gameover' && (
        <div className="z-10 text-center p-12 bg-white rounded-lg border-[6px] border-red-500 shadow-2xl animate-bounce -rotate-1 relative">
           <div className="absolute -top-4 -left-4 w-12 h-12 rounded-full bg-red-200 border-2 border-red-500"></div>
           <div className="absolute -bottom-4 -right-4 w-12 h-12 rounded-full bg-red-200 border-2 border-red-500"></div>

           <h2 className="text-6xl font-bold text-red-600 mb-4">Caught!</h2>
           <p className="text-xl mb-6">The cat scratched you too much!</p>
           <button 
             onClick={() => setGameState('start')}
             className="px-8 py-3 bg-red-500 text-white rounded-xl text-2xl font-bold hover:bg-red-600"
           >
             Try Again
           </button>
        </div>
      )}

      {gameState === 'win' && (
        <div className="z-10 text-center p-12 bg-white rounded-lg border-[6px] border-blue-500 shadow-2xl -rotate-1 relative">
           <div className="absolute -top-4 -left-4 w-12 h-12 rounded-full bg-blue-200 border-2 border-blue-500"></div>
           <div className="absolute -bottom-4 -right-4 w-12 h-12 rounded-full bg-blue-200 border-2 border-blue-500"></div>

           <h2 className="text-6xl font-bold text-blue-600 mb-4">Squeaky Clean!</h2>
           <p className="text-xl mb-6">You successfully bathed the cat!</p>
           <button 
             onClick={() => setGameState('start')}
             className="px-8 py-3 bg-blue-500 text-white rounded-xl text-2xl font-bold hover:bg-blue-600"
           >
             Play Again
           </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, Particle, Point, CatType } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    // Texture - Deterministic instead of random to prevent "static" effect
    ctx.strokeStyle = 'rgba(0,0,0,0.1)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    for(let i=0; i<6; i++) {
        // Use fixed offsets based on i to prevent animation jitter
        const angle = i * (Math.PI * 2 / 6);
        const dist = r * 0.7; 
        // Add some "messiness" that is static
        const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
        const ay = y + Math.sin(angle) * dist;
        const bx = x + Math.cos(angle + 2) * (dist * 0.5);
        const by = y + Math.sin(angle + 2) * (dist * 0.5);

        ctx.moveTo(ax, ay);
        ctx.lineTo(bx, by);
    }
    ctx.stroke();
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1);
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();
    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();

    // Window
    ctx.save();
    ctx.translate(100, 100);

    // Draw Window Pane Background
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();

    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);
    // Leaves
    ctx.fillStyle = CRAYON.green;
    ctx.beginPath();
    ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
    ctx.fill();
    // Pot
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating)
    if (winSequenceRef.current > 0) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
    ctx.fillStyle = '#a5d8ff';
    ctx.fillRect(x, waterLevel, width, height);

    // Water details
    ctx.strokeStyle = '#74c0fc';
    ctx.lineWidth = 3;
    ctx.beginPath();
    for (let i = x + 10; i < x + width - 10; i += 20) {
        const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 12, waveY);
    }
    ctx.stroke();
    ctx.restore();

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // TAIL
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange);
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // FACE
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Screen (Draw Room)
      drawRoom(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // Normal Game Logic

      // 1. Update Hand
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // 2. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
        audio.playSplash();
        audio.playLaugh(); // Play laugh when winning
        winSequenceRef.current = 180; // 3 seconds at 60fps
        // Don't return, let the next frame handle the sequence
      }

      // 3. Cat Physics & AI
      if (winSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // Grab Logic
          if (isGrabbing && distToHand < CATCH_DISTANCE) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40;
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic: Base speed is 6 (at temp 3). 
              // speed = base * (temp/3). Temp 1 = 2, Temp 10 = 20.
              const speedMultiplier = temperament / 3;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  if (distToHand < 40 && frameCount.current % 20 === 0) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) onGameOver();
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries
              if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
              if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-xl shadow-xl animate-bounce"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 120) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, Particle, Point, CatType } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
}

interface FloatingText {
  x: number;
  y: number;
  text: string;
  life: number;
  color: string;
  scale: number;
  vy: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const BATH_MESSAGES = [
  "Good kitty! ♥",
  "Almost done~",
  "So fluffy!",
  "Don't cry baby~",
  "Love you! ♥",
  "Squeaky clean!",
  "My precious~",
  "♥ ♥ ♥",
  "Be a good boy/girl~"
];

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const floatingTextsRef = useRef<FloatingText[]>([]); // Owner love messages
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1);
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();
    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();

    // Window
    ctx.save();
    ctx.translate(100, 100);

    // Draw Window Pane Background
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();

    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating)
    if (winSequenceRef.current > 0) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
    ctx.fillStyle = '#a5d8ff';
    ctx.fillRect(x, waterLevel, width, height);

    // Water details
    ctx.strokeStyle = '#74c0fc';
    ctx.lineWidth = 3;
    ctx.beginPath();
    for (let i = x + 10; i < x + width - 10; i += 20) {
        const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 12, waveY);
    }
    ctx.stroke();
    ctx.restore();

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // TAIL
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // FACE
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Screen (Draw Room)
      drawRoom(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly
        if (winSequenceRef.current % 50 === 0) {
            const text = BATH_MESSAGES[Math.floor(Math.random() * BATH_MESSAGES.length)];
            floatingTextsRef.current.push({
                x: 50 + Math.random() * 200, // Left side of screen
                y: CANVAS_HEIGHT - 100,
                text,
                life: 1.0,
                color: '#ff6b6b',
                scale: 0.5 + Math.random() * 0.5,
                vy: -2 - Math.random() * 2 // Float up
            });
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
        }

        // Draw Floating Text (UI overlay style on canvas)
        floatingTextsRef.current.forEach(ft => {
            ft.y += ft.vy;
            ft.life -= 0.01;
            ctx.save();
            ctx.globalAlpha = Math.max(0, ft.life);
            ctx.fillStyle = ft.color;
            ctx.font = `bold ${30 * ft.scale}px "Patrick Hand"`;
            ctx.fillText(ft.text, ft.x, ft.y);

            // Heart particle effect around text
            if (Math.random() > 0.8) {
               ctx.font = `${20 * ft.scale}px Arial`;
               ctx.fillText('♥', ft.x + (Math.random()-0.5)*40, ft.y + (Math.random()-0.5)*20);
            }
            ctx.restore();
        });
        floatingTextsRef.current = floatingTextsRef.current.filter(t => t.life > 0);

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // Normal Game Logic

      // 1. Update Hand
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // 2. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
        audio.playSplash();
        audio.playLaugh(); // Play laugh when winning
        winSequenceRef.current = 180; // 3 seconds at 60fps
        // Don't return, let the next frame handle the sequence
      }

      // 3. Cat Physics & AI
      if (winSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // Plant Interaction (Topiary)
          // Plant is at CANVAS_WIDTH - 100, 100.
          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - (CANVAS_WIDTH - 100), cat.y - 100);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(CANVAS_WIDTH - 100, 100, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          if (isGrabbing && distToHand < CATCH_DISTANCE) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40;
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic: Base speed is 6 (at temp 3). 
              // speed = base * (temp/3). Temp 1 = 2, Temp 10 = 20.
              const speedMultiplier = temperament / 3;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  if (distToHand < 40 && frameCount.current % 20 === 0) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) onGameOver();
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries
              if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
              if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-xl shadow-xl animate-bounce"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 120) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  MAX_HP, 
  CATCH_DISTANCE 
} from '../constants';
import { CatEntity, Particle, Point, CatType } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: () => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
}

interface OwnerMessage {
  id: number;
  text: string;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const BATH_MESSAGES = [
  "Good kitty!",
  "Almost done~",
  "So fluffy!",
  "Don't cry baby~",
  "Love you!",
  "Squeaky clean!",
  "My precious~",
  "Just a bit more~",
  "Be a good boy/girl~"
];

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1); // Rug Rotation

    // Draw Rug Base
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();

    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw Paw Prints on Rug (in local Rug coordinates)
    // We need to transform world coordinates to local coordinates in the loop, or store them as local.
    // Storing as local is easier for drawing.
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); // These are local coords relative to rug center
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; // Darker sand color

        // Main pad
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        // Toes
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();

        ctx.restore();
    });

    ctx.restore(); // Restore from Rug transform

    // Window
    ctx.save();
    ctx.translate(100, 100);

    // Draw Window Pane Background
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();

    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating)
    if (winSequenceRef.current > 0) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    // Water
    ctx.save();
    ctx.clip();
    const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
    ctx.fillStyle = '#a5d8ff';
    ctx.fillRect(x, waterLevel, width, height);

    // Water details
    ctx.strokeStyle = '#74c0fc';
    ctx.lineWidth = 3;
    ctx.beginPath();
    for (let i = x + 10; i < x + width - 10; i += 20) {
        const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
        ctx.moveTo(i, waveY);
        ctx.lineTo(i + 12, waveY);
    }
    ctx.stroke();
    ctx.restore();

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Patrick Hand"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // TAIL
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // FACE
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    audio.resume();
    audio.startBGM();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (!canvas || !ctx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Screen (Draw Room)
      drawRoom(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly (using React State for DOM Bubbles)
        if (winSequenceRef.current % 50 === 0) {
            const text = BATH_MESSAGES[Math.floor(Math.random() * BATH_MESSAGES.length)];
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                text: text + " ♥", // Add heart to text
                x: 20 + Math.random() * 50, // Mostly aligned left
                y: CANVAS_HEIGHT - 100 // Start from bottom
              }
            ]);
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
            setOwnerMessages([]); // Clear messages on end
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // Normal Game Logic

      // 1. Update Hand
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // 2. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
        audio.playSplash();
        audio.playLaugh(); // Play laugh when winning
        winSequenceRef.current = 180; // 3 seconds at 60fps
        // Don't return, let the next frame handle the sequence
      }

      // 3. Cat Physics & AI
      if (winSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // PAW PRINTS LOGIC
          // Rug Center: CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100
          // Rug Size: 300 x 150 (radius), rotated 0.1 rad.
          const rugX = CANVAS_WIDTH / 2;
          const rugY = CANVAS_HEIGHT / 2 + 100;
          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          // Inverse rotate to align with axis
          const angle = -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          // Check ellipse equation (allow some margin, 0.9)
          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             // Add Paw Print (store local coords relative to Rug)
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - 0.1, // Adjust for rug rotation
                 life: 1.0
             });
          }

          // Update Paw Prints
          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);


          // Plant Interaction (Topiary)
          // Plant is at CANVAS_WIDTH - 100, 100.
          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - (CANVAS_WIDTH - 100), cat.y - 100);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(CANVAS_WIDTH - 100, 100, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          if (isGrabbing && distToHand < CATCH_DISTANCE) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40;
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic: Base speed is 6 (at temp 3). 
              // speed = base * (temp/3). Temp 1 = 2, Temp 10 = 20.
              const speedMultiplier = temperament / 3;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  if (distToHand < 40 && frameCount.current % 20 === 0) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) onGameOver();
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries
              if (cat.x < CAT_RADIUS) { cat.x = CAT_RADIUS; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - CAT_RADIUS) { cat.x = CANVAS_WIDTH - CAT_RADIUS; cat.vx *= -1; }
              if (cat.y < CAT_RADIUS) { cat.y = CAT_RADIUS; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - CAT_RADIUS) { cat.y = CANVAS_HEIGHT - CAT_RADIUS; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) */}
      {ownerMessages.map((msg) => (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute left-8 bg-white border-4 border-black px-6 py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left"
          style={{ 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{msg.text}</span>
          {/* Small tail for bubble */}
          <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>
        </div>
      ))}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-xl shadow-xl animate-bounce"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 120) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

