            melody = [
                { f: 440.00, d: 0.2, t: 0, type: 'sine' }, // A4
                { f: 523.25, d: 0.2, t: 0.25, type: 'sine' }, // C5
                { f: 587.33, d: 0.2, t: 0.5, type: 'sine' }, // D5
