                   onClick={() => setGameState('start')}
                   className="px-8 py-3 bg-orange-500 text-white rounded-xl text-2xl font-bold hover:bg-orange-600 shadow-md"
                 >
                   {t.try_again}
                 </button>
               </div>
               <style>{`
                 @keyframes spin-slow {
                   0% { transform: rotate(0deg); }
                   25% { transform: rotate(5deg); }
                   75% { transform: rotate(-5deg); }
                   100% { transform: rotate(0deg); }
                 }
                 .animate-spin-slow {
                   animation: spin-slow 4s infinite ease-in-out;
                 }
               `}</style>
            </div>
          ) : (
            // PAW PRINT CARD (Scratched / Broken Tub)
            <div className="relative z-10 flex flex-col items-center">
                {/* Toes */}
                <div className="flex gap-4 mb-[-40px]">
                    <div className="w-24 h-24 bg-white border-8 border-red-500 rounded-full shadow-lg"></div>
                    <div className="w-28 h-28 bg-white border-8 border-red-500 rounded-full shadow-lg -mt-8"></div>
                    <div className="w-28 h-28 bg-white border-8 border-red-500 rounded-full shadow-lg -mt-8"></div>
                    <div className="w-24 h-24 bg-white border-8 border-red-500 rounded-full shadow-lg"></div>
                </div>
                {/* Main Pad */}
                <div className="w-[550px] h-[450px] bg-white border-[8px] border-red-500 rounded-[45%_45%_50%_50%] flex flex-col items-center justify-center text-center shadow-2xl relative overflow-hidden">
                    {/* Scratch Marks Overlay */}
                    <div className="absolute inset-0 pointer-events-none opacity-20">
                         <svg width="100%" height="100%" viewBox="0 0 100 100">
                             <path d="M10,10 L40,40 M60,10 L30,40 M20,60 L50,90" stroke="red" strokeWidth="2" />
                         </svg>
                    </div>

                    <div className="text-8xl mb-2">🐾💢</div>
                    <h2 className="text-6xl font-bold text-red-600 mb-4">{t.caught_title}</h2>
                    <p className="text-2xl mb-8 font-bold text-gray-700 max-w-md">{gameOverMsg}</p>
                    <button 
                      onClick={() => setGameState('start')}
                      className="px-10 py-4 bg-red-500 text-white rounded-full text-3xl font-bold hover:bg-red-600 shadow-lg transform hover:scale-105 transition-all"
                    >
                      {t.try_again}
                    </button>
                </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default App;

import { CatType } from '../types';

interface Note {
  f: number;
  d: number; // duration
  t: number; // start time
  type?: OscillatorType;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private currentThemeOscillators: { stop: () => void } | null = null;
  private isMuted: boolean = false;
  private bgmTimer: any = null;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.3;
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  stopTheme() {
    if (this.currentThemeOscillators) {
      this.currentThemeOscillators.stop();
      this.currentThemeOscillators = null;
    }
    this.stopBGM();
  }

  stopBGM() {
    if (this.bgmTimer !== null) {
      clearTimeout(this.bgmTimer);
      this.bgmTimer = null;
    }
  }

  playCatTheme(type: CatType) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.stopTheme();

    // Helper to create notes
    // C4=261.6, D4=293.7, E4=329.6, F4=349.2, G4=392.0, A4=440.0, B4=493.9, C5=523.3
    const NOTES: {[key: string]: number} = {
        'C3': 130.81, 'E3': 164.81, 'G3': 196.00, 'A3': 220.00, 'Bb3': 233.08, 'B3': 246.94,
        'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'F4': 349.23, 'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'Bb4': 466.16, 'B4': 493.88,
        'C5': 523.25, 'D5': 587.33, 'E5': 659.25, 'F5': 698.46, 'F#5': 739.99, 'G5': 783.99, 'A5': 880.00
    };

    let melody: Note[] = [];
    let loopDuration = 0;

    switch (type) {
        case 'white': // Lullaby - Brahms-ish
            // E4, E4, G4, E4, G4...
            melody = [
                { f: NOTES.E4, d: 0.4, t: 0.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 0.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 1.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 2.0, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 2.5, type: 'sine' },
                { f: NOTES.C5, d: 0.4, t: 3.5, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 4.0, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 4.75, type: 'sine' }
            ];
            loopDuration = 6.0;
            break;

        case 'black': // Mystery - Minor arpeggio
            melody = [
                { f: NOTES.E3, d: 0.2, t: 0.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 0.25, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 0.5, type: 'triangle' },
                { f: NOTES.E4, d: 0.4, t: 0.75, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 1.25, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 1.5, type: 'triangle' },
                { f: NOTES.E3, d: 0.6, t: 1.75, type: 'triangle' },
                { f: 0, d: 0.2, t: 2.5 }, // Rest
                { f: NOTES.C3, d: 0.2, t: 2.75, type: 'triangle' },
                { f: NOTES.E3, d: 0.2, t: 3.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 3.25, type: 'triangle' },
                { f: NOTES.C4, d: 0.6, t: 3.5, type: 'triangle' }
            ];
            loopDuration = 4.5;
            break;

        case 'orange': // Clumsy/Funny - Ragtime-ish (The Entertainer vibes)
            const oscT: OscillatorType = 'sawtooth';
            melody = [
                { f: NOTES.D4, d: 0.1, t: 0.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 0.15, type: oscT },
                { f: NOTES.C4, d: 0.1, t: 0.3, type: oscT },
                { f: NOTES.A4, d: 0.2, t: 0.45, type: oscT },
                { f: NOTES.B4, d: 0.1, t: 0.7, type: oscT },
                { f: NOTES.G4, d: 0.1, t: 0.85, type: oscT },
                { f: NOTES.D4, d: 0.1, t: 1.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 1.15, type: oscT },
                { f: NOTES.C4, d: 0.2, t: 1.3, type: oscT },
            ];
            loopDuration = 1.8;
            break;

        case 'tuxedo': // Classy - Baroque staccato
            const sq: OscillatorType = 'square';
            melody = [
                { f: NOTES.G4, d: 0.1, t: 0.0, type: sq },
                { f: NOTES.D4, d: 0.1, t: 0.2, type: sq },
                { f: NOTES.G4, d: 0.1, t: 0.4, type: sq },
                { f: NOTES.B4, d: 0.1, t: 0.6, type: sq },
                { f: NOTES.D5, d: 0.1, t: 0.8, type: sq },
                { f: NOTES.B4, d: 0.1, t: 1.0, type: sq },
                { f: NOTES.G4, d: 0.1, t: 1.2, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 1.4, type: sq },
                { f: NOTES.A4, d: 0.1, t: 1.6, type: sq },
                { f: NOTES.D4, d: 0.1, t: 1.8, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 2.0, type: sq },
                { f: NOTES.A4, d: 0.1, t: 2.2, type: sq },
            ];
            loopDuration = 2.4;
            break;

        case 'siamese': // Oriental Pentatonic
            melody = [
                { f: NOTES.A4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 0.5, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 0.75, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 1.0, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 1.5, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 1.75, type: 'sine' },
                { f: NOTES.B4, d: 0.4, t: 2.0, type: 'sine' },
            ];
            loopDuration = 2.6;
            break;

        case 'devon': // Quirky/Fast - Chromatic walk
            melody = [
                { f: NOTES.C4, d: 0.1, t: 0.0, type: 'triangle' },
                { f: NOTES.C5, d: 0.1, t: 0.15, type: 'triangle' },
                { f: NOTES.B4, d: 0.1, t: 0.3, type: 'triangle' },
                { f: NOTES.Bb4, d: 0.1, t: 0.45, type: 'triangle' },
                { f: NOTES.A4, d: 0.1, t: 0.6, type: 'triangle' },
                { f: NOTES['G#4'], d: 0.1, t: 0.75, type: 'triangle' },
                { f: NOTES.G4, d: 0.1, t: 0.9, type: 'triangle' },
                { f: NOTES.C4, d: 0.1, t: 1.05, type: 'triangle' },
            ];
            loopDuration = 1.3;
            break;

        case 'sphynx': // Theremin Slide
             // Use special logic for continuous slide
            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();
            osc.type = 'sine';
            gain.gain.value = 0.15;
            osc.connect(gain);
            gain.connect(this.masterGain);
            osc.start();

            // Sci-fi slide loop
            const slideLoop = () => {
                const now = this.ctx!.currentTime;
                osc.frequency.setValueAtTime(440, now);
                osc.frequency.exponentialRampToValueAtTime(880, now + 1.5);
                osc.frequency.linearRampToValueAtTime(660, now + 2.0);
                osc.frequency.exponentialRampToValueAtTime(440, now + 3.0);
            };
            slideLoop();
            const slideInterval = setInterval(slideLoop, 3000);

            this.currentThemeOscillators = {
                stop: () => {
                    clearInterval(slideInterval);
                    osc.stop();
                    osc.disconnect();
                    gain.disconnect();
                }
            };
            return;

        case 'calico': // Playful - Major jumps
            melody = [
                { f: NOTES.C4, d: 0.15, t: 0.0 },
                { f: NOTES.E4, d: 0.15, t: 0.2 },
                { f: NOTES.G4, d: 0.15, t: 0.4 },
                { f: NOTES.C5, d: 0.3, t: 0.6 },
                { f: NOTES.A4, d: 0.15, t: 1.0 },
                { f: NOTES.F4, d: 0.15, t: 1.2 },
                { f: NOTES.D4, d: 0.3, t: 1.4 },
            ];
            loopDuration = 2.0;
            break;

        case 'tabby': // Standard Happy
        default:
            melody = [
                { f: NOTES.C4, d: 0.3, t: 0.0 },
                { f: NOTES.D4, d: 0.3, t: 0.35 },
                { f: NOTES.E4, d: 0.3, t: 0.7 },
                { f: NOTES.F4, d: 0.3, t: 1.05 },
                { f: NOTES.G4, d: 0.6, t: 1.4 },
                { f: NOTES.G4, d: 0.6, t: 2.1 },
            ];
            loopDuration = 3.0;
            break;
    }

    const activeNodes: (OscillatorNode | GainNode)[] = [];

    const playLoop = () => {
        if (!this.ctx || !this.masterGain) return;
        const start = this.ctx.currentTime;

        melody.forEach(note => {
            if (note.f === 0) return; // Rest

            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            osc.type = note.type || 'sine';
            osc.frequency.value = note.f;

            gain.gain.setValueAtTime(0.08, start + note.t);
            gain.gain.exponentialRampToValueAtTime(0.001, start + note.t + note.d);

            osc.connect(gain);
            gain.connect(this.masterGain!);

            osc.start(start + note.t);
            osc.stop(start + note.t + note.d + 0.1);

            activeNodes.push(osc);
            activeNodes.push(gain);
        });
    };

    playLoop();
    const intervalId = setInterval(playLoop, loopDuration * 1000);

    this.currentThemeOscillators = {
        stop: () => {
            clearInterval(intervalId);
            activeNodes.forEach(node => {
                try { node.disconnect(); } catch(e) {}
            });
        }
    };
  }

  playMeow(pitch = 1, duration = 0.4) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800 * pitch, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400 * pitch, this.ctx.currentTime + duration);

    gain.gain.setValueAtTime(0.2, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playPurr() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Purr using low frequency sawtooth and amplitude modulation simulation
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(28, this.ctx.currentTime); 

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.2);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.5);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.8);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.2);

    // Filter to remove high frequency harshness of sawtooth
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 1.2);
  }

  playTrill() {
    // "Prrrt" sound - bird-like greeting or question
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(800, this.ctx.currentTime + 0.15);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.25);
  }

  playCaughtSound() {
    // Randomize sounds when caught
    const r = Math.random();
    if (r < 0.25) {
      this.playPurr(); // 25% Purr/Growl
    } else if (r < 0.5) {
      this.playTrill(); // 25% Trill
    } else if (r < 0.75) {
      this.playMeow(0.8 + Math.random() * 0.4, 0.4); // 25% Standard Meow
    } else {
      this.playMeow(1.5, 0.25); // 25% High pitch "Mew!"
    }
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // White noise buffer
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    // Filter to make it hiss-like
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // Short burst of noise
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playEat() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // Crunch sound - burst of filtered noise
    const bufferSize = this.ctx.sampleRate * 0.15;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1000, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playCrack() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // High pitched noise burst
    const bufferSize = this.ctx.sampleRate * 0.2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 2000;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.8, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playWinAscending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // C Major Arpeggio Up: C4, E4, G4, C5
    const notes = [261.63, 329.63, 392.00, 523.25]; 
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const startTime = now + i * 0.15;
      const duration = 0.3;

      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);

      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(startTime);
      osc.stop(startTime + duration + 0.1);
    });
  }

  playFailDescending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Sad slide down
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, this.ctx.currentTime + 1.5);

    // Filter to make it sound like a cartoon "womp womp"
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 500;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.5);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 1.5);
  }

  playCatSinging() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // Simple cheerful melody (La la la la)
    const melody = [
        { f: 523.25, d: 0.2 }, 
        { f: 587.33, d: 0.2 }, 
        { f: 659.25, d: 0.2 }, 
        { f: 698.46, d: 0.4 }, 
        { f: 783.99, d: 0.6 }
    ];

    let t = now;
    melody.forEach(n => {
        const osc = this.ctx!.createOscillator();
        const gain = this.ctx!.createGain();
        osc.type = 'triangle'; // Meow-ish wave
        osc.frequency.setValueAtTime(n.f, t);
        // Slight pitch bend for meow
        osc.frequency.linearRampToValueAtTime(n.f * 0.9, t + n.d);

        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, t + n.d);

        osc.connect(gain);
        gain.connect(this.masterGain!);
        osc.start(t);
        osc.stop(t + n.d + 0.1);
        t += n.d;
    });
  }

  playBouncingSequence() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // 3 Boings
    for(let i=0; i<3; i++) {
        const t = now + i * 0.4;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(200, t);
        osc.frequency.linearRampToValueAtTime(400, t + 0.1);
        osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

        gain.gain.setValueAtTime(0.3, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(t);
        osc.stop(t + 0.4);
    }
  }

  startBGM() {
    if (!this.ctx || !this.masterGain || this.bgmTimer !== null || this.isMuted) return;
    // Simple cheerful arpeggio loop
    const notes = [440, 554, 659, 554, 440, 330, 440, 554]; // A major ish
    let noteIndex = 0;

    const playNextNote = () => {
      if (!this.ctx || !this.masterGain || this.isMuted) {
          this.bgmTimer = null;
          return;
      }
      const osc = this.ctx.createOscillator();
      const gain = this.ctx.createGain();

      osc.type = 'triangle';
      osc.frequency.value = notes[noteIndex];
      noteIndex = (noteIndex + 1) % notes.length;

      gain.gain.setValueAtTime(0.05, this.ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

      osc.connect(gain);
      gain.connect(this.masterGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 0.25);

      osc.onended = () => {
        // Disconnect cleanly
        osc.disconnect();
        gain.disconnect();
      };

      this.bgmTimer = window.setTimeout(playNextNote, 250);
    };

    playNextNote();
  }
}

export const audio = new AudioService();

import { CatType } from '../types';

interface Note {
  f: number;
  d: number; // duration
  t: number; // start time
  type?: OscillatorType;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private currentThemeOscillators: { stop: () => void } | null = null;
  private isMuted: boolean = false;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.3;
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  stopTheme() {
    if (this.currentThemeOscillators) {
      this.currentThemeOscillators.stop();
      this.currentThemeOscillators = null;
    }
  }

  playCatTheme(type: CatType) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.stopTheme();

    // Helper to create notes
    // C4=261.6, D4=293.7, E4=329.6, F4=349.2, G4=392.0, A4=440.0, B4=493.9, C5=523.3
    const NOTES: {[key: string]: number} = {
        'C3': 130.81, 'E3': 164.81, 'G3': 196.00, 'A3': 220.00, 'Bb3': 233.08, 'B3': 246.94,
        'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'F4': 349.23, 'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'Bb4': 466.16, 'B4': 493.88,
        'C5': 523.25, 'D5': 587.33, 'E5': 659.25, 'F5': 698.46, 'F#5': 739.99, 'G5': 783.99, 'A5': 880.00
    };

    let melody: Note[] = [];
    let loopDuration = 0;

    switch (type) {
        case 'white': // Lullaby - Brahms-ish
            // E4, E4, G4, E4, G4...
            melody = [
                { f: NOTES.E4, d: 0.4, t: 0.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 0.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 1.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 2.0, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 2.5, type: 'sine' },
                { f: NOTES.C5, d: 0.4, t: 3.5, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 4.0, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 4.75, type: 'sine' }
            ];
            loopDuration = 6.0;
            break;

        case 'black': // Mystery - Minor arpeggio
            melody = [
                { f: NOTES.E3, d: 0.2, t: 0.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 0.25, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 0.5, type: 'triangle' },
                { f: NOTES.E4, d: 0.4, t: 0.75, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 1.25, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 1.5, type: 'triangle' },
                { f: NOTES.E3, d: 0.6, t: 1.75, type: 'triangle' },
                { f: 0, d: 0.2, t: 2.5 }, // Rest
                { f: NOTES.C3, d: 0.2, t: 2.75, type: 'triangle' },
                { f: NOTES.E3, d: 0.2, t: 3.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 3.25, type: 'triangle' },
                { f: NOTES.C4, d: 0.6, t: 3.5, type: 'triangle' }
            ];
            loopDuration = 4.5;
            break;

        case 'orange': // Clumsy/Funny - Ragtime-ish (The Entertainer vibes)
            const oscT: OscillatorType = 'sawtooth';
            melody = [
                { f: NOTES.D4, d: 0.1, t: 0.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 0.15, type: oscT },
                { f: NOTES.C4, d: 0.1, t: 0.3, type: oscT },
                { f: NOTES.A4, d: 0.2, t: 0.45, type: oscT },
                { f: NOTES.B4, d: 0.1, t: 0.7, type: oscT },
                { f: NOTES.G4, d: 0.1, t: 0.85, type: oscT },
                { f: NOTES.D4, d: 0.1, t: 1.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 1.15, type: oscT },
                { f: NOTES.C4, d: 0.2, t: 1.3, type: oscT },
            ];
            loopDuration = 1.8;
            break;

        case 'tuxedo': // Classy - Baroque staccato
            const sq: OscillatorType = 'square';
            melody = [
                { f: NOTES.G4, d: 0.1, t: 0.0, type: sq },
                { f: NOTES.D4, d: 0.1, t: 0.2, type: sq },
                { f: NOTES.G4, d: 0.1, t: 0.4, type: sq },
                { f: NOTES.B4, d: 0.1, t: 0.6, type: sq },
                { f: NOTES.D5, d: 0.1, t: 0.8, type: sq },
                { f: NOTES.B4, d: 0.1, t: 1.0, type: sq },
                { f: NOTES.G4, d: 0.1, t: 1.2, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 1.4, type: sq },
                { f: NOTES.A4, d: 0.1, t: 1.6, type: sq },
                { f: NOTES.D4, d: 0.1, t: 1.8, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 2.0, type: sq },
                { f: NOTES.A4, d: 0.1, t: 2.2, type: sq },
            ];
            loopDuration = 2.4;
            break;

        case 'siamese': // Oriental Pentatonic
            melody = [
                { f: NOTES.A4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 0.5, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 0.75, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 1.0, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 1.5, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 1.75, type: 'sine' },
                { f: NOTES.B4, d: 0.4, t: 2.0, type: 'sine' },
            ];
            loopDuration = 2.6;
            break;

        case 'devon': // Quirky/Fast - Chromatic walk
            melody = [
                { f: NOTES.C4, d: 0.1, t: 0.0, type: 'triangle' },
                { f: NOTES.C5, d: 0.1, t: 0.15, type: 'triangle' },
                { f: NOTES.B4, d: 0.1, t: 0.3, type: 'triangle' },
                { f: NOTES.Bb4, d: 0.1, t: 0.45, type: 'triangle' },
                { f: NOTES.A4, d: 0.1, t: 0.6, type: 'triangle' },
                { f: NOTES['G#4'], d: 0.1, t: 0.75, type: 'triangle' },
                { f: NOTES.G4, d: 0.1, t: 0.9, type: 'triangle' },
                { f: NOTES.C4, d: 0.1, t: 1.05, type: 'triangle' },
            ];
            loopDuration = 1.3;
            break;

        case 'sphynx': // Theremin Slide
             // Use special logic for continuous slide
            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();
            osc.type = 'sine';
            gain.gain.value = 0.15;
            osc.connect(gain);
            gain.connect(this.masterGain);
            osc.start();

            // Sci-fi slide loop
            const slideLoop = () => {
                const now = this.ctx!.currentTime;
                osc.frequency.setValueAtTime(440, now);
                osc.frequency.exponentialRampToValueAtTime(880, now + 1.5);
                osc.frequency.linearRampToValueAtTime(660, now + 2.0);
                osc.frequency.exponentialRampToValueAtTime(440, now + 3.0);
            };
            slideLoop();
            const slideInterval = setInterval(slideLoop, 3000);

            this.currentThemeOscillators = {
                stop: () => {
                    clearInterval(slideInterval);
                    osc.stop();
                    osc.disconnect();
                    gain.disconnect();
                }
            };
            return;

        case 'calico': // Playful - Major jumps
            melody = [
                { f: NOTES.C4, d: 0.15, t: 0.0 },
                { f: NOTES.E4, d: 0.15, t: 0.2 },
                { f: NOTES.G4, d: 0.15, t: 0.4 },
                { f: NOTES.C5, d: 0.3, t: 0.6 },
                { f: NOTES.A4, d: 0.15, t: 1.0 },
                { f: NOTES.F4, d: 0.15, t: 1.2 },
                { f: NOTES.D4, d: 0.3, t: 1.4 },
            ];
            loopDuration = 2.0;
            break;

        case 'tabby': // Standard Happy
        default:
            melody = [
                { f: NOTES.C4, d: 0.3, t: 0.0 },
                { f: NOTES.D4, d: 0.3, t: 0.35 },
                { f: NOTES.E4, d: 0.3, t: 0.7 },
                { f: NOTES.F4, d: 0.3, t: 1.05 },
                { f: NOTES.G4, d: 0.6, t: 1.4 },
                { f: NOTES.G4, d: 0.6, t: 2.1 },
            ];
            loopDuration = 3.0;
            break;
    }

    const activeNodes: (OscillatorNode | GainNode)[] = [];

    const playLoop = () => {
        if (!this.ctx || !this.masterGain) return;
        const start = this.ctx.currentTime;

        melody.forEach(note => {
            if (note.f === 0) return; // Rest

            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            osc.type = note.type || 'sine';
            osc.frequency.value = note.f;

            gain.gain.setValueAtTime(0.08, start + note.t);
            gain.gain.exponentialRampToValueAtTime(0.001, start + note.t + note.d);

            osc.connect(gain);
            gain.connect(this.masterGain!);

            osc.start(start + note.t);
            osc.stop(start + note.t + note.d + 0.1);

            activeNodes.push(osc);
            activeNodes.push(gain);
        });
    };

    playLoop();
    const intervalId = setInterval(playLoop, loopDuration * 1000);

    this.currentThemeOscillators = {
        stop: () => {
            clearInterval(intervalId);
            activeNodes.forEach(node => {
                try { node.disconnect(); } catch(e) {}
            });
        }
    };
  }

  playMeow(pitch = 1, duration = 0.4) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800 * pitch, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400 * pitch, this.ctx.currentTime + duration);

    gain.gain.setValueAtTime(0.2, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playPurr() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Purr using low frequency sawtooth and amplitude modulation simulation
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(28, this.ctx.currentTime); 

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.2);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.5);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.8);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.2);

    // Filter to remove high frequency harshness of sawtooth
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 1.2);
  }

  playTrill() {
    // "Prrrt" sound - bird-like greeting or question
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(800, this.ctx.currentTime + 0.15);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.25);
  }

  playCaughtSound() {
    // Randomize sounds when caught
    const r = Math.random();
    if (r < 0.25) {
      this.playPurr(); // 25% Purr/Growl
    } else if (r < 0.5) {
      this.playTrill(); // 25% Trill
    } else if (r < 0.75) {
      this.playMeow(0.8 + Math.random() * 0.4, 0.4); // 25% Standard Meow
    } else {
      this.playMeow(1.5, 0.25); // 25% High pitch "Mew!"
    }
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // White noise buffer
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    // Filter to make it hiss-like
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // Short burst of noise
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playEat() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // Crunch sound - burst of filtered noise
    const bufferSize = this.ctx.sampleRate * 0.15;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1000, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playCrack() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    // High pitched noise burst
    const bufferSize = this.ctx.sampleRate * 0.2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 2000;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.8, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playWinAscending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // C Major Arpeggio Up: C4, E4, G4, C5
    const notes = [261.63, 329.63, 392.00, 523.25]; 
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const startTime = now + i * 0.15;
      const duration = 0.3;

      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);

      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(startTime);
      osc.stop(startTime + duration + 0.1);
    });
  }

  playFailDescending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Sad slide down
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, this.ctx.currentTime + 1.5);

    // Filter to make it sound like a cartoon "womp womp"
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 500;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.5);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 1.5);
  }

  playCatSinging() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // Simple cheerful melody (La la la la)
    const melody = [
        { f: 523.25, d: 0.2 }, 
        { f: 587.33, d: 0.2 }, 
        { f: 659.25, d: 0.2 }, 
        { f: 698.46, d: 0.4 }, 
        { f: 783.99, d: 0.6 }
    ];

    let t = now;
    melody.forEach(n => {
        const osc = this.ctx!.createOscillator();
        const gain = this.ctx!.createGain();
        osc.type = 'triangle'; // Meow-ish wave
        osc.frequency.setValueAtTime(n.f, t);
        // Slight pitch bend for meow
        osc.frequency.linearRampToValueAtTime(n.f * 0.9, t + n.d);

        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, t + n.d);

        osc.connect(gain);
        gain.connect(this.masterGain!);
        osc.start(t);
        osc.stop(t + n.d + 0.1);
        t += n.d;
    });
  }

  playBouncingSequence() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    // 3 Boings
    for(let i=0; i<3; i++) {
        const t = now + i * 0.4;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(200, t);
        osc.frequency.linearRampToValueAtTime(400, t + 0.1);
        osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

        gain.gain.setValueAtTime(0.3, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(t);
        osc.stop(t + 0.4);
    }
  }

  startBGM(type: CatType) {
    // Play the cat-specific theme as BGM
    this.playCatTheme(type);
  }
}

export const audio = new AudioService();

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
  language: Language;
}

interface OwnerMessage {
  id: number;
  text: string;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1); // Rug Rotation

    // Draw Rug Base
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();

    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw Paw Prints on Rug (in local Rug coordinates)
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); // These are local coords relative to rug center
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; // Darker sand color

        // Main pad
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        // Toes
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();

        ctx.restore();
    });

    ctx.restore(); // Restore from Rug transform

    // Window
    ctx.save();
    ctx.translate(100, 100);

    // Draw Window Pane Background
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();

    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(FOOD_BOWL.x, FOOD_BOWL.y);

    // Bowl Body - Cuter Pink
    ctx.fillStyle = '#FFB7B2'; // Pastel Pink
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); // Bottom
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); // Top Rim
    ctx.fillStyle = '#FFDAC1'; // Peach/Cream inside
    ctx.fill();
    ctx.stroke();

    // Food - Static positions
    ctx.fillStyle = '#8d6e63'; // Brown pebbles
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); // Mound base
    ctx.fill();

    // Static pebbles (Fixed offsets to prevent jitter)
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });

    // Label
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);

    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating win)
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    if (isBroken) {
        // Draw cracks overlay
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        // Big crack left
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();

        // Big crack right
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();

        // Spiderweb center
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2, y + height/2 + 30);
        ctx.stroke();
    } else {
        // Water (Only if not broken)
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);

        // Water details
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current) {
        ctx.rotate(frameCount.current * 0.2); // Roll like a ball
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // SCALE BODY ONLY - KEEP FACE SMALL
    ctx.save();
    ctx.scale(cat.scale, cat.scale);

    // TAIL (Attached to body)
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS (Attached to body)
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // Restore scale so FACE is small
    ctx.restore();

    // FACE (Draw at original 1.0 scale)
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Resize Overlay Canvas to full window
    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Overlay (Always)
      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      // Clear Screen (Draw Room)
      drawRoom(ctx);
      drawFoodBowl(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly (using React State for DOM Bubbles)
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const text = msgs[Math.floor(Math.random() * msgs.length)];
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                text: text + " ♥", // Add heart to text
                x: 20 + Math.random() * 50, // Mostly aligned left
                y: CANVAS_HEIGHT - 100 // Start from bottom
              }
            ]);
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
            setOwnerMessages([]); // Clear messages on end
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // If Tub Broken Sequence
      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;

        // Force Cat Position to tub (crushing it)
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 - 20; // Sit in it
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); // Draw broken
        drawCat(ctx, cat);

        // Maybe some dust particles?
        if (frameCount.current % 10 === 0) {
             spawnParticles(BATHTUB.x + BATHTUB.width/2, BATHTUB.y + BATHTUB.height/2, '#bdc3c7', 2);
        }

        // Render particles
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      // Rolling Away Sequence
      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; // Roll right
          cat.angle += 0.1;

          drawBathtub(ctx); // Draw bathtub on main canvas so cat can go over it

          // Calculate Screen Coordinates for Cat to draw on Overlay
          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / CANVAS_WIDTH;
          const scaleY = rect.height / CANVAS_HEIGHT;

          // Draw Cat on Overlay
          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          // Check if Cat is fully off SCREEN (not just canvas)
          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
              // Ended
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; // Stop loop
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Normal Game Logic

      // 1. Update Hand
      if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
      if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
      if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
      if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
      handRef.current.vx *= 0.85;
      handRef.current.vy *= 0.85;
      handRef.current.x += handRef.current.vx;
      handRef.current.y += handRef.current.vy;
      handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
      handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));

      const isGrabbing = !!keysPressed.current['Space'];
      const cat = catRef.current;

      // 2. FOOD LOGIC
      // Check collision with bowl. 
      // Account for the fact that a large cat's center is clamped by walls and might be far from the bowl,
      // but its body (radius) might still be touching.
      const distToFood = Math.hypot(cat.x - FOOD_BOWL.x, cat.y - FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; // Allow eating if body is near bowl

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; // Grow bigger
          spawnParticles(FOOD_BOWL.x, FOOD_BOWL.y, '#8d6e63', 8);
          // Small push back
          if (distToFood > 10) {
             cat.vx = (cat.x - FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - FOOD_BOWL.y) * 0.1;
          }
      }

      // 3. ROLLING ENDING CHECK 
      // Rug width is ~600px. Cat radius 40. Scale 7.5 => 600px.
      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; // Stop running logic
          audio.playBouncingSequence(); // Play bouncing ball sounds
      }

      // 4. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          // Check if TOO FAT
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); // Play sad trombone/descending sound
                 tubBrokenSequenceRef.current = 120; // 2 seconds animation
              }
              // Don't return, let next frame handle sequence
          } else {
            audio.playSplash();
            audio.playWinAscending(); // Play happy ascending sound
            winSequenceRef.current = 180; // 3 seconds at 60fps
          }
      }

      // 5. Cat Physics & AI
      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // PAW PRINTS LOGIC
          // Rug Center: CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100
          // Rug Size: 300 x 150 (radius), rotated 0.1 rad.
          const rugX = CANVAS_WIDTH / 2;
          const rugY = CANVAS_HEIGHT / 2 + 100;
          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          // Inverse rotate to align with axis
          const angle = -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          // Check ellipse equation (allow some margin, 0.9)
          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             // Add Paw Print (store local coords relative to Rug)
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - 0.1, // Adjust for rug rotation
                 life: 1.0
             });
          }

          // Update Paw Prints
          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);


          // Plant Interaction (Topiary)
          // Plant is at CANVAS_WIDTH - 100, 100.
          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - (CANVAS_WIDTH - 100), cat.y - 100);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(CANVAS_WIDTH - 100, 100, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          // Adjust catch distance based on scale so you can grab the fat cat
          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + 30;

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); // Play diverse cat sounds when caught
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; // Hang lower if bigger
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic
              // 5-7 difficulty up slightly (1.2x)
              // 8-10 difficulty up significantly (1.6x)
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  // IMPROVED HIT DETECTION for Manic Mode
                  // Increased hit radius to 50 (from 40) + Scale
                  // Added Cooldown (800ms) instead of frame modulo to catch fast movements
                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; // Set cooldown

                      // Add visual OUCH feedback on left side (similar to bath messages)
                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const ouchText = ouchMsgs[Math.floor(Math.random() * ouchMsgs.length)];
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          text: ouchText,
                          x: 20 + Math.random() * 20, // Keep it near left
                          y: CANVAS_HEIGHT - 100 // Start from bottom like other messages
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); // Cat sings when winning fight
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); // Explicit caught code
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries (Adjust for scale)
              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - r) { cat.x = CANVAS_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - r) { cat.y = CANVAS_HEIGHT - r; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-8 left-8 p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) */}
      {ownerMessages.map((msg) => (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute left-8 bg-white border-4 border-black px-6 py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left"
          style={{ 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{msg.text}</span>
          {/* Small tail for bubble */}
          <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>
        </div>
      ))}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', // Adjust bubble height for scale
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-4 rounded-xl shadow-xl animate-bounce"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  CAT_RADIUS, 
  BATHTUB, 
  FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
  language: Language;
}

interface OwnerMessage {
  id: number;
  text: string;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // Game State
  const catRef = useRef<CatEntity>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: 1
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  // Touch State
  const touchRef = useRef<{
    active: boolean;
    x: number;
    y: number;
    isPinching: boolean;
  }>({
    active: false,
    x: 0,
    y: 0,
    isPinching: false
  });

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < CANVAS_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(CANVAS_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug
    ctx.save();
    ctx.translate(CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    ctx.rotate(0.1); // Rug Rotation

    // Draw Rug Base
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();

    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw Paw Prints on Rug (in local Rug coordinates)
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); // These are local coords relative to rug center
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; // Darker sand color

        // Main pad
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        // Toes
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();

        ctx.restore();
    });

    ctx.restore(); // Restore from Rug transform

    // Window
    ctx.save();
    ctx.translate(100, 100);

    // Draw Window Pane Background
    ctx.fillStyle = '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    ctx.beginPath();
    ctx.moveTo(100, 0); ctx.lineTo(100, 200);
    ctx.moveTo(0, 100); ctx.lineTo(200, 100);
    ctx.stroke();

    ctx.restore();

    // Plant
    ctx.save();
    ctx.translate(CANVAS_WIDTH - 100, 100);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(FOOD_BOWL.x, FOOD_BOWL.y);

    // Bowl Body - Cuter Pink
    ctx.fillStyle = '#FFB7B2'; // Pastel Pink
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); // Bottom
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); // Top Rim
    ctx.fillStyle = '#FFDAC1'; // Peach/Cream inside
    ctx.fill();
    ctx.stroke();

    // Food - Static positions
    ctx.fillStyle = '#8d6e63'; // Brown pebbles
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); // Mound base
    ctx.fill();

    // Static pebbles (Fixed offsets to prevent jitter)
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });

    // Label
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);

    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating win)
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    if (isBroken) {
        // Draw cracks overlay
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        // Big crack left
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();

        // Big crack right
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();

        // Spiderweb center
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2, y + height/2 + 30);
        ctx.stroke();
    } else {
        // Water (Only if not broken)
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);

        // Water details
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current) {
        ctx.rotate(frameCount.current * 0.2); // Roll like a ball
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // SCALE BODY ONLY - KEEP FACE SMALL
    ctx.save();
    ctx.scale(cat.scale, cat.scale);

    // TAIL (Attached to body)
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS (Attached to body)
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic') {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // Restore scale so FACE is small
    ctx.restore();

    // FACE (Draw at original 1.0 scale)
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
        ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : particlesRef.current;
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  // Touch Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    // Note: We don't prevent default here to allow UI clicks, but we might need to if it drags.
    // For game mechanics, we just track active state.
  };

  const handleTouchMove = (e: TouchEvent) => {
    // Need native event for non-passive prevention if attached to window/canvas
    e.preventDefault(); 

    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;

    const scaleX = CANVAS_WIDTH / rect.width;
    const scaleY = CANVAS_HEIGHT / rect.height;

    // Track primary finger for hand position
    if (e.touches.length > 0) {
        touchRef.current.active = true;
        const t = e.touches[0];
        touchRef.current.x = (t.clientX - rect.left) * scaleX;
        touchRef.current.y = (t.clientY - rect.top) * scaleY;
    }

    // Check for "Pinch" or just 2 fingers
    if (e.touches.length >= 2) {
        touchRef.current.isPinching = true;
    } else {
        touchRef.current.isPinching = false;
    }
  };

  const handleTouchEnd = (e: TouchEvent) => {
      if (e.touches.length === 0) {
          // Keep active true or false? If we set false, hand stops moving.
          // Let's set false so it stops "following" a non-existent finger.
          touchRef.current.active = false;
      }
      if (e.touches.length < 2) {
          touchRef.current.isPinching = false;
      }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Touch Listeners (Attached to canvas or window? Window ensures dragging off canvas still works)
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
        canvas.addEventListener('touchstart', (e) => handleTouchMove(e as unknown as TouchEvent), { passive: false }); // Update pos on start too
        window.addEventListener('touchend', handleTouchEnd);
    }

    // Resize Overlay Canvas to full window
    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Overlay (Always)
      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      // Clear Screen (Draw Room)
      drawRoom(ctx);
      drawFoodBowl(ctx);

      // --- Logic ---

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly (using React State for DOM Bubbles)
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const text = msgs[Math.floor(Math.random() * msgs.length)];
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                text: text + " ♥", // Add heart to text
                x: 20 + Math.random() * 50, // Mostly aligned left
                y: CANVAS_HEIGHT - 100 // Start from bottom
              }
            ]);
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            onWin(); // End sequence
            setOwnerMessages([]); // Clear messages on end
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // If Tub Broken Sequence
      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;

        // Force Cat Position to tub (crushing it)
        const cat = catRef.current;
        cat.x = BATHTUB.x + BATHTUB.width / 2;
        cat.y = BATHTUB.y + BATHTUB.height / 2 - 20; // Sit in it
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); // Draw broken
        drawCat(ctx, cat);

        // Maybe some dust particles?
        if (frameCount.current % 10 === 0) {
             spawnParticles(BATHTUB.x + BATHTUB.width/2, BATHTUB.y + BATHTUB.height/2, '#bdc3c7', 2);
        }

        // Render particles
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      // Rolling Away Sequence
      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; // Roll right
          cat.angle += 0.1;

          drawBathtub(ctx); // Draw bathtub on main canvas so cat can go over it

          // Calculate Screen Coordinates for Cat to draw on Overlay
          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / CANVAS_WIDTH;
          const scaleY = rect.height / CANVAS_HEIGHT;

          // Draw Cat on Overlay
          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          // Check if Cat is fully off SCREEN (not just canvas)
          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
              // Ended
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; // Stop loop
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Normal Game Logic

      // 1. Update Hand
      if (touchRef.current.active) {
          // Touch Mode: Hand follows touch position
          // Smoothly lerp towards touch
          const targetX = touchRef.current.x;
          const targetY = touchRef.current.y;
          // Apply velocity for potential physics interactions
          handRef.current.vx = (targetX - handRef.current.x) * 0.3; // Responsive tracking
          handRef.current.vy = (targetY - handRef.current.y) * 0.3;

          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;

          // Clamp
          handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));
      } else {
          // Keyboard Mode (WASD)
          if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
          if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
          if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
          if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
          handRef.current.vx *= 0.85;
          handRef.current.vy *= 0.85;
          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;
          handRef.current.x = Math.max(0, Math.min(CANVAS_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(CANVAS_HEIGHT, handRef.current.y));
      }

      // Determine Grab State
      const isGrabbing = !!keysPressed.current['Space'] || touchRef.current.isPinching;
      const cat = catRef.current;

      // 2. FOOD LOGIC
      // Check collision with bowl. 
      // Account for the fact that a large cat's center is clamped by walls and might be far from the bowl,
      // but its body (radius) might still be touching.
      const distToFood = Math.hypot(cat.x - FOOD_BOWL.x, cat.y - FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; // Allow eating if body is near bowl

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; // Grow bigger
          spawnParticles(FOOD_BOWL.x, FOOD_BOWL.y, '#8d6e63', 8);
          // Small push back
          if (distToFood > 10) {
             cat.vx = (cat.x - FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - FOOD_BOWL.y) * 0.1;
          }
      }

      // 3. ROLLING ENDING CHECK 
      // Rug width is ~600px. Cat radius 40. Scale 7.5 => 600px.
      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; // Stop running logic
          audio.playBouncingSequence(); // Play bouncing ball sounds
      }

      // 4. Check Bath Drop
      if (
        cat.x > BATHTUB.x && 
        cat.x < BATHTUB.x + BATHTUB.width && 
        cat.y > BATHTUB.y && 
        cat.y < BATHTUB.y + BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          // Check if TOO FAT
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); // Play sad trombone/descending sound
                 tubBrokenSequenceRef.current = 120; // 2 seconds animation
              }
              // Don't return, let next frame handle sequence
          } else {
            audio.playSplash();
            audio.playWinAscending(); // Play happy ascending sound
            winSequenceRef.current = 180; // 3 seconds at 60fps
          }
      }

      // 5. Cat Physics & AI
      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // PAW PRINTS LOGIC
          // Rug Center: CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100
          // Rug Size: 300 x 150 (radius), rotated 0.1 rad.
          const rugX = CANVAS_WIDTH / 2;
          const rugY = CANVAS_HEIGHT / 2 + 100;
          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          // Inverse rotate to align with axis
          const angle = -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          // Check ellipse equation (allow some margin, 0.9)
          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             // Add Paw Print (store local coords relative to Rug)
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - 0.1, // Adjust for rug rotation
                 life: 1.0
             });
          }

          // Update Paw Prints
          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);


          // Plant Interaction (Topiary)
          // Plant is at CANVAS_WIDTH - 100, 100.
          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - (CANVAS_WIDTH - 100), cat.y - 100);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(CANVAS_WIDTH - 100, 100, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          // Adjust catch distance based on scale so you can grab the fat cat
          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + 30;

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); // Play diverse cat sounds when caught
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; // Hang lower if bigger
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic
              // 5-7 difficulty up slightly (1.2x)
              // 8-10 difficulty up significantly (1.6x)
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  // IMPROVED HIT DETECTION for Manic Mode
                  // Increased hit radius to 50 (from 40) + Scale
                  // Added Cooldown (800ms) instead of frame modulo to catch fast movements
                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; // Set cooldown

                      // Add visual OUCH feedback on left side (similar to bath messages)
                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const ouchText = ouchMsgs[Math.floor(Math.random() * ouchMsgs.length)];
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          text: ouchText,
                          x: 20 + Math.random() * 20, // Keep it near left
                          y: CANVAS_HEIGHT - 100 // Start from bottom like other messages
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); // Cat sings when winning fight
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); // Explicit caught code
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries (Adjust for scale)
              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > CANVAS_WIDTH - r) { cat.x = CANVAS_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > CANVAS_HEIGHT - r) { cat.y = CANVAS_HEIGHT - r; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playMeow(1.0 + Math.random() * 0.5);
          }
      }

      // Rendering Layers
      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        if (canvas) {
            canvas.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchend', handleTouchEnd);
        }
        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none touch-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 p-2 md:p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md scale-75 md:scale-100 origin-top-left">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) */}
      {ownerMessages.map((msg) => (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute left-4 md:left-8 bg-white border-4 border-black px-4 py-2 md:px-6 md:py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left"
          style={{ 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-xl md:text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{msg.text}</span>
          {/* Small tail for bubble */}
          <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>
        </div>
      ))}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', // Adjust bubble height for scale
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-lg md:text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-xl shadow-xl animate-bounce"
          style={{
            left: (catRef.current.x / CANVAS_WIDTH) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-2xl md:text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

