// Mini component to draw the Start Screen Cat (Default White)
const StartCat: React.FC<{ meowText: string }> = ({ meowText }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const frameRef = useRef(0);

  useEffect(() => {
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;

    const render = () => {
      frameRef.current++;
      const f = frameRef.current;
      ctx.clearRect(0, 0, 300, 200);

      ctx.save();
      ctx.translate(150, 150);
      const scale = 1 + Math.sin(f * 0.05) * 0.02;
      ctx.scale(scale, scale);

      // Tail Wag
      ctx.beginPath();
      ctx.strokeStyle = '#2d2d2d';
      ctx.lineWidth = 4;
      ctx.lineCap = 'round';
      const tailWag = Math.sin(f * 0.1) * 20;
      ctx.moveTo(35, 10);
      ctx.bezierCurveTo(60, 10, 60 + tailWag, -40, 35, -30);
      ctx.stroke();

      // Body Base
      ctx.fillStyle = '#fff';
      ctx.strokeStyle = '#2d2d2d';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.ellipse(0, 0, 45, 40, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();

      // Ears (White)
      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.moveTo(-20, -30); ctx.lineTo(-35, -60); ctx.lineTo(-5, -40);
      ctx.fill(); ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(20, -30); ctx.lineTo(35, -60); ctx.lineTo(5, -40);
      ctx.fill(); ctx.stroke();

      // Face (Squinting Happy Eyes)
      ctx.strokeStyle = '#2d2d2d';
      ctx.lineWidth = 3;

      // Left Eye
      ctx.beginPath();
      ctx.moveTo(-25, -10); ctx.lineTo(-15, -20); ctx.lineTo(-5, -10);
      ctx.stroke();
      // Right Eye
      ctx.beginPath();
      ctx.moveTo(5, -10); ctx.lineTo(15, -20); ctx.lineTo(25, -10);
      ctx.stroke();

      // Blush
      ctx.fillStyle = 'rgba(255, 182, 193, 0.6)'; 
      ctx.beginPath(); ctx.arc(-25, 5, 8, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(25, 5, 8, 0, Math.PI*2); ctx.fill();

      // Mouth
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(0, 0); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, 0);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 8, -10, 5);
      ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 8, 10, 5);
      ctx.stroke();

      // Meow Bubble
      if (f % 200 < 60) {
        ctx.fillStyle = '#2d2d2d';
        ctx.font = '24px "Chewy"';
        // Add minimal outline for better readability
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 4;
        ctx.strokeText(meowText, 50, -60);
        ctx.fillText(meowText, 50, -60);
      }

      ctx.restore();
      requestAnimationFrame(render);
    };
    render();
  }, [meowText]);

  return <canvas ref={canvasRef} width={300} height={200} className="mx-auto" />;
};

const CatPreviewCircle: React.FC<{ type: CatType; selected: boolean; label: string; onClick: () => void }> = ({ type, selected, label, onClick }) => {
  // Styles for preview circles
  const getStyle = (t: CatType) => {
    switch(t) {
      case 'white': return { background: '#fff' };
      case 'black': return { background: '#2d2d2d' };
      case 'tuxedo': return { background: 'linear-gradient(135deg, #2d2d2d 50%, #fff 50%)' };
      case 'calico': return { background: 'radial-gradient(circle at 30% 30%, #ffa94d 20%, transparent 25%), radial-gradient(circle at 70% 60%, #2d2d2d 20%, transparent 25%), #fff' };
      case 'siamese': return { background: 'radial-gradient(circle, #4b3621 30%, #fdf5e6 70%)' }; 
      case 'devon': return { background: '#a0a0a0' }; // Pure Grey
      case 'orange': return { background: 'repeating-linear-gradient(45deg, #ffb74d, #ffb74d 10px, #e67e22 10px, #e67e22 20px)' }; // Orange Stripes
      case 'sphynx': return { background: '#f5cba7' }; // Skin
      case 'tabby': return { background: 'repeating-linear-gradient(45deg, #bdc3c7, #bdc3c7 10px, #2c3e50 10px, #2c3e50 20px)' }; // Grey Stripes
    }
  };

  return (
    <div className="flex flex-col items-center gap-2">
      <button
        onClick={onClick}
        className={`w-16 h-16 md:w-20 md:h-20 rounded-full border-4 shadow-md transition-transform hover:scale-110 ${selected ? 'border-orange-500 scale-110 ring-4 ring-orange-200' : 'border-gray-400'}`}
        style={getStyle(type)}
      />
      <span className="font-bold text-sm md:text-lg">{label}</span>
    </div>
  );
};

