  );
};

export default App;

import { CatType } from '../types';

interface Note {
  f: number;
  d: number; // duration
  t: number; // start time
  type?: OscillatorType;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private currentThemeOscillators: { stop: () => void } | null = null;
  private isMuted: boolean = false;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.3;
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  toggleMute(): boolean {
    this.isMuted = !this.isMuted;
    if (!this.isMuted) {
      this.resume();
    }
    return this.isMuted;
  }

  stopTheme() {
    if (this.currentThemeOscillators) {
      this.currentThemeOscillators.stop();
      this.currentThemeOscillators = null;
    }
  }

  playCatTheme(type: CatType) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.stopTheme();

    // Helper to create notes
    const NOTES: {[key: string]: number} = {
        'C3': 130.81, 'E3': 164.81, 'G3': 196.00, 'A3': 220.00, 'Bb3': 233.08, 'B3': 246.94,
        'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'F4': 349.23, 'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'Bb4': 466.16, 'B4': 493.88,
        'C5': 523.25, 'D5': 587.33, 'D#5': 622.25, 'E5': 659.25, 'F5': 698.46, 'F#5': 739.99, 'G5': 783.99, 'A5': 880.00
    };

    let melody: Note[] = [];
    let loopDuration = 0;
    let volumeMultiplier = 1.0; // Volume scalar for specific themes

    switch (type) {
        case 'white': // Lullaby
            melody = [
                { f: NOTES.E4, d: 0.4, t: 0.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 0.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 1.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 2.0, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 2.5, type: 'sine' },
                { f: NOTES.C5, d: 0.4, t: 3.5, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 4.0, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 4.75, type: 'sine' }
            ];
            loopDuration = 6.0;
            break;

        case 'black': // Mystery
            melody = [
                { f: NOTES.E3, d: 0.2, t: 0.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 0.25, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 0.5, type: 'triangle' },
                { f: NOTES.E4, d: 0.4, t: 0.75, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 1.25, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 1.5, type: 'triangle' },
                { f: NOTES.E3, d: 0.6, t: 1.75, type: 'triangle' },
                { f: 0, d: 0.2, t: 2.5 },
                { f: NOTES.C3, d: 0.2, t: 2.75, type: 'triangle' },
                { f: NOTES.E3, d: 0.2, t: 3.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 3.25, type: 'triangle' },
                { f: NOTES.C4, d: 0.6, t: 3.5, type: 'triangle' }
            ];
            loopDuration = 4.5;
            break;

        case 'orange': // Ragtime
            const oscT: OscillatorType = 'sawtooth';
            melody = [
                { f: NOTES.D4, d: 0.1, t: 0.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 0.15, type: oscT },
                { f: NOTES.C4, d: 0.1, t: 0.3, type: oscT },
                { f: NOTES.A4, d: 0.2, t: 0.45, type: oscT },
                { f: NOTES.B4, d: 0.1, t: 0.7, type: oscT },
                { f: NOTES.G4, d: 0.1, t: 0.85, type: oscT },
                { f: NOTES.D4, d: 0.1, t: 1.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 1.15, type: oscT },
                { f: NOTES.C4, d: 0.2, t: 1.3, type: oscT },
            ];
            loopDuration = 1.8;
            break;

        case 'tuxedo': // Baroque
            const sq: OscillatorType = 'square';
            melody = [
                { f: NOTES.G4, d: 0.1, t: 0.0, type: sq },
                { f: NOTES.D4, d: 0.1, t: 0.2, type: sq },
                { f: NOTES.G4, d: 0.1, t: 0.4, type: sq },
                { f: NOTES.B4, d: 0.1, t: 0.6, type: sq },
                { f: NOTES.D5, d: 0.1, t: 0.8, type: sq },
                { f: NOTES.B4, d: 0.1, t: 1.0, type: sq },
                { f: NOTES.G4, d: 0.1, t: 1.2, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 1.4, type: sq },
                { f: NOTES.A4, d: 0.1, t: 1.6, type: sq },
                { f: NOTES.D4, d: 0.1, t: 1.8, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 2.0, type: sq },
                { f: NOTES.A4, d: 0.1, t: 2.2, type: sq },
            ];
            loopDuration = 2.4;
            break;

        case 'siamese': // Oriental
            melody = [
                { f: NOTES.A4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 0.5, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 0.75, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 1.0, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 1.5, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 1.75, type: 'sine' },
                { f: NOTES.B4, d: 0.4, t: 2.0, type: 'sine' },
            ];
            loopDuration = 2.6;
            break;

        case 'devon': // Quirky/Fast - Volume Boosted
            volumeMultiplier = 2.5; // Louder for Devon Rex!
            melody = [
                { f: NOTES.C4, d: 0.1, t: 0.0, type: 'triangle' },
                { f: NOTES.C5, d: 0.1, t: 0.15, type: 'triangle' },
                { f: NOTES.B4, d: 0.1, t: 0.3, type: 'triangle' },
                { f: NOTES.Bb4, d: 0.1, t: 0.45, type: 'triangle' },
                { f: NOTES.A4, d: 0.1, t: 0.6, type: 'triangle' },
                { f: NOTES['G#4'], d: 0.1, t: 0.75, type: 'triangle' },
                { f: NOTES.G4, d: 0.1, t: 0.9, type: 'triangle' },
                { f: NOTES.C4, d: 0.1, t: 1.05, type: 'triangle' },
            ];
            loopDuration = 1.3;
            break;

        case 'sphynx': // NEW: Unified, melodic, pleasant synth loop
            melody = [
                // Arpeggio E Major 7
                { f: NOTES.E4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 0.2, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.4, type: 'sine' },
                { f: NOTES['D#5'], d: 0.4, t: 0.6, type: 'sine' },
                // Fall back
                { f: NOTES.B4, d: 0.2, t: 1.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 1.2, type: 'sine' },
                // Low resolve
                { f: NOTES.E4, d: 0.6, t: 1.4, type: 'sine' },
                { f: 0, d: 0.2, t: 2.0 }, // Rest
            ];
            loopDuration = 2.2;
            break;

        case 'calico': // Playful
            melody = [
                { f: NOTES.C4, d: 0.15, t: 0.0 },
                { f: NOTES.E4, d: 0.15, t: 0.2 },
                { f: NOTES.G4, d: 0.15, t: 0.4 },
                { f: NOTES.C5, d: 0.3, t: 0.6 },
                { f: NOTES.A4, d: 0.15, t: 1.0 },
                { f: NOTES.F4, d: 0.15, t: 1.2 },
                { f: NOTES.D4, d: 0.3, t: 1.4 },
            ];
            loopDuration = 2.0;
            break;

        case 'tabby': // Standard
        default:
            melody = [
                { f: NOTES.C4, d: 0.3, t: 0.0 },
                { f: NOTES.D4, d: 0.3, t: 0.35 },
                { f: NOTES.E4, d: 0.3, t: 0.7 },
                { f: NOTES.F4, d: 0.3, t: 1.05 },
                { f: NOTES.G4, d: 0.6, t: 1.4 },
                { f: NOTES.G4, d: 0.6, t: 2.1 },
            ];
            loopDuration = 3.0;
            break;
    }

    const activeNodes: (OscillatorNode | GainNode)[] = [];

    const playLoop = () => {
        if (!this.ctx || !this.masterGain) return;
        const start = this.ctx.currentTime;

        melody.forEach(note => {
            // Safety check for invalid/undefined frequencies (fixes 'non-finite' error)
            if (!note.f || !isFinite(note.f)) return;
            if (note.f === 0) return; // Rest

            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            osc.type = note.type || 'sine';
            osc.frequency.value = note.f;

            let baseVolume = 0.08;
            if (osc.type === 'square' || osc.type === 'sawtooth') {
                baseVolume = 0.05; 
            }

            // Apply volume multiplier
            const finalVolume = baseVolume * volumeMultiplier;

            gain.gain.setValueAtTime(finalVolume, start + note.t);
            gain.gain.exponentialRampToValueAtTime(0.001, start + note.t + note.d);

            osc.connect(gain);
            gain.connect(this.masterGain!);

            osc.start(start + note.t);
            osc.stop(start + note.t + note.d + 0.1);

            activeNodes.push(osc);
            activeNodes.push(gain);
        });
    };

    playLoop();
    const intervalId = setInterval(playLoop, loopDuration * 1000);

    this.currentThemeOscillators = {
        stop: () => {
            clearInterval(intervalId);
            activeNodes.forEach(node => {
                try { node.disconnect(); } catch(e) {}
            });
        }
    };
  }

  // Get Pitch scalar based on Cat Type
  private getPitchForType(type: CatType): number {
    switch (type) {
        case 'white':
        case 'siamese':
            return 1.4; // High pitch, squeaky
        case 'black':
        case 'tuxedo':
        case 'sphynx':
            return 0.7; // Low pitch, deep
        default:
            return 1.0; // Standard
    }
  }

  playVariedMeow(type: CatType) {
      const pitch = this.getPitchForType(type);
      // Add slight random variation to the base pitch
      const variation = 0.9 + Math.random() * 0.2; 
      this.playMeow(pitch * variation, 0.4);
  }

  playMeow(pitch = 1, duration = 0.4) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // SMOOTHER MEOW: Use Triangle instead of Sawtooth
    osc.type = 'triangle';

    // Pitch envelope: Start high, slide low (Standard meow contour)
    const startFreq = 600 * pitch;
    const endFreq = 300 * pitch;

    osc.frequency.setValueAtTime(startFreq, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(endFreq, this.ctx.currentTime + duration);

    // Volume Envelope: Attack -> Decay (Prevents clicking/harshness)
    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05); // Soft attack
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration); // Fade out

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playPurr() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(28, this.ctx.currentTime); 

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.2);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.5);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.8);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.2);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 1.2);
  }

  playTrill() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(800, this.ctx.currentTime + 0.15);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.25);
  }

  playCaughtSound() {
    const r = Math.random();
    if (r < 0.25) {
      this.playPurr(); 
    } else if (r < 0.5) {
      this.playTrill(); 
    } else if (r < 0.75) {
      this.playMeow(0.8 + Math.random() * 0.4, 0.4); 
    } else {
      this.playMeow(1.5, 0.25); 
    }
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playEat() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const bufferSize = this.ctx.sampleRate * 0.15;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1000, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playCrack() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const bufferSize = this.ctx.sampleRate * 0.2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 2000;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.8, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playWinAscending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    const notes = [261.63, 329.63, 392.00, 523.25]; 
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const startTime = now + i * 0.15;
      const duration = 0.3;

      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);

      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(startTime);
      osc.stop(startTime + duration + 0.1);
    });
  }

  playFunnyEscape() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Comical Slide Whistle: Sine wave sliding up fast
    osc.type = 'sine'; // Sine is cleaner for a whistle
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    // Big slide up
    osc.frequency.linearRampToValueAtTime(1500, this.ctx.currentTime + 0.4);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.3);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.4);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.4);
  }

  playFailDescending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, this.ctx.currentTime + 1.5);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 500;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.5);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 1.5);
  }

  playCatSinging() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    const melody = [
        { f: 523.25, d: 0.2 }, 
        { f: 587.33, d: 0.2 }, 
        { f: 659.25, d: 0.2 }, 
        { f: 698.46, d: 0.4 }, 
        { f: 783.99, d: 0.6 }
    ];

    let t = now;
    melody.forEach(n => {
        const osc = this.ctx!.createOscillator();
        const gain = this.ctx!.createGain();
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(n.f, t);
        osc.frequency.linearRampToValueAtTime(n.f * 0.9, t + n.d);

        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, t + n.d);

        osc.connect(gain);
        gain.connect(this.masterGain!);
        osc.start(t);
        osc.stop(t + n.d + 0.1);
        t += n.d;
    });
  }

  playBouncingSequence() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    const now = this.ctx.currentTime;
    for(let i=0; i<3; i++) {
        const t = now + i * 0.4;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(200, t);
        osc.frequency.linearRampToValueAtTime(400, t + 0.1);
        osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

        gain.gain.setValueAtTime(0.3, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(t);
        osc.stop(t + 0.4);
    }
  }

  startBGM(type: CatType) {
    this.playCatTheme(type);
  }
}

export const audio = new AudioService();

import { CatType } from '../types';

interface Note {
  f: number;
  d: number; // duration
  t: number; // start time
  type?: OscillatorType;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private currentThemeOscillators: { stop: () => void } | null = null;
  private isMuted: boolean = false;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.4; // Slightly increased volume
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(e => console.warn("Audio resume failed:", e));
    }
  }

  toggleMute(): boolean {
    this.isMuted = !this.isMuted;
    if (this.isMuted) {
      if (this.ctx) this.ctx.suspend();
    } else {
      this.resume();
    }
    return this.isMuted;
  }

  stopTheme() {
    if (this.currentThemeOscillators) {
      this.currentThemeOscillators.stop();
      this.currentThemeOscillators = null;
    }
  }

  playCatTheme(type: CatType) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;

    // Ensure context is running if possible
    this.resume();

    this.stopTheme();

    // Helper to create notes
    const NOTES: {[key: string]: number} = {
        'C3': 130.81, 'E3': 164.81, 'G3': 196.00, 'A3': 220.00, 'Bb3': 233.08, 'B3': 246.94,
        'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'F4': 349.23, 'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'Bb4': 466.16, 'B4': 493.88,
        'C5': 523.25, 'D5': 587.33, 'D#5': 622.25, 'E5': 659.25, 'F5': 698.46, 'F#5': 739.99, 'G5': 783.99, 'A5': 880.00
    };

    let melody: Note[] = [];
    let loopDuration = 0;
    let volumeMultiplier = 1.0; // Volume scalar for specific themes

    switch (type) {
        case 'white': // Lullaby
            melody = [
                { f: NOTES.E4, d: 0.4, t: 0.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 0.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 1.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 2.0, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 2.5, type: 'sine' },
                { f: NOTES.C5, d: 0.4, t: 3.5, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 4.0, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 4.75, type: 'sine' }
            ];
            loopDuration = 6.0;
            break;

        case 'black': // Mystery
            melody = [
                { f: NOTES.E3, d: 0.2, t: 0.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 0.25, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 0.5, type: 'triangle' },
                { f: NOTES.E4, d: 0.4, t: 0.75, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 1.25, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 1.5, type: 'triangle' },
                { f: NOTES.E3, d: 0.6, t: 1.75, type: 'triangle' },
                { f: 0, d: 0.2, t: 2.5 },
                { f: NOTES.C3, d: 0.2, t: 2.75, type: 'triangle' },
                { f: NOTES.E3, d: 0.2, t: 3.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 3.25, type: 'triangle' },
                { f: NOTES.C4, d: 0.6, t: 3.5, type: 'triangle' }
            ];
            loopDuration = 4.5;
            break;

        case 'orange': // Ragtime
            const oscT: OscillatorType = 'sawtooth';
            melody = [
                { f: NOTES.D4, d: 0.1, t: 0.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 0.15, type: oscT },
                { f: NOTES.C4, d: 0.1, t: 0.3, type: oscT },
                { f: NOTES.A4, d: 0.2, t: 0.45, type: oscT },
                { f: NOTES.B4, d: 0.1, t: 0.7, type: oscT },
                { f: NOTES.G4, d: 0.1, t: 0.85, type: oscT },
                { f: NOTES.D4, d: 0.1, t: 1.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 1.15, type: oscT },
                { f: NOTES.C4, d: 0.2, t: 1.3, type: oscT },
            ];
            loopDuration = 1.8;
            break;

        case 'tuxedo': // Baroque
            const sq: OscillatorType = 'square';
            melody = [
                { f: NOTES.G4, d: 0.1, t: 0.0, type: sq },
                { f: NOTES.D4, d: 0.1, t: 0.2, type: sq },
                { f: NOTES.G4, d: 0.1, t: 0.4, type: sq },
                { f: NOTES.B4, d: 0.1, t: 0.6, type: sq },
                { f: NOTES.D5, d: 0.1, t: 0.8, type: sq },
                { f: NOTES.B4, d: 0.1, t: 1.0, type: sq },
                { f: NOTES.G4, d: 0.1, t: 1.2, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 1.4, type: sq },
                { f: NOTES.A4, d: 0.1, t: 1.6, type: sq },
                { f: NOTES.D4, d: 0.1, t: 1.8, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 2.0, type: sq },
                { f: NOTES.A4, d: 0.1, t: 2.2, type: sq },
            ];
            loopDuration = 2.4;
            break;

        case 'siamese': // Oriental
            melody = [
                { f: NOTES.A4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 0.5, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 0.75, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 1.0, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 1.5, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 1.75, type: 'sine' },
                { f: NOTES.B4, d: 0.4, t: 2.0, type: 'sine' },
            ];
            loopDuration = 2.6;
            break;

        case 'devon': // Quirky/Fast - Volume Boosted
            volumeMultiplier = 2.5; // Louder for Devon Rex!
            melody = [
                { f: NOTES.C4, d: 0.1, t: 0.0, type: 'triangle' },
                { f: NOTES.C5, d: 0.1, t: 0.15, type: 'triangle' },
                { f: NOTES.B4, d: 0.1, t: 0.3, type: 'triangle' },
                { f: NOTES.Bb4, d: 0.1, t: 0.45, type: 'triangle' },
                { f: NOTES.A4, d: 0.1, t: 0.6, type: 'triangle' },
                { f: NOTES['G#4'], d: 0.1, t: 0.75, type: 'triangle' },
                { f: NOTES.G4, d: 0.1, t: 0.9, type: 'triangle' },
                { f: NOTES.C4, d: 0.1, t: 1.05, type: 'triangle' },
            ];
            loopDuration = 1.3;
            break;

        case 'sphynx': // NEW: Unified, melodic, pleasant synth loop
            melody = [
                // Arpeggio E Major 7
                { f: NOTES.E4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 0.2, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.4, type: 'sine' },
                { f: NOTES['D#5'], d: 0.4, t: 0.6, type: 'sine' },
                // Fall back
                { f: NOTES.B4, d: 0.2, t: 1.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 1.2, type: 'sine' },
                // Low resolve
                { f: NOTES.E4, d: 0.6, t: 1.4, type: 'sine' },
                { f: 0, d: 0.2, t: 2.0 }, // Rest
            ];
            loopDuration = 2.2;
            break;

        case 'calico': // Playful
            melody = [
                { f: NOTES.C4, d: 0.15, t: 0.0 },
                { f: NOTES.E4, d: 0.15, t: 0.2 },
                { f: NOTES.G4, d: 0.15, t: 0.4 },
                { f: NOTES.C5, d: 0.3, t: 0.6 },
                { f: NOTES.A4, d: 0.15, t: 1.0 },
                { f: NOTES.F4, d: 0.15, t: 1.2 },
                { f: NOTES.D4, d: 0.3, t: 1.4 },
            ];
            loopDuration = 2.0;
            break;

        case 'tabby': // Standard
        default:
            melody = [
                { f: NOTES.C4, d: 0.3, t: 0.0 },
                { f: NOTES.D4, d: 0.3, t: 0.35 },
                { f: NOTES.E4, d: 0.3, t: 0.7 },
                { f: NOTES.F4, d: 0.3, t: 1.05 },
                { f: NOTES.G4, d: 0.6, t: 1.4 },
                { f: NOTES.G4, d: 0.6, t: 2.1 },
            ];
            loopDuration = 3.0;
            break;
    }

    const activeNodes: (OscillatorNode | GainNode)[] = [];

    const playLoop = () => {
        if (!this.ctx || !this.masterGain) return;
        const start = this.ctx.currentTime;

        melody.forEach(note => {
            // CRITICAL FIX: Explicit check for valid number to prevent "non-finite" errors
            if (typeof note.f !== 'number' || !isFinite(note.f)) return;
            if (note.f === 0) return; // Rest

            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            osc.type = note.type || 'sine';
            osc.frequency.value = note.f;

            let baseVolume = 0.08;
            if (osc.type === 'square' || osc.type === 'sawtooth') {
                baseVolume = 0.05; 
            }

            // Apply volume multiplier
            const finalVolume = baseVolume * volumeMultiplier;

            gain.gain.setValueAtTime(finalVolume, start + note.t);
            gain.gain.exponentialRampToValueAtTime(0.001, start + note.t + note.d);

            osc.connect(gain);
            gain.connect(this.masterGain!);

            osc.start(start + note.t);
            osc.stop(start + note.t + note.d + 0.1);

            activeNodes.push(osc);
            activeNodes.push(gain);
        });
    };

    playLoop();
    const intervalId = setInterval(playLoop, loopDuration * 1000);

    this.currentThemeOscillators = {
        stop: () => {
            clearInterval(intervalId);
            activeNodes.forEach(node => {
                try { node.disconnect(); } catch(e) {}
            });
        }
    };
  }

  // Get Pitch scalar based on Cat Type
  private getPitchForType(type: CatType): number {
    switch (type) {
        case 'white':
        case 'siamese':
            return 1.4; // High pitch, squeaky
        case 'black':
        case 'tuxedo':
        case 'sphynx':
            return 0.7; // Low pitch, deep
        default:
            return 1.0; // Standard
    }
  }

  playVariedMeow(type: CatType) {
      const pitch = this.getPitchForType(type);
      // Add slight random variation to the base pitch
      const variation = 0.9 + Math.random() * 0.2; 
      this.playMeow(pitch * variation, 0.4);
  }

  playMeow(pitch = 1, duration = 0.4) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume(); // Ensure context is running

    if (!isFinite(pitch) || pitch <= 0) pitch = 1;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // SMOOTHER MEOW: Use Triangle instead of Sawtooth
    osc.type = 'triangle';

    // Pitch envelope: Start high, slide low (Standard meow contour)
    const startFreq = 600 * pitch;
    const endFreq = 300 * pitch;

    osc.frequency.setValueAtTime(startFreq, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(endFreq, this.ctx.currentTime + duration);

    // Volume Envelope: Attack -> Decay (Prevents clicking/harshness)
    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05); // Soft attack
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration); // Fade out

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playPurr() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(28, this.ctx.currentTime); 

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.2);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.5);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.8);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.2);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 1.2);
  }

  playTrill() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(800, this.ctx.currentTime + 0.15);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.25);
  }

  playCaughtSound() {
    const r = Math.random();
    if (r < 0.25) {
      this.playPurr(); 
    } else if (r < 0.5) {
      this.playTrill(); 
    } else if (r < 0.75) {
      this.playMeow(0.8 + Math.random() * 0.4, 0.4); 
    } else {
      this.playMeow(1.5, 0.25); 
    }
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playEat() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.15;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1000, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playCrack() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 2000;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.8, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playWinAscending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    const notes = [261.63, 329.63, 392.00, 523.25]; 
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const startTime = now + i * 0.15;
      const duration = 0.3;

      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);

      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(startTime);
      osc.stop(startTime + duration + 0.1);
    });
  }

  playFunnyEscape() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Comical Slide Whistle: Sine wave sliding up fast
    osc.type = 'sine'; // Sine is cleaner for a whistle
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    // Big slide up
    osc.frequency.linearRampToValueAtTime(1500, this.ctx.currentTime + 0.4);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.3);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.4);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.4);
  }

  playFailDescending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, this.ctx.currentTime + 1.5);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 500;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.5);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 1.5);
  }

  playCatSinging() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    const melody = [
        { f: 523.25, d: 0.2 }, 
        { f: 587.33, d: 0.2 }, 
        { f: 659.25, d: 0.2 }, 
        { f: 698.46, d: 0.4 }, 
        { f: 783.99, d: 0.6 }
    ];

    let t = now;
    melody.forEach(n => {
        const osc = this.ctx!.createOscillator();
        const gain = this.ctx!.createGain();
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(n.f, t);
        osc.frequency.linearRampToValueAtTime(n.f * 0.9, t + n.d);

        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, t + n.d);

        osc.connect(gain);
        gain.connect(this.masterGain!);
        osc.start(t);
        osc.stop(t + n.d + 0.1);
        t += n.d;
    });
  }

  playBouncingSequence() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    for(let i=0; i<3; i++) {
        const t = now + i * 0.4;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(200, t);
        osc.frequency.linearRampToValueAtTime(400, t + 0.1);
        osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

        gain.gain.setValueAtTime(0.3, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(t);
        osc.stop(t + 0.4);
    }
  }

  startBGM(type: CatType) {
    this.playCatTheme(type);
  }
}

export const audio = new AudioService();

import { CatType } from '../types';

interface Note {
  f: number;
  d: number; // duration
  t: number; // start time
  type?: OscillatorType;
}

class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private currentThemeOscillators: { stop: () => void } | null = null;
  private isMuted: boolean = false;

  constructor() {
    try {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.masterGain.gain.value = 0.4; // Slightly increased volume
    } catch (e) {
      console.warn('Web Audio API not supported', e);
    }
  }

  resume() {
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(e => console.warn("Audio resume failed:", e));
    }
  }

  toggleMute(): boolean {
    this.isMuted = !this.isMuted;
    if (this.isMuted) {
      if (this.ctx) this.ctx.suspend();
    } else {
      this.resume();
    }
    return this.isMuted;
  }

  stopTheme() {
    if (this.currentThemeOscillators) {
      this.currentThemeOscillators.stop();
      this.currentThemeOscillators = null;
    }
  }

  playCatTheme(type: CatType) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;

    // Ensure context is running if possible
    this.resume();

    this.stopTheme();

    // Helper to create notes
    const NOTES: {[key: string]: number} = {
        'C3': 130.81, 'E3': 164.81, 'G3': 196.00, 'A3': 220.00, 'Bb3': 233.08, 'B3': 246.94,
        'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'F4': 349.23, 'F#4': 369.99, 'G4': 392.00, 'G#4': 415.30, 'A4': 440.00, 'Bb4': 466.16, 'B4': 493.88,
        'C5': 523.25, 'D5': 587.33, 'D#5': 622.25, 'E5': 659.25, 'F5': 698.46, 'F#5': 739.99, 'G5': 783.99, 'A5': 880.00
    };

    let melody: Note[] = [];
    let loopDuration = 0;
    let volumeMultiplier = 1.0; // Volume scalar for specific themes

    switch (type) {
        case 'white': // Lullaby
            melody = [
                { f: NOTES.E4, d: 0.4, t: 0.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 0.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 1.0, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 2.0, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 2.5, type: 'sine' },
                { f: NOTES.C5, d: 0.4, t: 3.5, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 4.0, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 4.5, type: 'sine' },
                { f: NOTES.G4, d: 0.8, t: 4.75, type: 'sine' }
            ];
            loopDuration = 6.0;
            break;

        case 'black': // Mystery
            melody = [
                { f: NOTES.E3, d: 0.2, t: 0.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 0.25, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 0.5, type: 'triangle' },
                { f: NOTES.E4, d: 0.4, t: 0.75, type: 'triangle' },
                { f: NOTES.B3, d: 0.2, t: 1.25, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 1.5, type: 'triangle' },
                { f: NOTES.E3, d: 0.6, t: 1.75, type: 'triangle' },
                { f: 0, d: 0.2, t: 2.5 },
                { f: NOTES.C3, d: 0.2, t: 2.75, type: 'triangle' },
                { f: NOTES.E3, d: 0.2, t: 3.0, type: 'triangle' },
                { f: NOTES.G3, d: 0.2, t: 3.25, type: 'triangle' },
                { f: NOTES.C4, d: 0.6, t: 3.5, type: 'triangle' }
            ];
            loopDuration = 4.5;
            break;

        case 'orange': // Ragtime
            const oscT: OscillatorType = 'sawtooth';
            melody = [
                { f: NOTES.D4, d: 0.1, t: 0.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 0.15, type: oscT },
                { f: NOTES.C4, d: 0.1, t: 0.3, type: oscT },
                { f: NOTES.A4, d: 0.2, t: 0.45, type: oscT },
                { f: NOTES.B4, d: 0.1, t: 0.7, type: oscT },
                { f: NOTES.G4, d: 0.1, t: 0.85, type: oscT },
                { f: NOTES.D4, d: 0.1, t: 1.0, type: oscT },
                { f: NOTES.E4, d: 0.1, t: 1.15, type: oscT },
                { f: NOTES.C4, d: 0.2, t: 1.3, type: oscT },
            ];
            loopDuration = 1.8;
            break;

        case 'tuxedo': // Baroque
            const sq: OscillatorType = 'square';
            melody = [
                { f: NOTES.G4, d: 0.1, t: 0.0, type: sq },
                { f: NOTES.D4, d: 0.1, t: 0.2, type: sq },
                { f: NOTES.G4, d: 0.1, t: 0.4, type: sq },
                { f: NOTES.B4, d: 0.1, t: 0.6, type: sq },
                { f: NOTES.D5, d: 0.1, t: 0.8, type: sq },
                { f: NOTES.B4, d: 0.1, t: 1.0, type: sq },
                { f: NOTES.G4, d: 0.1, t: 1.2, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 1.4, type: sq },
                { f: NOTES.A4, d: 0.1, t: 1.6, type: sq },
                { f: NOTES.D4, d: 0.1, t: 1.8, type: sq },
                { f: NOTES['F#4'], d: 0.1, t: 2.0, type: sq },
                { f: NOTES.A4, d: 0.1, t: 2.2, type: sq },
            ];
            loopDuration = 2.4;
            break;

        case 'siamese': // Oriental
            melody = [
                { f: NOTES.A4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.25, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 0.5, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 0.75, type: 'sine' },
                { f: NOTES.E4, d: 0.4, t: 1.0, type: 'sine' },
                { f: NOTES['F#4'], d: 0.2, t: 1.5, type: 'sine' },
                { f: NOTES.A4, d: 0.2, t: 1.75, type: 'sine' },
                { f: NOTES.B4, d: 0.4, t: 2.0, type: 'sine' },
            ];
            loopDuration = 2.6;
            break;

        case 'devon': // Quirky/Fast - Volume Boosted
            volumeMultiplier = 2.5; // Louder for Devon Rex!
            melody = [
                { f: NOTES.C4, d: 0.1, t: 0.0, type: 'triangle' },
                { f: NOTES.C5, d: 0.1, t: 0.15, type: 'triangle' },
                { f: NOTES.B4, d: 0.1, t: 0.3, type: 'triangle' },
                { f: NOTES.Bb4, d: 0.1, t: 0.45, type: 'triangle' },
                { f: NOTES.A4, d: 0.1, t: 0.6, type: 'triangle' },
                { f: NOTES['G#4'], d: 0.1, t: 0.75, type: 'triangle' },
                { f: NOTES.G4, d: 0.1, t: 0.9, type: 'triangle' },
                { f: NOTES.C4, d: 0.1, t: 1.05, type: 'triangle' },
            ];
            loopDuration = 1.3;
            break;

        case 'sphynx': // NEW: Unified, melodic, pleasant synth loop
            melody = [
                // Arpeggio E Major 7
                { f: NOTES.E4, d: 0.2, t: 0.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 0.2, type: 'sine' },
                { f: NOTES.B4, d: 0.2, t: 0.4, type: 'sine' },
                { f: NOTES['D#5'], d: 0.4, t: 0.6, type: 'sine' },
                // Fall back
                { f: NOTES.B4, d: 0.2, t: 1.0, type: 'sine' },
                { f: NOTES['G#4'], d: 0.2, t: 1.2, type: 'sine' },
                // Low resolve
                { f: NOTES.E4, d: 0.6, t: 1.4, type: 'sine' },
                { f: 0, d: 0.2, t: 2.0 }, // Rest
            ];
            loopDuration = 2.2;
            break;

        case 'calico': // Playful
            melody = [
                { f: NOTES.C4, d: 0.15, t: 0.0 },
                { f: NOTES.E4, d: 0.15, t: 0.2 },
                { f: NOTES.G4, d: 0.15, t: 0.4 },
                { f: NOTES.C5, d: 0.3, t: 0.6 },
                { f: NOTES.A4, d: 0.15, t: 1.0 },
                { f: NOTES.F4, d: 0.15, t: 1.2 },
                { f: NOTES.D4, d: 0.3, t: 1.4 },
            ];
            loopDuration = 2.0;
            break;

        case 'tabby': // Standard
        default:
            melody = [
                { f: NOTES.C4, d: 0.3, t: 0.0 },
                { f: NOTES.D4, d: 0.3, t: 0.35 },
                { f: NOTES.E4, d: 0.3, t: 0.7 },
                { f: NOTES.F4, d: 0.3, t: 1.05 },
                { f: NOTES.G4, d: 0.6, t: 1.4 },
                { f: NOTES.G4, d: 0.6, t: 2.1 },
            ];
            loopDuration = 3.0;
            break;
    }

    const activeNodes: (OscillatorNode | GainNode)[] = [];

    const playLoop = () => {
        if (!this.ctx || !this.masterGain) return;
        const start = this.ctx.currentTime;

        melody.forEach(note => {
            // CRITICAL FIX: Explicit check for valid number to prevent "non-finite" errors
            if (typeof note.f !== 'number' || !isFinite(note.f)) return;
            if (note.f === 0) return; // Rest

            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            osc.type = note.type || 'sine';
            osc.frequency.value = note.f;

            let baseVolume = 0.08;
            if (osc.type === 'square' || osc.type === 'sawtooth') {
                baseVolume = 0.05; 
            }

            // Apply volume multiplier
            const finalVolume = baseVolume * volumeMultiplier;

            gain.gain.setValueAtTime(finalVolume, start + note.t);
            gain.gain.exponentialRampToValueAtTime(0.001, start + note.t + note.d);

            osc.connect(gain);
            gain.connect(this.masterGain!);

            osc.start(start + note.t);
            osc.stop(start + note.t + note.d + 0.1);

            activeNodes.push(osc);
            activeNodes.push(gain);
        });
    };

    playLoop();
    const intervalId = setInterval(playLoop, loopDuration * 1000);

    this.currentThemeOscillators = {
        stop: () => {
            clearInterval(intervalId);
            activeNodes.forEach(node => {
                try { node.disconnect(); } catch(e) {}
            });
        }
    };
  }

  // Get Pitch scalar based on Cat Type
  private getPitchForType(type: CatType): number {
    switch (type) {
        case 'white':
        case 'siamese':
            return 1.4; // High pitch, squeaky
        case 'black':
        case 'tuxedo':
        case 'sphynx':
            return 0.7; // Low pitch, deep
        default:
            return 1.0; // Standard
    }
  }

  playVariedMeow(type: CatType) {
      const pitch = this.getPitchForType(type);
      // Add slight random variation to the base pitch
      const variation = 0.9 + Math.random() * 0.2; 
      this.playMeow(pitch * variation, 0.4);
  }

  playMeow(pitch = 1, duration = 0.4) {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume(); // Ensure context is running

    if (!isFinite(pitch) || pitch <= 0) pitch = 1;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // SMOOTHER MEOW: Use Triangle instead of Sawtooth
    osc.type = 'triangle';

    // Pitch envelope: Start high, slide low (Standard meow contour)
    const startFreq = 600 * pitch;
    const endFreq = 300 * pitch;

    osc.frequency.setValueAtTime(startFreq, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(endFreq, this.ctx.currentTime + duration);

    // Volume Envelope: Attack -> Decay (Prevents clicking/harshness)
    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05); // Soft attack
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration); // Fade out

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playPurr() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(28, this.ctx.currentTime); 

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.2);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.5);
    gain.gain.linearRampToValueAtTime(0.15, this.ctx.currentTime + 0.8);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.2);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 1.2);
  }

  playTrill() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(800, this.ctx.currentTime + 0.15);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.2);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.25);
  }

  playCaughtSound() {
    const r = Math.random();
    if (r < 0.25) {
      this.playPurr(); 
    } else if (r < 0.5) {
      this.playTrill(); 
    } else if (r < 0.75) {
      this.playMeow(0.8 + Math.random() * 0.4, 0.4); 
    } else {
      this.playMeow(1.5, 0.25); 
    }
  }

  playHiss() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.5;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playSplash() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.4, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }

  playScratch() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.1;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.8;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;
    const gain = this.ctx.createGain();

    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.1);

    noise.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playEat() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.15;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1000, this.ctx.currentTime);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.5, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playCrack() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const bufferSize = this.ctx.sampleRate * 0.2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 2000;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.8, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    noise.start();
  }

  playWinAscending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    const notes = [261.63, 329.63, 392.00, 523.25]; 
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const startTime = now + i * 0.15;
      const duration = 0.3;

      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);

      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(startTime);
      osc.stop(startTime + duration + 0.1);
    });
  }

  playFunnyEscape() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Comical Slide Whistle: Sine wave sliding up fast
    osc.type = 'sine'; // Sine is cleaner for a whistle
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    // Big slide up
    osc.frequency.linearRampToValueAtTime(1500, this.ctx.currentTime + 0.4);

    gain.gain.setValueAtTime(0.0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.05);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.3);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.4);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.4);
  }

  playFailDescending() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(400, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, this.ctx.currentTime + 1.5);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 500;

    gain.gain.setValueAtTime(0.3, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 1.5);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 1.5);
  }

  playCatSinging() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    const melody = [
        { f: 523.25, d: 0.2 }, 
        { f: 587.33, d: 0.2 }, 
        { f: 659.25, d: 0.2 }, 
        { f: 698.46, d: 0.4 }, 
        { f: 783.99, d: 0.6 }
    ];

    let t = now;
    melody.forEach(n => {
        const osc = this.ctx!.createOscillator();
        const gain = this.ctx!.createGain();
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(n.f, t);
        osc.frequency.linearRampToValueAtTime(n.f * 0.9, t + n.d);

        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.01, t + n.d);

        osc.connect(gain);
        gain.connect(this.masterGain!);
        osc.start(t);
        osc.stop(t + n.d + 0.1);
        t += n.d;
    });
  }

  playLoveSound() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';

    // "Bloop" / "Pop" sound
    // Start slightly lower and go high quickly
    osc.frequency.setValueAtTime(800, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1200, this.ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.15);

    osc.connect(gain);
    gain.connect(this.masterGain);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.2);
  }

  playBouncingSequence() {
    if (!this.ctx || !this.masterGain || this.isMuted) return;
    this.resume();
    const now = this.ctx.currentTime;
    for(let i=0; i<3; i++) {
        const t = now + i * 0.4;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(200, t);
        osc.frequency.linearRampToValueAtTime(400, t + 0.1);
        osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

        gain.gain.setValueAtTime(0.3, t);
        gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(t);
        osc.stop(t + 0.4);
    }
  }

  startBGM(type: CatType) {
    this.playCatTheme(type);
  }
}

export const audio = new AudioService();

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  MOBILE_CANVAS_WIDTH, 
  MOBILE_CANVAS_HEIGHT,
  CAT_RADIUS, 
  BATHTUB, 
  MOBILE_BATHTUB,
  FOOD_BOWL,
  MOBILE_FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
  language: Language;
  isMobile: boolean;
}

interface OwnerMessage {
  id: number;
  text: string;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language, isMobile }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // New States for Features
  const [isWindowOpen, setIsWindowOpen] = useState<boolean>(false);
  const windowOpenSequenceRef = useRef<number>(0); // Animation timer for cat flying out
  const pettingModeRef = useRef<boolean>(false); // Intermediate mode before calling onWin
  const pettingTimerRef = useRef<number>(0);

  // Bath Exit (Rolling Out) State
  const bathExitSequenceRef = useRef<number>(0);
  const bathExitStartRef = useRef<Point>({x: 0, y: 0});

  // Game Dimensions based on Mobile state
  const GAME_WIDTH = isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH;
  const GAME_HEIGHT = isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT;
  const CURRENT_BATHTUB = isMobile ? MOBILE_BATHTUB : BATHTUB;
  const CURRENT_FOOD_BOWL = isMobile ? MOBILE_FOOD_BOWL : FOOD_BOWL;

  // Game State
  const catRef = useRef<CatEntity>({
    x: GAME_WIDTH / 2,
    y: GAME_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: isMobile ? 1.5 : 1 // Start bigger on mobile
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  // Touch State
  const touchRef = useRef<{
    active: boolean;
    x: number;
    y: number;
    isPinching: boolean;
    tapDetected: boolean;
  }>({
    active: false,
    x: 0,
    y: 0,
    isPinching: false,
    tapDetected: false
  });

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const heartsRef = useRef<Particle[]>([]); // Specific for petting
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < GAME_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(GAME_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug Position calculation
    const rugX = GAME_WIDTH / 2;
    const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

    // Rug
    ctx.save();
    ctx.translate(rugX, rugY);
    ctx.rotate(isMobile ? Math.PI / 2 : 0.1); // Vertical rug on mobile

    // Draw Rug Base
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();

    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw Paw Prints on Rug (in local Rug coordinates)
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); // These are local coords relative to rug center
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; // Darker sand color

        // Main pad
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        // Toes
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();

        ctx.restore();
    });

    ctx.restore(); // Restore from Rug transform

    // Window - Moved Down to avoid HP bar (Top-Left)
    ctx.save();
    const winX = isMobile ? 50 : 100;
    const winY = isMobile ? 150 : 180; // Moved down significantly (from 50/100)
    ctx.translate(winX, winY);

    // Draw Window Pane Background
    ctx.fillStyle = isWindowOpen ? '#87CEEB' : '#dbe4ff'; // Brighter sky if open
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);

    if (isWindowOpen) {
        // Draw open panes (perspective to sides)
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeStyle = CRAYON.wood;

        // Left pane opening out
        ctx.beginPath();
        ctx.moveTo(0, 0); ctx.lineTo(-40, 10); ctx.lineTo(-40, 190); ctx.lineTo(0, 200);
        ctx.fill(); ctx.stroke();

        // Right pane opening out
        ctx.beginPath();
        ctx.moveTo(200, 0); ctx.lineTo(240, 10); ctx.lineTo(240, 190); ctx.lineTo(200, 200);
        ctx.fill(); ctx.stroke();
    } else {
        // Closed crossbar
        ctx.beginPath();
        ctx.moveTo(100, 0); ctx.lineTo(100, 200);
        ctx.moveTo(0, 100); ctx.lineTo(200, 100);
        ctx.stroke();
    }

    ctx.restore();

    // Plant - Moved down to align with window bottom/side
    ctx.save();
    // Mobile: Near window right. Window is at x=50, w=200 -> ends at 250.
    const plantX = isMobile ? 300 : GAME_WIDTH - 100;
    const plantY = isMobile ? 250 : 180; // Align with new window Y
    ctx.translate(plantX, plantY);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y);
    if (isMobile) ctx.scale(1.4, 1.4); // Bigger bowl on mobile

    // Bowl Body - Cuter Pink
    ctx.fillStyle = '#FFB7B2'; // Pastel Pink
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); // Bottom
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); // Top Rim
    ctx.fillStyle = '#FFDAC1'; // Peach/Cream inside
    ctx.fill();
    ctx.stroke();

    // Food - Static positions
    ctx.fillStyle = '#8d6e63'; // Brown pebbles
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); // Mound base
    ctx.fill();

    // Static pebbles (Fixed offsets to prevent jitter)
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });

    // Label
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);

    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = CURRENT_BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating win)
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    if (isBroken) {
        // Draw cracks overlay
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        // Big crack left
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();

        // Big crack right
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();

        // Spiderweb center
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2, y + height/2 + 30);
        ctx.stroke();
    } else {
        // Water (Only if not broken)
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);

        // Water details
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);
    if (isMobile) ctx.scale(1.5, 1.5); // Bigger hand

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        ctx.rotate(frameCount.current * 0.2); // Roll like a ball
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else if (pettingModeRef.current) {
        // Lying down
        ctx.rotate(Math.PI / 2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // SCALE BODY ONLY - KEEP FACE SMALL
    ctx.save();
    ctx.scale(cat.scale, cat.scale);

    // TAIL (Attached to body)
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0 || pettingModeRef.current) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS (Attached to body)
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic' || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else if (pettingModeRef.current) {
        // Tucked in legs
        drawLeg(-15, 25, -20, 35);
        drawLeg(15, 25, 20, 35);
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // Restore scale so FACE is small
    ctx.restore();

    // FACE (Draw at original 1.0 scale)
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0 || pettingModeRef.current || bathExitSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        if (pettingModeRef.current) {
            // Smile
            ctx.arc(0, 5, 10, 0, Math.PI);
        } else {
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        }
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' | 'heart' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : (type === 'heart' ? heartsRef.current : particlesRef.current);
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' || type === 'heart' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  // Touch Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    // Note: We don't prevent default here to allow UI clicks, but we might need to if it drags.
    // For game mechanics, we just track active state.
  };

  const handleTouchMove = (e: TouchEvent) => {
    // Need native event for non-passive prevention if attached to window/canvas
    e.preventDefault(); 

    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;

    // Use GAME_WIDTH/HEIGHT for scale calculation
    const scaleX = GAME_WIDTH / rect.width;
    const scaleY = GAME_HEIGHT / rect.height;

    // Track primary finger for hand position
    if (e.touches.length > 0) {
        touchRef.current.active = true;
        const t = e.touches[0];
        touchRef.current.x = (t.clientX - rect.left) * scaleX;
        touchRef.current.y = (t.clientY - rect.top) * scaleY;
    }

    // Check for "Pinch" or just 2 fingers
    if (e.touches.length >= 2) {
        touchRef.current.isPinching = true;
    } else {
        touchRef.current.isPinching = false;
    }
  };

  const handleTouchEnd = (e: TouchEvent) => {
      if (e.touches.length === 0) {
          touchRef.current.active = false;
      }
      if (e.touches.length < 2) {
          touchRef.current.isPinching = false;
      }
  };

  const handleCanvasClick = (e: React.MouseEvent) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const scaleX = GAME_WIDTH / rect.width;
      const scaleY = GAME_HEIGHT / rect.height;
      const clickX = (e.clientX - rect.left) * scaleX;
      const clickY = (e.clientY - rect.top) * scaleY;

      // Window Click Detection
      const winX = isMobile ? 50 : 100;
      const winY = isMobile ? 150 : 180;
      const winSize = 200;

      if (!isWindowOpen && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          if (clickX > winX && clickX < winX + winSize && clickY > winY && clickY < winY + winSize) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Funny sound for dramatic escape
          }
      }

      // Petting Interaction
      if (pettingModeRef.current) {
          const cat = catRef.current;
          const dist = Math.hypot(clickX - cat.x, clickY - cat.y);
          if (dist < CAT_RADIUS * 2) {
              spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 3, 'heart');
              audio.playLoveSound(); // Cute love sound
          }
      }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Touch Listeners (Attached to canvas or window? Window ensures dragging off canvas still works)
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
        canvas.addEventListener('touchstart', (e) => handleTouchMove(e as unknown as TouchEvent), { passive: false }); // Update pos on start too
        window.addEventListener('touchend', handleTouchEnd);
    }

    // Resize Overlay Canvas to full window
    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Overlay (Always)
      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      // Clear Screen (Draw Room)
      drawRoom(ctx);
      drawFoodBowl(ctx);

      // --- LOGIC START ---

      // 0. Update Hand Position (Moved to top so it works in all modes)
      if (touchRef.current.active) {
          // Touch Mode: Hand follows touch position
          // Smoothly lerp towards touch
          const targetX = touchRef.current.x;
          const targetY = touchRef.current.y;
          // Apply velocity for potential physics interactions
          handRef.current.vx = (targetX - handRef.current.x) * 0.3; // Responsive tracking
          handRef.current.vy = (targetY - handRef.current.y) * 0.3;

          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;

          // Clamp
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      } else {
          // Keyboard Mode (WASD)
          if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
          if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
          if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
          if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
          handRef.current.vx *= 0.85;
          handRef.current.vy *= 0.85;
          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      }

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly (using React State for DOM Bubbles)
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const text = msgs[Math.floor(Math.random() * msgs.length)];
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                text: text + " ♥", // Add heart to text
                x: 20 + Math.random() * 50, // Mostly aligned left
                y: GAME_HEIGHT - 100 // Start from bottom
              }
            ]);
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            // Initialize Exit Sequence
            setBathEmote(null);
            setOwnerMessages([]); 
            bathExitSequenceRef.current = 60; // 1 second roll out animation
            // Save starting pos (current tub pos)
            bathExitStartRef.current = { x: cat.x, y: cat.y };
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // Bath Exit Sequence (Rolling Out to Rug)
      if (bathExitSequenceRef.current > 0) {
          bathExitSequenceRef.current--;
          const maxFrames = 60;
          const progress = 1 - (bathExitSequenceRef.current / maxFrames);
          // Ease out quart
          const ease = 1 - Math.pow(1 - progress, 4); 

          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
          const start = bathExitStartRef.current;
          const cat = catRef.current;

          cat.x = start.x + (rugX - start.x) * ease;
          cat.y = start.y + (rugY - start.y) * ease;
          cat.angle += 0.2; // Roll effect

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (bathExitSequenceRef.current === 0) {
              // Start Petting Phase
              pettingModeRef.current = true;
              pettingTimerRef.current = 300; // 5 seconds @ 60fps
              cat.vx = 0; cat.vy = 0;
              cat.angle = Math.PI / 2; // Lie down
              audio.playTrill(); // Arrived sound
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Petting Phase Logic
      if (pettingModeRef.current) {
          pettingTimerRef.current--;
          const cat = catRef.current;

          // Hover effect check with Spacebar support
          const hand = handRef.current;
          const distToHand = Math.hypot(cat.x - hand.x, cat.y - hand.y);
          const isInteracting = (touchRef.current.active || keysPressed.current['Space']) && distToHand < CAT_RADIUS * 2;

          if (isInteracting) {
              if (frameCount.current % 10 === 0) { // Faster feedback when actively petting
                  spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 1, 'heart');
                  audio.playLoveSound(); // Cute love sound
              }
          }

          drawBathtub(ctx);
          drawCat(ctx, cat);
          drawHand(ctx, handRef.current.x, handRef.current.y, false);

          // Render hearts
          heartsRef.current.forEach((p, i) => {
            p.y -= 2; // Float up
            p.x += Math.sin(frameCount.current * 0.1 + i) * 0.5;
            p.life -= 0.02;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.font = '24px Arial';
            ctx.fillText('♥', p.x, p.y);
            ctx.globalAlpha = 1;
          });
          heartsRef.current = heartsRef.current.filter(p => p.life > 0);

          if (pettingTimerRef.current <= 0) {
              pettingModeRef.current = false;
              onWin();
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Window Open / Freedom Sequence
      // Also supports Spacebar interaction
      if (!isWindowOpen && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winSize = 200;
          const hand = handRef.current;

          const overWindow = hand.x > winX && hand.x < winX + winSize && hand.y > winY && hand.y < winY + winSize;

          // Check for Spacebar press while over window
          if (overWindow && keysPressed.current['Space']) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Use funny sound for dramatic escape
          }
      }

      if (windowOpenSequenceRef.current > 0) {
          windowOpenSequenceRef.current--;
          const cat = catRef.current;
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winCenterX = winX + 100;
          const winCenterY = winY + 100;

          // Suck cat towards window
          cat.x += (winCenterX - cat.x) * 0.1;
          cat.y += (winCenterY - cat.y) * 0.1;
          cat.scale *= 0.95;
          cat.angle += 0.2;

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (windowOpenSequenceRef.current === 1) {
              onGameOver(TRANSLATIONS[language].free_msg, 'free');
              return;
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // If Tub Broken Sequence
      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;

        // Force Cat Position to tub (crushing it)
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 - 20; // Sit in it
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); // Draw broken
        drawCat(ctx, cat);

        // Maybe some dust particles?
        if (frameCount.current % 10 === 0) {
             spawnParticles(CURRENT_BATHTUB.x + CURRENT_BATHTUB.width/2, CURRENT_BATHTUB.y + CURRENT_BATHTUB.height/2, '#bdc3c7', 2);
        }

        // Render particles
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      // Rolling Away Sequence
      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; // Roll right
          cat.angle += 0.1;

          drawBathtub(ctx); // Draw bathtub on main canvas so cat can go over it

          // Calculate Screen Coordinates for Cat to draw on Overlay
          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / GAME_WIDTH;
          const scaleY = rect.height / GAME_HEIGHT;

          // Draw Cat on Overlay
          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          // Check if Cat is fully off SCREEN (not just canvas)
          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
              // Ended
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; // Stop loop
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Normal Game Logic

      // Determine Grab State
      const isGrabbing = !!keysPressed.current['Space'] || touchRef.current.isPinching;
      const cat = catRef.current;

      // 2. FOOD LOGIC
      // Check collision with bowl. 
      // Account for the fact that a large cat's center is clamped by walls and might be far from the bowl,
      // but its body (radius) might still be touching.
      const distToFood = Math.hypot(cat.x - CURRENT_FOOD_BOWL.x, cat.y - CURRENT_FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; // Allow eating if body is near bowl

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; // Grow bigger
          spawnParticles(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y, '#8d6e63', 8);
          // Small push back
          if (distToFood > 10) {
             cat.vx = (cat.x - CURRENT_FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - CURRENT_FOOD_BOWL.y) * 0.1;
          }
      }

      // 3. ROLLING ENDING CHECK 
      // Rug width is ~600px. Cat radius 40. Scale 7.5 => 600px.
      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; // Stop running logic
          audio.playBouncingSequence(); // Play bouncing ball sounds
      }

      // 4. Check Bath Drop
      if (
        cat.x > CURRENT_BATHTUB.x && 
        cat.x < CURRENT_BATHTUB.x + CURRENT_BATHTUB.width && 
        cat.y > CURRENT_BATHTUB.y && 
        cat.y < CURRENT_BATHTUB.y + CURRENT_BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          // Check if TOO FAT
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); // Play sad trombone/descending sound
                 tubBrokenSequenceRef.current = 120; // 2 seconds animation
              }
              // Don't return, let next frame handle sequence
          } else {
            audio.playSplash();
            audio.playWinAscending(); // Play happy ascending sound
            winSequenceRef.current = 180; // 3 seconds at 60fps
          }
      }

      // 5. Cat Physics & AI
      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // PAW PRINTS LOGIC
          // Rug Center changes based on layout
          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          // Inverse rotate to align with axis (Mobile has 90deg rot)
          const angle = isMobile ? -Math.PI/2 : -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          // Check ellipse equation (allow some margin, 0.9)
          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             // Add Paw Print (store local coords relative to Rug)
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - (isMobile ? Math.PI/2 : 0.1), // Adjust for rug rotation
                 life: 1.0
             });
          }

          // Update Paw Prints
          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);


          // Plant Interaction (Topiary)
          // Plant is at fixed location relative to Width/Height
          // Mobile: Near window right (Window ends at x=250), so place at ~300. 
          const plantX = isMobile ? 300 : GAME_WIDTH - 100;
          const plantY = isMobile ? 250 : 180;

          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - plantX, cat.y - plantY);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(plantX, plantY, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          // Adjust catch distance based on scale so you can grab the fat cat
          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + (isMobile ? 50 : 30); // Easier catch on mobile

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); // Play diverse cat sounds when caught
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; // Hang lower if bigger
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic
              // 5-7 difficulty up slightly (1.2x)
              // 8-10 difficulty up significantly (1.6x)
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  // IMPROVED HIT DETECTION for Manic Mode
                  // Increased hit radius to 50 (from 40) + Scale
                  // Added Cooldown (800ms) instead of frame modulo to catch fast movements
                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; // Set cooldown

                      // Add visual OUCH feedback on left side (similar to bath messages)
                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const ouchText = ouchMsgs[Math.floor(Math.random() * ouchMsgs.length)];
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          text: ouchText,
                          x: 20 + Math.random() * 20, // Keep it near left
                          y: GAME_HEIGHT - 100 // Start from bottom like other messages
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); // Cat sings when winning fight
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); // Explicit caught code
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries (Adjust for scale)
              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > GAME_WIDTH - r) { cat.x = GAME_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > GAME_HEIGHT - r) { cat.y = GAME_HEIGHT - r; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playVariedMeow(catType); // Varied idle meow
          }
      }

      // Rendering Layers
      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        if (canvas) {
            canvas.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchend', handleTouchEnd);
            canvas.removeEventListener('click', handleCanvasClick);
        }
        // Add click listener specifically for window/petting
        if (canvas) canvas.addEventListener('click', handleCanvasClick);

        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language, isMobile]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH} 
        height={isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none touch-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 p-2 md:p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md scale-75 md:scale-100 origin-top-left">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) */}
      {ownerMessages.map((msg) => (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute bg-white border-4 border-black px-4 py-2 md:px-6 md:py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left z-40"
          style={isMobile ? {
            top: '10%',
            left: '50%',
            transform: 'translateX(-50%)' // Center at top for mobile
          } : { 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-xl md:text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{msg.text}</span>
          {!isMobile && <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>}
        </div>
      ))}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            // On mobile, force thought bubbles higher so they aren't covered by thumb/cat
            top: isMobile 
                 ? '15%' 
                 : ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', 
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-lg md:text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-xl shadow-xl animate-bounce z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / (isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT)) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-2xl md:text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  MOBILE_CANVAS_WIDTH, 
  MOBILE_CANVAS_HEIGHT,
  CAT_RADIUS, 
  BATHTUB, 
  MOBILE_BATHTUB,
  FOOD_BOWL,
  MOBILE_FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
  language: Language;
  isMobile: boolean;
}

interface OwnerMessage {
  id: number;
  type: 'bath' | 'ouch';
  index: number;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language, isMobile }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // New States for Features
  const [isWindowOpen, setIsWindowOpen] = useState<boolean>(false);
  const windowOpenSequenceRef = useRef<number>(0); // Animation timer for cat flying out
  const pettingModeRef = useRef<boolean>(false); // Intermediate mode before calling onWin
  const pettingTimerRef = useRef<number>(0);

  // Bath Exit (Rolling Out) State
  const bathExitSequenceRef = useRef<number>(0);
  const bathExitStartRef = useRef<Point>({x: 0, y: 0});

  // Game Dimensions based on Mobile state
  const GAME_WIDTH = isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH;
  const GAME_HEIGHT = isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT;
  const CURRENT_BATHTUB = isMobile ? MOBILE_BATHTUB : BATHTUB;
  const CURRENT_FOOD_BOWL = isMobile ? MOBILE_FOOD_BOWL : FOOD_BOWL;

  // Game State
  const catRef = useRef<CatEntity>({
    x: GAME_WIDTH / 2,
    y: GAME_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: isMobile ? 1.5 : 1 // Start bigger on mobile
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  // Touch State
  const touchRef = useRef<{
    active: boolean;
    x: number;
    y: number;
    isPinching: boolean;
    tapDetected: boolean;
  }>({
    active: false,
    x: 0,
    y: 0,
    isPinching: false,
    tapDetected: false
  });

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const heartsRef = useRef<Particle[]>([]); // Specific for petting
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // Clear cat thought when language changes to avoid stale text
  useEffect(() => {
    setCatThought("");
  }, [language]);

  // --- Crayon Drawing Helpers ---

  // Vibrant multi-layered line with REDUCED JITTER for stability
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 1. Light underlay (texture)
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    // Jitter reduced from 3 to 1 to fix "trembling" legs
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();

    // 2. Main solid line
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    // 3. Sketchy overlay
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; // Reduced from 1.5
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  // Deterministic Scribble Fill (Fixes blinking eyes/spots)
  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    if (!clean) {
        // Texture - Deterministic instead of random to prevent "static" effect
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            // Use fixed offsets based on i to prevent animation jitter
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            // Add some "messiness" that is static
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);

            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---

  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    // Floor
    ctx.fillStyle = '#fffdf5'; // Warm paper
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Floorboards
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < GAME_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5)); // Reduced jitter
        ctx.lineTo(GAME_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();

    // Rug Position calculation
    const rugX = GAME_WIDTH / 2;
    const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

    // Rug
    ctx.save();
    ctx.translate(rugX, rugY);
    ctx.rotate(isMobile ? Math.PI / 2 : 0.1); // Vertical rug on mobile

    // Draw Rug Base
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99'; // Light yellow
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();

    // Rug pattern
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);

    // Draw Paw Prints on Rug (in local Rug coordinates)
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); // These are local coords relative to rug center
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; // Darker sand color

        // Main pad
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        // Toes
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();

        ctx.restore();
    });

    ctx.restore(); // Restore from Rug transform

    // Window - Moved Down to avoid HP bar (Top-Left)
    ctx.save();
    const winX = isMobile ? 50 : 100;
    const winY = isMobile ? 150 : 180; // Moved down significantly (from 50/100)
    ctx.translate(winX, winY);

    // Draw Window Pane Background
    ctx.fillStyle = isWindowOpen ? '#87CEEB' : '#dbe4ff'; // Brighter sky if open
    ctx.fillRect(0, 0, 200, 200);

    // Animated Cat Cloud
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); // Clip cloud to window

    // Update Cloud Position
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;

    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;

    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    // Cloud Body
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    // Cloud Head (Cat Ears)
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30); // Ear L
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25); // Ear R
    // Cloud Tail
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Window Frame
    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);

    if (isWindowOpen) {
        // Draw open panes (perspective to sides)
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeStyle = CRAYON.wood;

        // Left pane opening out
        ctx.beginPath();
        ctx.moveTo(0, 0); ctx.lineTo(-40, 10); ctx.lineTo(-40, 190); ctx.lineTo(0, 200);
        ctx.fill(); ctx.stroke();

        // Right pane opening out
        ctx.beginPath();
        ctx.moveTo(200, 0); ctx.lineTo(240, 10); ctx.lineTo(240, 190); ctx.lineTo(200, 200);
        ctx.fill(); ctx.stroke();
    } else {
        // Closed crossbar
        ctx.beginPath();
        ctx.moveTo(100, 0); ctx.lineTo(100, 200);
        ctx.moveTo(0, 100); ctx.lineTo(200, 100);
        ctx.stroke();
    }

    ctx.restore();

    // Plant - Moved down to align with window bottom/side
    ctx.save();
    // Mobile: Near window right. Window is at x=50, w=200 -> ends at 250.
    const plantX = isMobile ? 300 : GAME_WIDTH - 100;
    const plantY = isMobile ? 250 : 180; // Align with new window Y
    ctx.translate(plantX, plantY);

    if (plantTrimmedRef.current) {
        // TOPIARY: Noble Cat with Crown
        ctx.fillStyle = CRAYON.green;
        // Body (Bush)
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60); // Pot area
        // Head Shape
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        // Ears
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();

        // Crown
        ctx.fillStyle = '#f1c40f'; // Gold
        ctx.strokeStyle = '#e67e22'; // Dark Orange
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        // Normal Plant
        // Leaves
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }

    // Pot (Always drawn)
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y);
    if (isMobile) ctx.scale(1.4, 1.4); // Bigger bowl on mobile

    // Bowl Body - Cuter Pink
    ctx.fillStyle = '#FFB7B2'; // Pastel Pink
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); // Bottom
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); // Top Rim
    ctx.fillStyle = '#FFDAC1'; // Peach/Cream inside
    ctx.fill();
    ctx.stroke();

    // Food - Static positions
    ctx.fillStyle = '#8d6e63'; // Brown pebbles
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); // Mound base
    ctx.fill();

    // Static pebbles (Fixed offsets to prevent jitter)
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });

    // Label
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);

    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = CURRENT_BATHTUB;

    // Shower Pipe
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    // Vertical part from floor/wall
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    // Curve over top
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();

    // Shower Head
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; // Nozzle face
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();

    // Shower Water (Only when animating win)
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();

    // Feet
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);

    // Tub Body
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();

    if (isBroken) {
        // Draw cracks overlay
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        // Big crack left
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();

        // Big crack right
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();

        // Spiderweb center
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2, y + height/2 + 30);
        ctx.stroke();
    } else {
        // Water (Only if not broken)
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);

        // Water details
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }

    // Tub Label
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);

    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);
    if (isMobile) ctx.scale(1.5, 1.5); // Bigger hand

    // Hand color fill
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;

    if (isGrabbing) {
        // Closed fist
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        // Knuckles line
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        // Open hand
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();

        // Fingers
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });

        // Thumb side
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);

    // Win Animation Sequence Rotation
    if (winSequenceRef.current > 0) {
        // Scrubbing motion
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        ctx.rotate(frameCount.current * 0.2); // Roll like a ball
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else if (pettingModeRef.current) {
        // Lying down
        ctx.rotate(Math.PI / 2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';

    // --- Define Colors based on Type & Mode ---
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    // Breed Specifics
    if (!isManic) {
        switch(catType) {
            case 'white': 
                bodyColor = '#fff'; break;
            case 'black': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'tuxedo': 
                bodyColor = '#2d2d2d'; 
                strokeColor = '#1a1a1a'; 
                eyeColor = '#fff'; 
                break;
            case 'calico': 
                bodyColor = '#fff'; break;
            case 'siamese': 
                bodyColor = '#fdf5e6'; // Cream
                break;
            case 'devon': 
                bodyColor = '#a0a0a0'; // Pure Grey
                break;
            case 'orange':
                bodyColor = '#ffb74d'; // Orange
                strokeColor = '#d35400';
                break;
            case 'sphynx':
                bodyColor = '#f5cba7'; // Skin
                strokeColor = '#d35400';
                break;
            case 'tabby':
                bodyColor = '#bdc3c7'; // Grey
                strokeColor = '#2c3e50';
                break;
        }
    } else {
        // Manic Override
        bodyColor = '#ffcccc'; 
        strokeColor = CRAYON.red;
        eyeColor = '#ffff00';
    }

    // SCALE BODY ONLY - KEEP FACE SMALL
    ctx.save();
    ctx.scale(cat.scale, cat.scale);

    // TAIL (Attached to body)
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; // Dark brown tail
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';

    // Tail shape
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); // Spiky tail
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0 || pettingModeRef.current) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    // LEGS (Attached to body)
    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; // Dark legs

    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic' || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); 
        drawLeg(15, 25, 20, 55); 
    } else if (pettingModeRef.current) {
        // Tucked in legs
        drawLeg(-15, 25, -20, 35);
        drawLeg(15, 25, 20, 35);
    } else {
        drawLeg(-15, 25, -15, 45);
        drawLeg(15, 25, 15, 45);
    }

    // BODY
    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();

    if (isManic) {
        // Spiky body
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            // Skinnier, weird shape
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    // BODY PATTERNS
    if (!isManic) {
        if (catType === 'tuxedo') {
            // White belly
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            // Updated Calico: Left eye patch (approx -15, -12) is now clean
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); // Clean fill
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             // Stripes
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             // Top stripes
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             // Side stripes
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            // Wrinkles
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    // EARS
    // Logic for Siamese dark ears or Devon big ears
    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }

    ctx.fillStyle = earColor;
    ctx.beginPath();

    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        // Giant ears
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        // Normal ears
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();

    // Restore scale so FACE is small
    ctx.restore();

    // FACE (Draw at original 1.0 scale)
    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        // Angry eyes
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        // Siamese Mask
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; // Dark face mask
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; // Blue eyes
        }

        if (winSequenceRef.current > 0 || pettingModeRef.current || bathExitSequenceRef.current > 0) {
             // Happy Eyes ^ ^
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
             // Normal dots
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    // Mouth
    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        // Adjust mouth color for dark faces
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';

        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); // nose
        ctx.beginPath();
        if (pettingModeRef.current) {
            // Smile
            ctx.arc(0, 5, 10, 0, Math.PI);
        } else {
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        }
        ctx.stroke();
    }

    // Whiskers
    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';

        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }

    ctx.restore();
  };

  // --- Game Logic ---

  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' | 'heart' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : (type === 'heart' ? heartsRef.current : particlesRef.current);
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' || type === 'heart' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  // Touch Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    // Note: We don't prevent default here to allow UI clicks, but we might need to if it drags.
    // For game mechanics, we just track active state.
  };

  const handleTouchMove = (e: TouchEvent) => {
    // Need native event for non-passive prevention if attached to window/canvas
    e.preventDefault(); 

    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;

    // Use GAME_WIDTH/HEIGHT for scale calculation
    const scaleX = GAME_WIDTH / rect.width;
    const scaleY = GAME_HEIGHT / rect.height;

    // Track primary finger for hand position
    if (e.touches.length > 0) {
        touchRef.current.active = true;
        const t = e.touches[0];
        touchRef.current.x = (t.clientX - rect.left) * scaleX;
        touchRef.current.y = (t.clientY - rect.top) * scaleY;
    }

    // Check for "Pinch" or just 2 fingers
    if (e.touches.length >= 2) {
        touchRef.current.isPinching = true;
    } else {
        touchRef.current.isPinching = false;
    }
  };

  const handleTouchEnd = (e: TouchEvent) => {
      if (e.touches.length === 0) {
          touchRef.current.active = false;
      }
      if (e.touches.length < 2) {
          touchRef.current.isPinching = false;
      }
  };

  const handleCanvasClick = (e: React.MouseEvent) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const scaleX = GAME_WIDTH / rect.width;
      const scaleY = GAME_HEIGHT / rect.height;
      const clickX = (e.clientX - rect.left) * scaleX;
      const clickY = (e.clientY - rect.top) * scaleY;

      // Window Click Detection
      const winX = isMobile ? 50 : 100;
      const winY = isMobile ? 150 : 180;
      const winSize = 200;

      if (!isWindowOpen && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          if (clickX > winX && clickX < winX + winSize && clickY > winY && clickY < winY + winSize) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Funny sound for dramatic escape
          }
      }

      // Petting Interaction
      if (pettingModeRef.current) {
          const cat = catRef.current;
          const dist = Math.hypot(clickX - cat.x, clickY - cat.y);
          if (dist < CAT_RADIUS * 2) {
              spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 3, 'heart');
              audio.playLoveSound(); // Cute love sound
          }
      }
  };

  useEffect(() => {
    // Input Handling
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Touch Listeners (Attached to canvas or window? Window ensures dragging off canvas still works)
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
        canvas.addEventListener('touchstart', (e) => handleTouchMove(e as unknown as TouchEvent), { passive: false }); // Update pos on start too
        window.addEventListener('touchend', handleTouchEnd);
    }

    // Resize Overlay Canvas to full window
    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      // Clear Overlay (Always)
      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      // Clear Screen (Draw Room)
      drawRoom(ctx);
      drawFoodBowl(ctx);

      // --- LOGIC START ---

      // 0. Update Hand Position (Moved to top so it works in all modes)
      if (touchRef.current.active) {
          // Touch Mode: Hand follows touch position
          // Smoothly lerp towards touch
          const targetX = touchRef.current.x;
          const targetY = touchRef.current.y;
          // Apply velocity for potential physics interactions
          handRef.current.vx = (targetX - handRef.current.x) * 0.3; // Responsive tracking
          handRef.current.vy = (targetY - handRef.current.y) * 0.3;

          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;

          // Clamp
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      } else {
          // Keyboard Mode (WASD)
          if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
          if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
          if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
          if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
          handRef.current.vx *= 0.85;
          handRef.current.vy *= 0.85;
          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      }

      // If in Win Sequence (Bath Animation)
      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;

        // Show Bath Emote overlay
        setBathEmote("ε=( o｀ω′)ノ");

        // Spawn Owner Messages every second roughly (using React State for DOM Bubbles)
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const idx = Math.floor(Math.random() * msgs.length);
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                type: 'bath',
                index: idx,
                x: 20 + Math.random() * 50, // Mostly aligned left
                y: GAME_HEIGHT - 100 // Start from bottom
              }
            ]);
        }

        // Force Cat Position to tub
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        // Bubbles logic
        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }

        // Draw Tub (Back layer if needed for depth? We just draw on top for now)
        drawBathtub(ctx);
        drawCat(ctx, cat);

        // Draw Bubbles
        bubblesRef.current.forEach(p => {
            p.y -= 1; // Rise
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            // Initialize Exit Sequence
            setBathEmote(null);
            setOwnerMessages([]); 
            bathExitSequenceRef.current = 60; // 1 second roll out animation
            // Save starting pos (current tub pos)
            bathExitStartRef.current = { x: cat.x, y: cat.y };
        }

        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      // Bath Exit Sequence (Rolling Out to Rug)
      if (bathExitSequenceRef.current > 0) {
          bathExitSequenceRef.current--;
          const maxFrames = 60;
          const progress = 1 - (bathExitSequenceRef.current / maxFrames);
          // Ease out quart
          const ease = 1 - Math.pow(1 - progress, 4); 

          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
          const start = bathExitStartRef.current;
          const cat = catRef.current;

          cat.x = start.x + (rugX - start.x) * ease;
          cat.y = start.y + (rugY - start.y) * ease;
          cat.angle += 0.2; // Roll effect

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (bathExitSequenceRef.current === 0) {
              // Start Petting Phase
              pettingModeRef.current = true;
              pettingTimerRef.current = 300; // 5 seconds @ 60fps
              cat.vx = 0; cat.vy = 0;
              cat.angle = Math.PI / 2; // Lie down
              audio.playTrill(); // Arrived sound
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Petting Phase Logic
      if (pettingModeRef.current) {
          pettingTimerRef.current--;
          const cat = catRef.current;

          // Hover effect check with Spacebar support
          const hand = handRef.current;
          const distToHand = Math.hypot(cat.x - hand.x, cat.y - hand.y);
          const isInteracting = (touchRef.current.active || keysPressed.current['Space']) && distToHand < CAT_RADIUS * 2;

          if (isInteracting) {
              if (frameCount.current % 10 === 0) { // Faster feedback when actively petting
                  spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 1, 'heart');
                  audio.playLoveSound(); // Cute love sound
              }
          }

          drawBathtub(ctx);
          drawCat(ctx, cat);
          drawHand(ctx, handRef.current.x, handRef.current.y, false);

          // Render hearts
          heartsRef.current.forEach((p, i) => {
            p.y -= 2; // Float up
            p.x += Math.sin(frameCount.current * 0.1 + i) * 0.5;
            p.life -= 0.02;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.font = '24px Arial';
            ctx.fillText('♥', p.x, p.y);
            ctx.globalAlpha = 1;
          });
          heartsRef.current = heartsRef.current.filter(p => p.life > 0);

          if (pettingTimerRef.current <= 0) {
              pettingModeRef.current = false;
              onWin();
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Window Open / Freedom Sequence
      // Also supports Spacebar interaction
      if (!isWindowOpen && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winSize = 200;
          const hand = handRef.current;

          const overWindow = hand.x > winX && hand.x < winX + winSize && hand.y > winY && hand.y < winY + winSize;

          // Check for Spacebar press while over window
          if (overWindow && keysPressed.current['Space']) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Use funny sound for dramatic escape
          }
      }

      if (windowOpenSequenceRef.current > 0) {
          windowOpenSequenceRef.current--;
          const cat = catRef.current;
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winCenterX = winX + 100;
          const winCenterY = winY + 100;

          // Suck cat towards window
          cat.x += (winCenterX - cat.x) * 0.1;
          cat.y += (winCenterY - cat.y) * 0.1;
          cat.scale *= 0.95;
          cat.angle += 0.2;

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (windowOpenSequenceRef.current === 1) {
              onGameOver(TRANSLATIONS[language].free_msg, 'free');
              return;
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // If Tub Broken Sequence
      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;

        // Force Cat Position to tub (crushing it)
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 - 20; // Sit in it
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); // Draw broken
        drawCat(ctx, cat);

        // Maybe some dust particles?
        if (frameCount.current % 10 === 0) {
             spawnParticles(CURRENT_BATHTUB.x + CURRENT_BATHTUB.width/2, CURRENT_BATHTUB.y + CURRENT_BATHTUB.height/2, '#bdc3c7', 2);
        }

        // Render particles
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      // Rolling Away Sequence
      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; // Roll right
          cat.angle += 0.1;

          drawBathtub(ctx); // Draw bathtub on main canvas so cat can go over it

          // Calculate Screen Coordinates for Cat to draw on Overlay
          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / GAME_WIDTH;
          const scaleY = rect.height / GAME_HEIGHT;

          // Draw Cat on Overlay
          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          // Check if Cat is fully off SCREEN (not just canvas)
          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
              // Ended
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; // Stop loop
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Normal Game Logic

      // Determine Grab State
      const isGrabbing = !!keysPressed.current['Space'] || touchRef.current.isPinching;
      const cat = catRef.current;

      // 2. FOOD LOGIC
      // Check collision with bowl. 
      // Account for the fact that a large cat's center is clamped by walls and might be far from the bowl,
      // but its body (radius) might still be touching.
      const distToFood = Math.hypot(cat.x - CURRENT_FOOD_BOWL.x, cat.y - CURRENT_FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; // Allow eating if body is near bowl

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; // Grow bigger
          spawnParticles(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y, '#8d6e63', 8);
          // Small push back
          if (distToFood > 10) {
             cat.vx = (cat.x - CURRENT_FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - CURRENT_FOOD_BOWL.y) * 0.1;
          }
      }

      // 3. ROLLING ENDING CHECK 
      // Rug width is ~600px. Cat radius 40. Scale 7.5 => 600px.
      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; // Stop running logic
          audio.playBouncingSequence(); // Play bouncing ball sounds
      }

      // 4. Check Bath Drop
      if (
        cat.x > CURRENT_BATHTUB.x && 
        cat.x < CURRENT_BATHTUB.x + CURRENT_BATHTUB.width && 
        cat.y > CURRENT_BATHTUB.y && 
        cat.y < CURRENT_BATHTUB.y + CURRENT_BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          // Check if TOO FAT
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); // Play sad trombone/descending sound
                 tubBrokenSequenceRef.current = 120; // 2 seconds animation
              }
              // Don't return, let next frame handle sequence
          } else {
            audio.playSplash();
            audio.playWinAscending(); // Play happy ascending sound
            winSequenceRef.current = 180; // 3 seconds at 60fps
          }
      }

      // 5. Cat Physics & AI
      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          // PAW PRINTS LOGIC
          // Rug Center changes based on layout
          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          // Inverse rotate to align with axis (Mobile has 90deg rot)
          const angle = isMobile ? -Math.PI/2 : -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          // Check ellipse equation (allow some margin, 0.9)
          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             // Add Paw Print (store local coords relative to Rug)
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - (isMobile ? Math.PI/2 : 0.1), // Adjust for rug rotation
                 life: 1.0
             });
          }

          // Update Paw Prints
          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);


          // Plant Interaction (Topiary)
          // Plant is at fixed location relative to Width/Height
          // Mobile: Near window right (Window ends at x=250), so place at ~300. 
          const plantX = isMobile ? 300 : GAME_WIDTH - 100;
          const plantY = isMobile ? 250 : 180;

          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - plantX, cat.y - plantY);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(plantX, plantY, CRAYON.green, 15);
                  audio.playScratch(); // Sound effect for trimming
              }
          }

          // Grab Logic
          // Adjust catch distance based on scale so you can grab the fat cat
          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + (isMobile ? 50 : 30); // Easier catch on mobile

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); // Play diverse cat sounds when caught
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; // Hang lower if bigger
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          // Manic Logic: Probability depends on temperament
          // Base probability for Temp 3 is roughly 40% every 10s (600 frames)
          // Threshold = 1 - (0.1 + temp * 0.1). Temp 3 -> 0.4 prob, threshold 0.6.
          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          // Movement
          if (cat.mode !== 'caught') {
              // Speed Logic
              // 5-7 difficulty up slightly (1.2x)
              // 8-10 difficulty up significantly (1.6x)
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; // Also scale acceleration
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  // IMPROVED HIT DETECTION for Manic Mode
                  // Increased hit radius to 50 (from 40) + Scale
                  // Added Cooldown (800ms) instead of frame modulo to catch fast movements
                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; // Set cooldown

                      // Add visual OUCH feedback on left side (similar to bath messages)
                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const idx = Math.floor(Math.random() * ouchMsgs.length);
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          type: 'ouch',
                          index: idx,
                          x: 20 + Math.random() * 20, // Keep it near left
                          y: GAME_HEIGHT - 100 // Start from bottom like other messages
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); // Cat sings when winning fight
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); // Explicit caught code
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              // Boundaries (Adjust for scale)
              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > GAME_WIDTH - r) { cat.x = GAME_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > GAME_HEIGHT - r) { cat.y = GAME_HEIGHT - r; cat.vy *= -1; }
          }
      }

      // Gemini Thoughts
      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playVariedMeow(catType); // Varied idle meow
          }
      }

      // Rendering Layers
      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      // Particles
      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        if (canvas) {
            canvas.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchend', handleTouchEnd);
            canvas.removeEventListener('click', handleCanvasClick);
        }
        // Add click listener specifically for window/petting - FIXED BUG: was addEventListener
        if (canvas) canvas.removeEventListener('click', handleCanvasClick);

        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language, isMobile]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH} 
        height={isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none touch-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 p-2 md:p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md scale-75 md:scale-100 origin-top-left">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) - DYNAMIC TEXT RENDERING */}
      {ownerMessages.map((msg) => {
        // Resolve text based on current language prop
        let text = "";
        if (msg.type === 'bath') {
           const list = TRANSLATIONS[language].bath_messages;
           const safeIndex = msg.index % list.length;
           text = list[safeIndex] + " ♥";
        } else {
           const list = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
           const safeIndex = msg.index % list.length;
           text = list[safeIndex];
        }

        return (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute bg-white border-4 border-black px-4 py-2 md:px-6 md:py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left z-40"
          style={isMobile ? {
            top: '10%',
            left: '50%',
            transform: 'translateX(-50%)' // Center at top for mobile
          } : { 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-xl md:text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{text}</span>
          {!isMobile && <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>}
        </div>
        );
      })}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            // On mobile, force thought bubbles higher so they aren't covered by thumb/cat
            top: isMobile 
                 ? '15%' 
                 : ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', 
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-lg md:text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-xl shadow-xl animate-bounce z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / (isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT)) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-2xl md:text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  MOBILE_CANVAS_WIDTH, 
  MOBILE_CANVAS_HEIGHT,
  CAT_RADIUS, 
  BATHTUB, 
  MOBILE_BATHTUB,
  FOOD_BOWL,
  MOBILE_FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: () => void;
  catType: CatType;
  temperament: number;
  language: Language;
  isMobile: boolean;
}

interface OwnerMessage {
  id: number;
  type: 'bath' | 'ouch';
  index: number;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language, isMobile }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // New States for Features
  const [isWindowOpen, setIsWindowOpen] = useState<boolean>(false);
  const isWindowOpenRef = useRef<boolean>(false); // Ref for loop access
  const windowOpenSequenceRef = useRef<number>(0); // Animation timer for cat flying out
  const pettingModeRef = useRef<boolean>(false); // Intermediate mode before calling onWin
  const pettingTimerRef = useRef<number>(0);

  // Bath Exit (Rolling Out) State
  const bathExitSequenceRef = useRef<number>(0);
  const bathExitStartRef = useRef<Point>({x: 0, y: 0});

  // Game Dimensions based on Mobile state
  const GAME_WIDTH = isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH;
  const GAME_HEIGHT = isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT;
  const CURRENT_BATHTUB = isMobile ? MOBILE_BATHTUB : BATHTUB;
  const CURRENT_FOOD_BOWL = isMobile ? MOBILE_FOOD_BOWL : FOOD_BOWL;

  // Game State
  const catRef = useRef<CatEntity>({
    x: GAME_WIDTH / 2,
    y: GAME_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: isMobile ? 1.5 : 1 // Start bigger on mobile
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  // Touch State
  const touchRef = useRef<{
    active: boolean;
    x: number;
    y: number;
    startX: number;
    startY: number;
    startTime: number;
    isPinching: boolean;
    tapDetected: boolean;
  }>({
    active: false,
    x: 0,
    y: 0,
    startX: 0,
    startY: 0,
    startTime: 0,
    isPinching: false,
    tapDetected: false
  });

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const heartsRef = useRef<Particle[]>([]); // Specific for petting
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // Clear cat thought when language changes to avoid stale text
  useEffect(() => {
    setCatThought("");
  }, [language]);

  // Sync isWindowOpenRef
  useEffect(() => {
      isWindowOpenRef.current = isWindowOpen;
  }, [isWindowOpen]);

  // --- Crayon Drawing Helpers ---
  // (Omitted unchanged helpers for brevity, same as previous)
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; 
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
    if (!clean) {
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);
            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---
  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    ctx.fillStyle = '#fffdf5';
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < GAME_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5));
        ctx.lineTo(GAME_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();
    const rugX = GAME_WIDTH / 2;
    const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
    ctx.save();
    ctx.translate(rugX, rugY);
    ctx.rotate(isMobile ? Math.PI / 2 : 0.1); 
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99';
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); 
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; 
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.restore();
    });
    ctx.restore();

    ctx.save();
    const winX = isMobile ? 50 : 100;
    const winY = isMobile ? 150 : 180;
    ctx.translate(winX, winY);

    // Window drawing
    ctx.fillStyle = isWindowOpen ? '#87CEEB' : '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); 
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;
    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30);
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25);
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    if (isWindowOpen) {
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeStyle = CRAYON.wood;
        ctx.beginPath();
        ctx.moveTo(0, 0); ctx.lineTo(-40, 10); ctx.lineTo(-40, 190); ctx.lineTo(0, 200);
        ctx.fill(); ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(200, 0); ctx.lineTo(240, 10); ctx.lineTo(240, 190); ctx.lineTo(200, 200);
        ctx.fill(); ctx.stroke();
    } else {
        ctx.beginPath();
        ctx.moveTo(100, 0); ctx.lineTo(100, 200);
        ctx.moveTo(0, 100); ctx.lineTo(200, 100);
        ctx.stroke();
    }
    ctx.restore();

    ctx.save();
    const plantX = isMobile ? 300 : GAME_WIDTH - 100;
    const plantY = isMobile ? 250 : 180;
    ctx.translate(plantX, plantY);

    if (plantTrimmedRef.current) {
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();
        ctx.fillStyle = '#f1c40f'; 
        ctx.strokeStyle = '#e67e22'; 
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y);
    if (isMobile) ctx.scale(1.4, 1.4); 
    ctx.fillStyle = '#FFB7B2'; 
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); 
    ctx.fill();
    ctx.stroke();
    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); 
    ctx.fillStyle = '#FFDAC1'; 
    ctx.fill();
    ctx.stroke();
    ctx.fillStyle = '#8d6e63'; 
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); 
    ctx.fill();
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = CURRENT_BATHTUB;
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; 
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();
    if (isBroken) {
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2, y + height/2 + 30);
        ctx.stroke();
    } else {
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);
    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);
    if (isMobile) ctx.scale(1.5, 1.5); 
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    if (isGrabbing) {
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);
    if (winSequenceRef.current > 0) {
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        ctx.rotate(frameCount.current * 0.2); 
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else if (pettingModeRef.current) {
        ctx.rotate(Math.PI / 2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    if (!isManic) {
        switch(catType) {
            case 'white': bodyColor = '#fff'; break;
            case 'black': bodyColor = '#2d2d2d'; strokeColor = '#1a1a1a'; eyeColor = '#fff'; break;
            case 'tuxedo': bodyColor = '#2d2d2d'; strokeColor = '#1a1a1a'; eyeColor = '#fff'; break;
            case 'calico': bodyColor = '#fff'; break;
            case 'siamese': bodyColor = '#fdf5e6'; break;
            case 'devon': bodyColor = '#a0a0a0'; break;
            case 'orange': bodyColor = '#ffb74d'; strokeColor = '#d35400'; break;
            case 'sphynx': bodyColor = '#f5cba7'; strokeColor = '#d35400'; break;
            case 'tabby': bodyColor = '#bdc3c7'; strokeColor = '#2c3e50'; break;
        }
    } else {
        bodyColor = '#ffcccc'; strokeColor = CRAYON.red; eyeColor = '#ffff00';
    }

    ctx.save();
    ctx.scale(cat.scale, cat.scale);
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; 
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); 
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0 || pettingModeRef.current) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; 
    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic' || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); drawLeg(15, 25, 20, 55); 
    } else if (pettingModeRef.current) {
        drawLeg(-15, 25, -20, 35); drawLeg(15, 25, 20, 35);
    } else {
        drawLeg(-15, 25, -15, 45); drawLeg(15, 25, 15, 45);
    }

    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();
    if (isManic) {
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    if (!isManic) {
        if (catType === 'tuxedo') {
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); 
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }
    ctx.fillStyle = earColor;
    ctx.beginPath();
    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();
    ctx.restore();

    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; 
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; 
        }
        if (winSequenceRef.current > 0 || pettingModeRef.current || bathExitSequenceRef.current > 0) {
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); 
        ctx.beginPath();
        if (pettingModeRef.current) {
            ctx.arc(0, 5, 10, 0, Math.PI);
        } else {
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 10, 10, 5);
        }
        ctx.stroke();
    }

    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';
        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }
    ctx.restore();
  };

  // --- Game Logic ---
  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' | 'heart' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : (type === 'heart' ? heartsRef.current : particlesRef.current);
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' || type === 'heart' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  const handleInteraction = (inputX: number, inputY: number) => {
      // Window Click Detection
      const winX = isMobile ? 50 : 100;
      const winY = isMobile ? 150 : 180;
      const winSize = 200;

      // Use Ref for window status to avoid stale closure if called from event handler
      if (!isWindowOpenRef.current && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          if (inputX > winX && inputX < winX + winSize && inputY > winY && inputY < winY + winSize) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Funny sound for dramatic escape
          }
      }

      // Petting Interaction
      if (pettingModeRef.current) {
          const cat = catRef.current;
          const dist = Math.hypot(inputX - cat.x, inputY - cat.y);
          if (dist < CAT_RADIUS * 2) {
              spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 3, 'heart');
              audio.playLoveSound(); // Cute love sound
          }
      }
  };

  // Touch Handlers
  const handleTouchMove = (e: TouchEvent) => {
    e.preventDefault(); 

    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;

    const scaleX = GAME_WIDTH / rect.width;
    const scaleY = GAME_HEIGHT / rect.height;

    // Track primary finger for hand position
    if (e.touches.length > 0) {
        touchRef.current.active = true;
        const t = e.touches[0];
        touchRef.current.x = (t.clientX - rect.left) * scaleX;
        touchRef.current.y = (t.clientY - rect.top) * scaleY;
    }

    if (e.touches.length >= 2) {
        touchRef.current.isPinching = true;
    } else {
        touchRef.current.isPinching = false;
    }
  };

  const handleCanvasClick = (e: React.MouseEvent) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const scaleX = GAME_WIDTH / rect.width;
      const scaleY = GAME_HEIGHT / rect.height;
      const clickX = (e.clientX - rect.left) * scaleX;
      const clickY = (e.clientY - rect.top) * scaleY;

      handleInteraction(clickX, clickY);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    const canvas = canvasRef.current;

    const onTouchStart = (e: TouchEvent) => {
        const t = e.touches[0];
        if(t) {
            touchRef.current.startX = t.clientX;
            touchRef.current.startY = t.clientY;
            touchRef.current.startTime = Date.now();
            handleTouchMove(e); 
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (e.touches.length === 0) {
            touchRef.current.active = false;
        }
        if (e.touches.length < 2) {
            touchRef.current.isPinching = false;
        }

        // Tap Detection for Mobile Window Opening
        const now = Date.now();
        if (now - touchRef.current.startTime < 300) {
             const t = e.changedTouches[0];
             if (t) {
                 const dist = Math.hypot(t.clientX - touchRef.current.startX, t.clientY - touchRef.current.startY);
                 if (dist < 20) {
                     const rect = canvasRef.current?.getBoundingClientRect();
                     if(rect) {
                         const scaleX = GAME_WIDTH / rect.width;
                         const scaleY = GAME_HEIGHT / rect.height;
                         const clickX = (t.clientX - rect.left) * scaleX;
                         const clickY = (t.clientY - rect.top) * scaleY;
                         handleInteraction(clickX, clickY);
                     }
                 }
             }
        }
    };

    if (canvas) {
        canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
        canvas.addEventListener('touchstart', onTouchStart, { passive: false }); 
        window.addEventListener('touchend', onTouchEnd);
    }

    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      drawRoom(ctx);
      drawFoodBowl(ctx);

      if (touchRef.current.active) {
          const targetX = touchRef.current.x;
          const targetY = touchRef.current.y;
          handRef.current.vx = (targetX - handRef.current.x) * 0.3; 
          handRef.current.vy = (targetY - handRef.current.y) * 0.3;

          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;

          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      } else {
          if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
          if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
          if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
          if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
          handRef.current.vx *= 0.85;
          handRef.current.vy *= 0.85;
          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      }

      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;
        setBathEmote("ε=( o｀ω′)ノ");
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const idx = Math.floor(Math.random() * msgs.length);
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                type: 'bath',
                index: idx,
                x: 20 + Math.random() * 50, 
                y: GAME_HEIGHT - 100 
              }
            ]);
        }
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }
        drawBathtub(ctx);
        drawCat(ctx, cat);

        bubblesRef.current.forEach(p => {
            p.y -= 1; 
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            setBathEmote(null);
            setOwnerMessages([]); 
            bathExitSequenceRef.current = 60; 
            bathExitStartRef.current = { x: cat.x, y: cat.y };
        }
        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      if (bathExitSequenceRef.current > 0) {
          bathExitSequenceRef.current--;
          const maxFrames = 60;
          const progress = 1 - (bathExitSequenceRef.current / maxFrames);
          const ease = 1 - Math.pow(1 - progress, 4); 
          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
          const start = bathExitStartRef.current;
          const cat = catRef.current;

          cat.x = start.x + (rugX - start.x) * ease;
          cat.y = start.y + (rugY - start.y) * ease;
          cat.angle += 0.2; 

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (bathExitSequenceRef.current === 0) {
              pettingModeRef.current = true;
              pettingTimerRef.current = 300; 
              cat.vx = 0; cat.vy = 0;
              cat.angle = Math.PI / 2; 
              audio.playTrill(); 
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      if (pettingModeRef.current) {
          pettingTimerRef.current--;
          const cat = catRef.current;
          const hand = handRef.current;
          const distToHand = Math.hypot(cat.x - hand.x, cat.y - hand.y);
          const isInteracting = (touchRef.current.active || keysPressed.current['Space']) && distToHand < CAT_RADIUS * 2;

          if (isInteracting) {
              if (frameCount.current % 10 === 0) { 
                  spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 1, 'heart');
                  audio.playLoveSound(); 
              }
          }

          drawBathtub(ctx);
          drawCat(ctx, cat);
          drawHand(ctx, handRef.current.x, handRef.current.y, false);

          heartsRef.current.forEach((p, i) => {
            p.y -= 2; 
            p.x += Math.sin(frameCount.current * 0.1 + i) * 0.5;
            p.life -= 0.02;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.font = '24px Arial';
            ctx.fillText('♥', p.x, p.y);
            ctx.globalAlpha = 1;
          });
          heartsRef.current = heartsRef.current.filter(p => p.life > 0);

          if (pettingTimerRef.current <= 0) {
              pettingModeRef.current = false;
              onWin();
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Window Open / Freedom Sequence logic using Refs for up-to-date state
      if (!isWindowOpenRef.current && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0 && windowOpenSequenceRef.current === 0) {
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winSize = 200;
          const hand = handRef.current;
          const cat = catRef.current;

          const overWindow = hand.x > winX && hand.x < winX + winSize && hand.y > winY && hand.y < winY + winSize;

          // Mobile: If holding cat (caught mode) and dragged over window area
          const isMobileHolding = isMobile && cat.mode === 'caught';

          if (overWindow && (keysPressed.current['Space'] || isMobileHolding)) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); 
          }
      }

      if (windowOpenSequenceRef.current > 0) {
          windowOpenSequenceRef.current--;
          const cat = catRef.current;
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winCenterX = winX + 100;
          const winCenterY = winY + 100;

          cat.x += (winCenterX - cat.x) * 0.1;
          cat.y += (winCenterY - cat.y) * 0.1;
          cat.scale *= 0.95;
          cat.angle += 0.2;

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (windowOpenSequenceRef.current === 1) {
              onGameOver(TRANSLATIONS[language].free_msg, 'free');
              return;
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 - 20; 
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); 
        drawCat(ctx, cat);

        if (frameCount.current % 10 === 0) {
             spawnParticles(CURRENT_BATHTUB.x + CURRENT_BATHTUB.width/2, CURRENT_BATHTUB.y + CURRENT_BATHTUB.height/2, '#bdc3c7', 2);
        }
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; 
          cat.angle += 0.1;

          drawBathtub(ctx); 

          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / GAME_WIDTH;
          const scaleY = rect.height / GAME_HEIGHT;

          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; 
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      const isGrabbing = !!keysPressed.current['Space'] || touchRef.current.isPinching;
      const cat = catRef.current;

      const distToFood = Math.hypot(cat.x - CURRENT_FOOD_BOWL.x, cat.y - CURRENT_FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; 

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; 
          spawnParticles(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y, '#8d6e63', 8);
          if (distToFood > 10) {
             cat.vx = (cat.x - CURRENT_FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - CURRENT_FOOD_BOWL.y) * 0.1;
          }
      }

      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; 
          audio.playBouncingSequence(); 
      }

      if (
        cat.x > CURRENT_BATHTUB.x && 
        cat.x < CURRENT_BATHTUB.x + CURRENT_BATHTUB.width && 
        cat.y > CURRENT_BATHTUB.y && 
        cat.y < CURRENT_BATHTUB.y + CURRENT_BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); 
                 tubBrokenSequenceRef.current = 120; 
              }
          } else {
            audio.playSplash();
            audio.playWinAscending(); 
            winSequenceRef.current = 180; 
          }
      }

      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          const angle = isMobile ? -Math.PI/2 : -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - (isMobile ? Math.PI/2 : 0.1), 
                 life: 1.0
             });
          }

          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);

          const plantX = isMobile ? 300 : GAME_WIDTH - 100;
          const plantY = isMobile ? 250 : 180;

          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - plantX, cat.y - plantY);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(plantX, plantY, CRAYON.green, 15);
                  audio.playScratch(); 
              }
          }

          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + (isMobile ? 50 : 30); 

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); 
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; 
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          if (cat.mode !== 'caught') {
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; 
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; 

                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const idx = Math.floor(Math.random() * ouchMsgs.length);
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          type: 'ouch',
                          index: idx,
                          x: 20 + Math.random() * 20, 
                          y: GAME_HEIGHT - 100 
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); 
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); 
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > GAME_WIDTH - r) { cat.x = GAME_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > GAME_HEIGHT - r) { cat.y = GAME_HEIGHT - r; cat.vy *= -1; }
          }
      }

      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playVariedMeow(catType); 
          }
      }

      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        if (canvas) {
            canvas.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchstart', onTouchStart); // Clean up custom handler
            window.removeEventListener('touchend', onTouchEnd);
            canvas.removeEventListener('click', handleCanvasClick);
        }

        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language, isMobile]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH} 
        height={isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none touch-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 p-2 md:p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md scale-75 md:scale-100 origin-top-left">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) - DYNAMIC TEXT RENDERING */}
      {ownerMessages.map((msg) => {
        // Resolve text based on current language prop
        let text = "";
        if (msg.type === 'bath') {
           const list = TRANSLATIONS[language].bath_messages;
           const safeIndex = msg.index % list.length;
           text = list[safeIndex] + " ♥";
        } else {
           const list = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
           const safeIndex = msg.index % list.length;
           text = list[safeIndex];
        }

        return (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute bg-white border-4 border-black px-4 py-2 md:px-6 md:py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left z-40"
          style={isMobile ? {
            top: '10%',
            left: '50%',
            transform: 'translateX(-50%)' // Center at top for mobile
          } : { 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-xl md:text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{text}</span>
          {!isMobile && <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>}
        </div>
        );
      })}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            // On mobile, force thought bubbles higher so they aren't covered by thumb/cat
            top: isMobile 
                 ? '15%' 
                 : ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', 
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-lg md:text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-xl shadow-xl animate-bounce z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / (isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT)) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-2xl md:text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default GameEngine;

import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  MOBILE_CANVAS_WIDTH, 
  MOBILE_CANVAS_HEIGHT,
  CAT_RADIUS, 
  BATHTUB, 
  MOBILE_BATHTUB,
  FOOD_BOWL,
  MOBILE_FOOD_BOWL,
  MAX_HP, 
  CATCH_DISTANCE,
  TRANSLATIONS
} from '../constants';
import { CatEntity, Particle, Point, CatType, Language, GameOverReason } from '../types';
import { audio } from '../services/audioService';
import { generateCatThought } from '../services/geminiService';

interface GameEngineProps {
  onGameOver: (message: string, reason: GameOverReason) => void;
  onWin: (timeElapsed: number) => void;
  catType: CatType;
  temperament: number;
  language: Language;
  isMobile: boolean;
}

interface OwnerMessage {
  id: number;
  type: 'bath' | 'ouch';
  index: number;
  x: number;
  y: number;
}

interface PawPrint {
  x: number;
  y: number;
  angle: number;
  life: number;
}

// Vibrant Crayon Colors
const CRAYON = {
  black: '#2d2d2d',
  red: '#ff6b6b',
  blue: '#4dabf7',
  orange: '#ffa94d',
  skin: '#ffc9c9',
  green: '#69db7c',
  wood: '#d4a373',
  wall: '#f8f9fa'
};

const GameEngine: React.FC<GameEngineProps> = ({ onGameOver, onWin, catType, temperament, language, isMobile }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null); // For elements escaping the box
  const hpRef = useRef<number>(MAX_HP);
  const [currentHp, setCurrentHp] = useState(MAX_HP);
  const [catThought, setCatThought] = useState<string>("");
  const [bathEmote, setBathEmote] = useState<string | null>(null);
  const [ownerMessages, setOwnerMessages] = useState<OwnerMessage[]>([]);

  const winSequenceRef = useRef<number>(0); // 0: playing, >0: animating bath
  const tubBrokenSequenceRef = useRef<number>(0); // 0: intact, >0: animating break

  // New States for Features
  const [isWindowOpen, setIsWindowOpen] = useState<boolean>(false);
  const isWindowOpenRef = useRef<boolean>(false); // Ref for loop access
  const windowOpenSequenceRef = useRef<number>(0); // Animation timer for cat flying out
  const pettingModeRef = useRef<boolean>(false); // Intermediate mode before calling onWin
  const pettingTimerRef = useRef<number>(0);

  // Game Timer state
  const startTimeRef = useRef<number>(Date.now());
  const finalTimeRef = useRef<number>(0);

  // Bath Exit (Rolling Out) State
  const bathExitSequenceRef = useRef<number>(0);
  const bathExitStartRef = useRef<Point>({x: 0, y: 0});

  // Game Dimensions based on Mobile state
  const GAME_WIDTH = isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH;
  const GAME_HEIGHT = isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT;
  const CURRENT_BATHTUB = isMobile ? MOBILE_BATHTUB : BATHTUB;
  const CURRENT_FOOD_BOWL = isMobile ? MOBILE_FOOD_BOWL : FOOD_BOWL;

  // Game State
  const catRef = useRef<CatEntity>({
    x: GAME_WIDTH / 2,
    y: GAME_HEIGHT / 2,
    vx: 0,
    vy: 0,
    mode: 'idle',
    angle: 0,
    scale: isMobile ? 1.5 : 1 // Start bigger on mobile
  });

  const handRef = useRef<Point & { vx: number, vy: number }>({ x: 100, y: 100, vx: 0, vy: 0 });
  const keysPressed = useRef<{ [key: string]: boolean }>({});

  // Touch State
  const touchRef = useRef<{
    active: boolean;
    x: number;
    y: number;
    startX: number;
    startY: number;
    startTime: number;
    isPinching: boolean;
    tapDetected: boolean;
  }>({
    active: false,
    x: 0,
    y: 0,
    startX: 0,
    startY: 0,
    startTime: 0,
    isPinching: false,
    tapDetected: false
  });

  const particlesRef = useRef<Particle[]>([]);
  const bubblesRef = useRef<Particle[]>([]); // Specific for bath
  const heartsRef = useRef<Particle[]>([]); // Specific for petting
  const pawPrintsRef = useRef<PawPrint[]>([]);
  const plantTrimmedRef = useRef<boolean>(false);

  const cloudXRef = useRef<number>(0); // Cloud position for window
  const lastThoughtTime = useRef<number>(0);
  const lastDamageTime = useRef<number>(0); // Cooldown for taking damage
  const lastEatTime = useRef<number>(0);
  const manicTimer = useRef<number>(0);
  const frameCount = useRef<number>(0);

  // Rolling ending state
  const isRollingAwayRef = useRef<boolean>(false);

  // Clear cat thought when language changes to avoid stale text
  useEffect(() => {
    setCatThought("");
  }, [language]);

  // Sync isWindowOpenRef
  useEffect(() => {
      isWindowOpenRef.current = isWindowOpen;
  }, [isWindowOpen]);

  // --- Crayon Drawing Helpers ---
  const drawCrayonLine = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color: string, width: number = 3) => {
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.4;
    ctx.lineWidth = width * 2;
    const jitter1 = () => (Math.random() - 0.5) * 1.0; 
    ctx.moveTo(x1 + jitter1(), y1 + jitter1());
    ctx.lineTo(x2 + jitter1(), y2 + jitter1());
    ctx.stroke();
    ctx.beginPath();
    ctx.globalAlpha = 1.0;
    ctx.lineWidth = width;
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
    ctx.beginPath();
    ctx.lineWidth = 1;
    const jitter2 = () => (Math.random() - 0.5) * 0.8; 
    ctx.moveTo(x1 + jitter2(), y1 + jitter2());
    ctx.lineTo(x2 + jitter2(), y2 + jitter2());
    ctx.stroke();
  };

  const drawScribbleFill = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, color: string, clean: boolean = false) => {
    ctx.save();
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
    if (!clean) {
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<6; i++) {
            const angle = i * (Math.PI * 2 / 6);
            const dist = r * 0.7; 
            const ax = x + Math.cos(angle) * dist + (i%2===0 ? 2 : -2);
            const ay = y + Math.sin(angle) * dist;
            const bx = x + Math.cos(angle + 2) * (dist * 0.5);
            const by = y + Math.sin(angle + 2) * (dist * 0.5);
            ctx.moveTo(ax, ay);
            ctx.lineTo(bx, by);
        }
        ctx.stroke();
    }
    ctx.restore();
  };

  // --- Scene Drawing ---
  const drawRoom = (ctx: CanvasRenderingContext2D) => {
    ctx.fillStyle = '#fffdf5';
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.beginPath();
    ctx.strokeStyle = '#f0e6d2';
    ctx.lineWidth = 2;
    for(let i = 0; i < GAME_HEIGHT; i+= 60) {
        ctx.moveTo(0, i + (Math.random()*0.5));
        ctx.lineTo(GAME_WIDTH, i + (Math.random()*0.5));
    }
    ctx.stroke();
    const rugX = GAME_WIDTH / 2;
    const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
    ctx.save();
    ctx.translate(rugX, rugY);
    ctx.rotate(isMobile ? Math.PI / 2 : 0.1); 
    ctx.beginPath();
    ctx.ellipse(0, 0, 300, 150, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#ffec99';
    ctx.fill();
    ctx.lineWidth = 4;
    ctx.strokeStyle = CRAYON.orange;
    ctx.stroke();
    ctx.beginPath();
    ctx.ellipse(0, 0, 250, 120, 0, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffc078';
    ctx.setLineDash([10, 10]);
    ctx.stroke();
    ctx.setLineDash([]);
    pawPrintsRef.current.forEach(p => {
        ctx.save();
        ctx.translate(p.x, p.y); 
        ctx.rotate(p.angle);
        ctx.globalAlpha = p.life * 0.6;
        ctx.fillStyle = '#d4a373'; 
        ctx.beginPath();
        ctx.ellipse(0, 0, 6, 5, 0, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath(); ctx.arc(-6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(0, -9, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(6, -6, 2.5, 0, Math.PI*2); ctx.fill();
        ctx.restore();
    });
    ctx.restore();

    ctx.save();
    const winX = isMobile ? 50 : 100;
    const winY = isMobile ? 150 : 180;
    ctx.translate(winX, winY);

    // Window drawing
    ctx.fillStyle = isWindowOpen ? '#87CEEB' : '#dbe4ff';
    ctx.fillRect(0, 0, 200, 200);

    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, 200, 200);
    ctx.clip(); 
    cloudXRef.current += 0.5;
    if (cloudXRef.current > 280) cloudXRef.current = -120;
    const cx = cloudXRef.current;
    const cy = 80 + Math.sin(frameCount.current * 0.02) * 10;
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    ctx.ellipse(cx, cy, 40, 30, 0, 0, Math.PI * 2);
    ctx.ellipse(cx - 30, cy - 10, 25, 25, 0, 0, Math.PI * 2);
    ctx.moveTo(cx - 45, cy - 25); ctx.lineTo(cx - 50, cy - 45); ctx.lineTo(cx - 30, cy - 30);
    ctx.moveTo(cx - 20, cy - 30); ctx.lineTo(cx - 10, cy - 45); ctx.lineTo(cx - 5, cy - 25);
    ctx.ellipse(cx + 40, cy, 15, 15, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.strokeStyle = CRAYON.wood;
    ctx.lineWidth = 8;
    ctx.strokeRect(0, 0, 200, 200);
    if (isWindowOpen) {
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeStyle = CRAYON.wood;
        ctx.beginPath();
        ctx.moveTo(0, 0); ctx.lineTo(-40, 10); ctx.lineTo(-40, 190); ctx.lineTo(0, 200);
        ctx.fill(); ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(200, 0); ctx.lineTo(240, 10); ctx.lineTo(240, 190); ctx.lineTo(200, 200);
        ctx.fill(); ctx.stroke();
    } else {
        ctx.beginPath();
        ctx.moveTo(100, 0); ctx.lineTo(100, 200);
        ctx.moveTo(0, 100); ctx.lineTo(200, 100);
        ctx.stroke();
    }
    ctx.restore();

    ctx.save();
    const plantX = isMobile ? 300 : GAME_WIDTH - 100;
    const plantY = isMobile ? 250 : 180;
    ctx.translate(plantX, plantY);

    if (plantTrimmedRef.current) {
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
        ctx.beginPath();
        ctx.arc(0, -30, 35, 0, Math.PI*2); 
        ctx.fill();
        ctx.beginPath(); ctx.moveTo(-30, -50); ctx.lineTo(-40, -80); ctx.lineTo(-10, -60); ctx.fill();
        ctx.beginPath(); ctx.moveTo(30, -50); ctx.lineTo(40, -80); ctx.lineTo(10, -60); ctx.fill();
        ctx.fillStyle = '#f1c40f'; 
        ctx.strokeStyle = '#e67e22'; 
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(-15, -60); 
        ctx.lineTo(-25, -85); ctx.lineTo(-8, -70);
        ctx.lineTo(0, -90); 
        ctx.lineTo(8, -70); ctx.lineTo(25, -85); 
        ctx.lineTo(15, -60);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
    } else {
        ctx.fillStyle = CRAYON.green;
        ctx.beginPath();
        ctx.ellipse(0, -40, 30, 60, 0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(20, -30, 30, 60, -0.5, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(-20, -20, 30, 60, 0.2, 0, Math.PI*2);
        ctx.fill();
    }
    ctx.fillStyle = CRAYON.red;
    ctx.beginPath();
    ctx.moveTo(-30, 0); ctx.lineTo(30, 0); ctx.lineTo(20, 60); ctx.lineTo(-20, 60);
    ctx.fill();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.restore();
  };

  const drawFoodBowl = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.translate(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y);
    if (isMobile) ctx.scale(1.4, 1.4); 
    ctx.fillStyle = '#FFB7B2'; 
    ctx.beginPath();
    ctx.ellipse(0, 10, 35, 15, 0, 0, Math.PI * 2); 
    ctx.fill();
    ctx.stroke();
    ctx.beginPath();
    ctx.ellipse(0, 0, 35, 15, 0, 0, Math.PI * 2); 
    ctx.fillStyle = '#FFDAC1'; 
    ctx.fill();
    ctx.stroke();
    ctx.fillStyle = '#8d6e63'; 
    ctx.beginPath();
    ctx.ellipse(0, 2, 25, 10, 0, 0, Math.PI * 2); 
    ctx.fill();
    ctx.fillStyle = '#5d4037';
    const pebbleOffsets = [
        {x: -10, y: -2}, {x: 10, y: -2}, {x: 0, y: 0}, {x: -5, y: 5}, {x: 5, y: 5},
        {x: -15, y: 2}, {x: 15, y: 2}
    ];
    pebbleOffsets.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2); ctx.fill();
    });
    ctx.fillStyle = '#fff';
    ctx.font = '12px "Chewy"';
    ctx.fillText("YUM", -12, 15);
    ctx.restore();
  };

  const drawBathtub = (ctx: CanvasRenderingContext2D, isBroken: boolean = false) => {
    ctx.save();
    const { x, y, width, height } = CURRENT_BATHTUB;
    const pipeX = x + width - 40;
    const pipeTop = y - 120;
    ctx.beginPath();
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 8;
    ctx.lineCap = 'round';
    ctx.moveTo(pipeX + 20, y + height); 
    ctx.lineTo(pipeX + 20, pipeTop);
    ctx.quadraticCurveTo(pipeX + 20, pipeTop - 30, pipeX - 20, pipeTop - 30);
    ctx.stroke();
    ctx.save();
    ctx.translate(pipeX - 30, pipeTop - 30);
    ctx.rotate(0.4);
    ctx.fillStyle = '#bdc3c7';
    ctx.beginPath();
    ctx.moveTo(0, -10); ctx.lineTo(30, 10); ctx.lineTo(25, 20); ctx.lineTo(-5, 0);
    ctx.fill();
    ctx.fillStyle = '#7f8c8d'; 
    ctx.beginPath();
    ctx.ellipse(28, 15, 5, 12, 0.5, 0, Math.PI*2);
    ctx.fill();
    if (winSequenceRef.current > 0 && !isBroken) {
        const showerX = 28;
        const showerY = 15;
        ctx.strokeStyle = '#a5d8ff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        for(let i=0; i<5; i++) {
             ctx.moveTo(showerX + (i*4-8), showerY);
             ctx.lineTo(showerX + (i*6-12) - 20, showerY + 200);
        }
        ctx.stroke();
    }
    ctx.restore();
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 4;
    drawCrayonLine(ctx, x + 20, y + height, x + 20, y + height + 20, CRAYON.black);
    drawCrayonLine(ctx, x + width - 20, y + height, x + width - 20, y + height + 20, CRAYON.black);
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.roundRect(x, y, width, height, 20);
    ctx.fill();
    ctx.strokeStyle = CRAYON.blue;
    ctx.lineWidth = 4;
    ctx.stroke();
    if (isBroken) {
        ctx.strokeStyle = '#2d2d2d';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x + 40, y + 10);
        ctx.lineTo(x + 70, y + 80);
        ctx.lineTo(x + 50, y + 140);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + width - 40, y + 10);
        ctx.lineTo(x + width - 70, y + 80);
        ctx.lineTo(x + width - 50, y + 140);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 - 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 - 20);
        ctx.moveTo(x + width/2, y + height/2);
        ctx.lineTo(x + width/2 + 20, y + height/2 + 30);
        ctx.stroke();
    } else {
        ctx.save();
        ctx.clip();
        const waterLevel = y + 40 + Math.sin(frameCount.current * 0.05) * 5;
        ctx.fillStyle = '#a5d8ff';
        ctx.fillRect(x, waterLevel, width, height);
        ctx.strokeStyle = '#74c0fc';
        ctx.lineWidth = 3;
        ctx.beginPath();
        for (let i = x + 10; i < x + width - 10; i += 20) {
            const waveY = waterLevel + 15 + Math.sin(i * 0.15 + frameCount.current * 0.1) * 6;
            ctx.moveTo(i, waveY);
            ctx.lineTo(i + 12, waveY);
        }
        ctx.stroke();
        ctx.restore();
    }
    ctx.fillStyle = CRAYON.blue;
    ctx.font = '30px "Chewy"';
    ctx.fillText("BATH", x + 75, y + height - 20);
    ctx.restore();
  };

  const drawHand = (ctx: CanvasRenderingContext2D, x: number, y: number, isGrabbing: boolean) => {
    ctx.save();
    ctx.translate(x, y);
    if (isMobile) ctx.scale(1.5, 1.5); 
    ctx.fillStyle = CRAYON.skin;
    ctx.strokeStyle = CRAYON.black;
    ctx.lineWidth = 3;
    if (isGrabbing) {
        ctx.beginPath();
        ctx.ellipse(0, 0, 30, 25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(-15, 0); ctx.quadraticCurveTo(0, 10, 15, 0);
        ctx.stroke();
    } else {
        ctx.rotate(-0.2);
        ctx.beginPath();
        ctx.arc(0, 0, 25, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        const fingerOffsets = [-18, -6, 6, 18];
        fingerOffsets.forEach(off => {
            ctx.beginPath();
            ctx.ellipse(off, -25, 8, 18, 0, 0, Math.PI * 2);
            ctx.fillStyle = CRAYON.skin;
            ctx.fill();
            ctx.stroke();
        });
        ctx.beginPath();
        ctx.ellipse(-30, 10, 10, 18, -0.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
    ctx.restore();
  };

  const drawCat = (ctx: CanvasRenderingContext2D, cat: CatEntity) => {
    ctx.save();
    ctx.translate(cat.x, cat.y);
    if (winSequenceRef.current > 0) {
        ctx.rotate(Math.sin(frameCount.current * 0.5) * 0.2);
    } else if (isRollingAwayRef.current || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        ctx.rotate(frameCount.current * 0.2); 
    } else if (cat.mode === 'caught') {
        const swing = Math.sin(frameCount.current * 0.2) * 0.1;
        ctx.rotate(swing);
    } else if (cat.mode === 'run') {
        const lean = Math.atan2(cat.vy, cat.vx);
        ctx.rotate(lean * 0.2);
    } else if (pettingModeRef.current) {
        ctx.rotate(Math.PI / 2);
    } else {
        ctx.scale(1, 1 + Math.sin(frameCount.current * 0.1) * 0.02);
    }

    const isManic = cat.mode === 'manic';
    let bodyColor = '#fff';
    let strokeColor = CRAYON.black;
    let eyeColor = CRAYON.black;

    if (!isManic) {
        switch(catType) {
            case 'white': bodyColor = '#fff'; break;
            case 'black': bodyColor = '#2d2d2d'; strokeColor = '#1a1a1a'; eyeColor = '#fff'; break;
            case 'tuxedo': bodyColor = '#2d2d2d'; strokeColor = '#1a1a1a'; eyeColor = '#fff'; break;
            case 'calico': bodyColor = '#fff'; break;
            case 'siamese': bodyColor = '#fdf5e6'; break;
            case 'devon': bodyColor = '#a0a0a0'; break;
            case 'orange': bodyColor = '#ffb74d'; strokeColor = '#d35400'; break;
            case 'sphynx': bodyColor = '#f5cba7'; strokeColor = '#d35400'; break;
            case 'tabby': bodyColor = '#bdc3c7'; strokeColor = '#2c3e50'; break;
        }
    } else {
        bodyColor = '#ffcccc'; strokeColor = CRAYON.red; eyeColor = '#ffff00';
    }

    ctx.save();
    ctx.scale(cat.scale, cat.scale);
    ctx.beginPath();
    ctx.strokeStyle = strokeColor;
    if (catType === 'siamese' && !isManic) ctx.strokeStyle = '#4b3621'; 
    ctx.lineWidth = 5;
    ctx.lineCap = 'round';
    if (cat.mode === 'caught') {
        ctx.moveTo(30, 20); ctx.quadraticCurveTo(40, 60, 30, 80);
    } else if (isManic) {
        ctx.moveTo(35, 10); ctx.lineTo(55, -20); ctx.lineTo(75, 10); 
    } else if (cat.mode === 'idle' || winSequenceRef.current > 0 || pettingModeRef.current) {
        const wag = Math.sin(frameCount.current * 0.15) * 20;
        ctx.moveTo(35, 10); ctx.bezierCurveTo(60, 10, 60 + wag, -40, 35, -30);
    } else {
        ctx.moveTo(35, 10); ctx.lineTo(70, 0);
    }
    ctx.stroke();

    ctx.lineWidth = 4;
    let legColor = strokeColor;
    if (catType === 'siamese' && !isManic) legColor = '#4b3621'; 
    const drawLeg = (x1: number, y1: number, x2: number, y2: number) => {
        drawCrayonLine(ctx, x1, y1, x2, y2, legColor, 4);
    };

    if (winSequenceRef.current > 0) {
        const splash = Math.sin(frameCount.current * 0.8) * 5;
        drawLeg(-20, 20, -30, 30 + splash);
        drawLeg(20, 20, 30, 30 - splash);
    } else if (cat.mode === 'run' || cat.mode === 'manic' || windowOpenSequenceRef.current > 0 || bathExitSequenceRef.current > 0) {
        const legOffset = Math.sin(frameCount.current * 0.8) * 12;
        drawLeg(-20, 20, -25 + legOffset, 45);
        drawLeg(20, 20, 25 - legOffset, 45);
    } else if (cat.mode === 'caught') {
        drawLeg(-15, 25, -20, 55); drawLeg(15, 25, 20, 55); 
    } else if (pettingModeRef.current) {
        drawLeg(-15, 25, -20, 35); drawLeg(15, 25, 20, 35);
    } else {
        drawLeg(-15, 25, -15, 45); drawLeg(15, 25, 15, 45);
    }

    ctx.fillStyle = bodyColor;
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.beginPath();
    if (isManic) {
        for (let i = 0; i < Math.PI * 2; i += 0.4) {
            const r = CAT_RADIUS + (Math.random() * 4);
            const bx = Math.cos(i) * r;
            const by = Math.sin(i) * r * 0.8;
            ctx.lineTo(bx, by);
        }
    } else {
        if (catType === 'devon' || catType === 'sphynx') {
            ctx.ellipse(0, 0, CAT_RADIUS * 0.9, CAT_RADIUS * 0.8, 0, 0, Math.PI * 2);
        } else {
            ctx.ellipse(0, 0, CAT_RADIUS, CAT_RADIUS * 0.85, 0, 0, Math.PI * 2);
        }
    }
    ctx.closePath();
    ctx.fill();

    if (!isManic) {
        if (catType === 'tuxedo') {
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.ellipse(0, 12, 22, 18, 0, 0, Math.PI * 2);
            ctx.fill();
        } else if (catType === 'calico') {
            drawScribbleFill(ctx, -15, -12, 12, CRAYON.orange, true); 
            drawScribbleFill(ctx, 18, 10, 10, '#2d2d2d');
            drawScribbleFill(ctx, 10, -15, 8, CRAYON.orange);
        } else if (catType === 'orange' || catType === 'tabby') {
             const stripeColor = catType === 'orange' ? '#d35400' : '#2c3e50';
             ctx.strokeStyle = stripeColor;
             ctx.lineWidth = 3;
             ctx.beginPath();
             ctx.moveTo(-10, -25); ctx.lineTo(-10, -15);
             ctx.moveTo(0, -28); ctx.lineTo(0, -18);
             ctx.moveTo(10, -25); ctx.lineTo(10, -15);
             ctx.stroke();
             ctx.beginPath();
             ctx.moveTo(-25, -5); ctx.lineTo(-15, -5);
             ctx.moveTo(-28, 5); ctx.lineTo(-18, 5);
             ctx.moveTo(25, -5); ctx.lineTo(15, -5);
             ctx.moveTo(28, 5); ctx.lineTo(18, 5);
             ctx.stroke();
        } else if (catType === 'sphynx') {
            ctx.strokeStyle = '#d35400';
            ctx.lineWidth = 1;
            ctx.globalAlpha = 0.3;
            ctx.beginPath();
            ctx.moveTo(-10, -25); ctx.quadraticCurveTo(0, -20, 10, -25);
            ctx.moveTo(-12, -20); ctx.quadraticCurveTo(0, -15, 12, -20);
            ctx.stroke();
            ctx.globalAlpha = 1.0;
        }
    }

    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = 4;
    ctx.stroke();

    let earColor = bodyColor;
    if (!isManic) {
        if (catType === 'siamese') earColor = '#4b3621';
        if (catType === 'black' || catType === 'tuxedo') earColor = '#2d2d2d';
    }
    ctx.fillStyle = earColor;
    ctx.beginPath();
    if ((catType === 'devon' || catType === 'sphynx') && !isManic) {
        ctx.moveTo(-25, -20); ctx.lineTo(-45, -65); ctx.lineTo(-5, -30);
        ctx.moveTo(25, -20); ctx.lineTo(45, -65); ctx.lineTo(5, -30);
    } else {
        ctx.moveTo(-20, -25); ctx.lineTo(-35, -55); ctx.lineTo(-5, -35);
        ctx.moveTo(20, -25); ctx.lineTo(35, -55); ctx.lineTo(5, -35);
    }
    ctx.fill();
    ctx.stroke();
    ctx.restore();

    if (isManic) {
        ctx.strokeStyle = CRAYON.red;
        drawCrayonLine(ctx, -25, -15, -10, -5, CRAYON.red, 3);
        drawCrayonLine(ctx, 25, -15, 10, -5, CRAYON.red, 3);
        ctx.fillStyle = '#ffff00';
        ctx.beginPath(); ctx.arc(-15, -5, 5, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(15, -5, 5, 0, Math.PI*2); ctx.fill();
    } else if (cat.mode === 'caught') {
        ctx.fillStyle = eyeColor;
        ctx.font = '24px Arial';
        ctx.fillText('><', -12, 5);
    } else {
        if (!isManic && catType === 'siamese') {
             ctx.fillStyle = '#4b3621'; 
             ctx.beginPath();
             ctx.ellipse(0, 0, 18, 14, 0, 0, Math.PI*2);
             ctx.fill();
             eyeColor = '#a5d8ff'; 
        }
        if (winSequenceRef.current > 0 || pettingModeRef.current || bathExitSequenceRef.current > 0) {
            ctx.strokeStyle = eyeColor;
            ctx.lineWidth = 3;
            ctx.beginPath(); ctx.moveTo(-20, -5); ctx.lineTo(-10, -15); ctx.lineTo(0, -5); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(10, -15); ctx.lineTo(20, -5); ctx.stroke();
        } else {
            ctx.fillStyle = eyeColor;
            ctx.beginPath(); ctx.arc(-12, -10, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(12, -10, 4, 0, Math.PI*2); ctx.fill();
        }
    }

    if (!isManic) {
        ctx.strokeStyle = strokeColor;
        if (catType === 'black' || catType === 'tuxedo' || catType === 'siamese') ctx.strokeStyle = '#999';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -2); ctx.lineTo(-2, 2); ctx.lineTo(2, 2); ctx.lineTo(0, -2); ctx.stroke(); 
        ctx.beginPath();
        if (pettingModeRef.current) {
            ctx.arc(0, 5, 10, 0, Math.PI);
        } else {
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(-5, 10, -10, 5);
            ctx.moveTo(0, 2); ctx.quadraticCurveTo(5, 8, 10, 5);
        }
        ctx.stroke();
    }

    if (catType !== 'sphynx') {
        ctx.lineWidth = 1;
        ctx.strokeStyle = strokeColor;
        if (!isManic && (catType === 'black' || catType === 'tuxedo' || catType === 'siamese')) ctx.strokeStyle = '#999';
        drawCrayonLine(ctx, -25, 2, -50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, -25, 6, -50, 10, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 2, 50, -2, ctx.strokeStyle as string, 1);
        drawCrayonLine(ctx, 25, 6, 50, 10, ctx.strokeStyle as string, 1);
    }
    ctx.restore();
  };

  // --- Game Logic ---
  const spawnParticles = (x: number, y: number, color: string, count: number, type: 'sparkle' | 'bubble' | 'heart' = 'sparkle') => {
    const arr = type === 'bubble' ? bubblesRef.current : (type === 'heart' ? heartsRef.current : particlesRef.current);
    for (let i = 0; i < count; i++) {
      arr.push({
        x, y,
        vx: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12),
        vy: (Math.random() - 0.5) * (type === 'bubble' ? 4 : 12) - (type === 'bubble' || type === 'heart' ? 2 : 0),
        life: 1.0,
        color
      });
    }
  };

  const handleInteraction = (inputX: number, inputY: number) => {
      // Window Click Detection
      const winX = isMobile ? 50 : 100;
      const winY = isMobile ? 150 : 180;
      const winSize = 200;

      // Use Ref for window status to avoid stale closure if called from event handler
      if (!isWindowOpenRef.current && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          if (inputX > winX && inputX < winX + winSize && inputY > winY && inputY < winY + winSize) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); // Funny sound for dramatic escape
          }
      }

      // Petting Interaction
      if (pettingModeRef.current) {
          const cat = catRef.current;
          const dist = Math.hypot(inputX - cat.x, inputY - cat.y);
          if (dist < CAT_RADIUS * 2) {
              spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 3, 'heart');
              audio.playLoveSound(); // Cute love sound
          }
      }
  };

  // Touch Handlers
  const handleTouchMove = (e: TouchEvent) => {
    e.preventDefault(); 

    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;

    const scaleX = GAME_WIDTH / rect.width;
    const scaleY = GAME_HEIGHT / rect.height;

    // Track primary finger for hand position
    if (e.touches.length > 0) {
        touchRef.current.active = true;
        const t = e.touches[0];
        touchRef.current.x = (t.clientX - rect.left) * scaleX;
        touchRef.current.y = (t.clientY - rect.top) * scaleY;
    }

    if (e.touches.length >= 2) {
        touchRef.current.isPinching = true;
    } else {
        touchRef.current.isPinching = false;
    }
  };

  const handleCanvasClick = (e: React.MouseEvent) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const scaleX = GAME_WIDTH / rect.width;
      const scaleY = GAME_HEIGHT / rect.height;
      const clickX = (e.clientX - rect.left) * scaleX;
      const clickY = (e.clientY - rect.top) * scaleY;

      handleInteraction(clickX, clickY);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysPressed.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysPressed.current[e.code] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    const canvas = canvasRef.current;

    const onTouchStart = (e: TouchEvent) => {
        const t = e.touches[0];
        if(t) {
            touchRef.current.startX = t.clientX;
            touchRef.current.startY = t.clientY;
            touchRef.current.startTime = Date.now();
            handleTouchMove(e); 
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (e.touches.length === 0) {
            touchRef.current.active = false;
        }
        if (e.touches.length < 2) {
            touchRef.current.isPinching = false;
        }

        // Tap Detection for Mobile Window Opening
        const now = Date.now();
        if (now - touchRef.current.startTime < 300) {
             const t = e.changedTouches[0];
             if (t) {
                 const dist = Math.hypot(t.clientX - touchRef.current.startX, t.clientY - touchRef.current.startY);
                 if (dist < 20) {
                     const rect = canvasRef.current?.getBoundingClientRect();
                     if(rect) {
                         const scaleX = GAME_WIDTH / rect.width;
                         const scaleY = GAME_HEIGHT / rect.height;
                         const clickX = (t.clientX - rect.left) * scaleX;
                         const clickY = (t.clientY - rect.top) * scaleY;
                         handleInteraction(clickX, clickY);
                     }
                 }
             }
        }
    };

    if (canvas) {
        canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
        canvas.addEventListener('touchstart', onTouchStart, { passive: false }); 
        window.addEventListener('touchend', onTouchEnd);
    }

    const resizeOverlay = () => {
        if (overlayCanvasRef.current) {
            overlayCanvasRef.current.width = window.innerWidth;
            overlayCanvasRef.current.height = window.innerHeight;
        }
    };
    window.addEventListener('resize', resizeOverlay);
    resizeOverlay();

    audio.resume();
    audio.startBGM(catType);

    // Initialize Timer
    startTimeRef.current = Date.now();

    let animationFrameId: number;

    const loop = () => {
      const canvas = canvasRef.current;
      const overlayCanvas = overlayCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      const oCtx = overlayCanvas?.getContext('2d');

      if (!canvas || !ctx || !overlayCanvas || !oCtx) return;

      frameCount.current++;
      const now = Date.now();

      oCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);

      drawRoom(ctx);
      drawFoodBowl(ctx);

      if (touchRef.current.active) {
          const targetX = touchRef.current.x;
          const targetY = touchRef.current.y;
          handRef.current.vx = (targetX - handRef.current.x) * 0.3; 
          handRef.current.vy = (targetY - handRef.current.y) * 0.3;

          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;

          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      } else {
          if (keysPressed.current['KeyW']) handRef.current.vy -= 1.5;
          if (keysPressed.current['KeyS']) handRef.current.vy += 1.5;
          if (keysPressed.current['KeyA']) handRef.current.vx -= 1.5;
          if (keysPressed.current['KeyD']) handRef.current.vx += 1.5;
          handRef.current.vx *= 0.85;
          handRef.current.vy *= 0.85;
          handRef.current.x += handRef.current.vx;
          handRef.current.y += handRef.current.vy;
          handRef.current.x = Math.max(0, Math.min(GAME_WIDTH, handRef.current.x));
          handRef.current.y = Math.max(0, Math.min(GAME_HEIGHT, handRef.current.y));
      }

      if (winSequenceRef.current > 0) {
        winSequenceRef.current--;
        setBathEmote("ε=( o｀ω′)ノ");
        if (winSequenceRef.current % 50 === 0) {
            const msgs = TRANSLATIONS[language].bath_messages;
            const idx = Math.floor(Math.random() * msgs.length);
            setOwnerMessages(prev => [
              ...prev, 
              {
                id: Date.now(),
                type: 'bath',
                index: idx,
                x: 20 + Math.random() * 50, 
                y: GAME_HEIGHT - 100 
              }
            ]);
        }
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 + Math.sin(frameCount.current * 0.2) * 5;
        cat.vx = 0; cat.vy = 0;

        if (frameCount.current % 5 === 0) {
            spawnParticles(cat.x + (Math.random()-0.5)*50, cat.y, '#fff', 1, 'bubble');
        }
        drawBathtub(ctx);
        drawCat(ctx, cat);

        bubblesRef.current.forEach(p => {
            p.y -= 1; 
            p.x += Math.sin(p.y * 0.1) * 0.5;
            p.life -= 0.01;
            ctx.beginPath();
            ctx.strokeStyle = '#a5d8ff';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.arc(p.x, p.y, 5 + Math.random()*5, 0, Math.PI*2);
            ctx.fill();
            ctx.stroke();
        });
        bubblesRef.current = bubblesRef.current.filter(p => p.life > 0);

        if (winSequenceRef.current === 1) {
            setBathEmote(null);
            setOwnerMessages([]); 
            bathExitSequenceRef.current = 60; 
            bathExitStartRef.current = { x: cat.x, y: cat.y };
        }
        animationFrameId = requestAnimationFrame(loop);
        return; 
      } else {
        setBathEmote(null);
      }

      if (bathExitSequenceRef.current > 0) {
          bathExitSequenceRef.current--;
          const maxFrames = 60;
          const progress = 1 - (bathExitSequenceRef.current / maxFrames);
          const ease = 1 - Math.pow(1 - progress, 4); 
          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;
          const start = bathExitStartRef.current;
          const cat = catRef.current;

          cat.x = start.x + (rugX - start.x) * ease;
          cat.y = start.y + (rugY - start.y) * ease;
          cat.angle += 0.2; 

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (bathExitSequenceRef.current === 0) {
              pettingModeRef.current = true;
              pettingTimerRef.current = 300; 
              cat.vx = 0; cat.vy = 0;
              cat.angle = Math.PI / 2; 
              audio.playTrill(); 
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      if (pettingModeRef.current) {
          pettingTimerRef.current--;
          const cat = catRef.current;
          const hand = handRef.current;
          const distToHand = Math.hypot(cat.x - hand.x, cat.y - hand.y);
          const isInteracting = (touchRef.current.active || keysPressed.current['Space']) && distToHand < CAT_RADIUS * 2;

          if (isInteracting) {
              if (frameCount.current % 10 === 0) { 
                  spawnParticles(cat.x, cat.y - 50 * cat.scale, '#ff6b6b', 1, 'heart');
                  audio.playLoveSound(); 
              }
          }

          drawBathtub(ctx);
          drawCat(ctx, cat);
          drawHand(ctx, handRef.current.x, handRef.current.y, false);

          heartsRef.current.forEach((p, i) => {
            p.y -= 2; 
            p.x += Math.sin(frameCount.current * 0.1 + i) * 0.5;
            p.life -= 0.02;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.font = '24px Arial';
            ctx.fillText('♥', p.x, p.y);
            ctx.globalAlpha = 1;
          });
          heartsRef.current = heartsRef.current.filter(p => p.life > 0);

          if (pettingTimerRef.current <= 0) {
              pettingModeRef.current = false;
              // Calculate Time Elapsed
              finalTimeRef.current = (Date.now() - startTimeRef.current) / 1000;
              onWin(finalTimeRef.current);
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      // Window Open / Freedom Sequence logic using Refs for up-to-date state
      if (!isWindowOpenRef.current && !pettingModeRef.current && winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0 && windowOpenSequenceRef.current === 0) {
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winSize = 200;
          const hand = handRef.current;
          const cat = catRef.current;

          const overWindow = hand.x > winX && hand.x < winX + winSize && hand.y > winY && hand.y < winY + winSize;

          // Mobile: If holding cat (caught mode) and dragged over window area
          const isMobileHolding = isMobile && cat.mode === 'caught';

          if (overWindow && (keysPressed.current['Space'] || isMobileHolding)) {
              setIsWindowOpen(true);
              windowOpenSequenceRef.current = 120; // Start freedom sequence
              audio.playFunnyEscape(); 
          }
      }

      if (windowOpenSequenceRef.current > 0) {
          windowOpenSequenceRef.current--;
          const cat = catRef.current;
          const winX = isMobile ? 50 : 100;
          const winY = isMobile ? 150 : 180;
          const winCenterX = winX + 100;
          const winCenterY = winY + 100;

          cat.x += (winCenterX - cat.x) * 0.1;
          cat.y += (winCenterY - cat.y) * 0.1;
          cat.scale *= 0.95;
          cat.angle += 0.2;

          drawBathtub(ctx);
          drawCat(ctx, cat);

          if (windowOpenSequenceRef.current === 1) {
              onGameOver(TRANSLATIONS[language].free_msg, 'free');
              return;
          }
          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      if (tubBrokenSequenceRef.current > 0) {
        tubBrokenSequenceRef.current--;
        const cat = catRef.current;
        cat.x = CURRENT_BATHTUB.x + CURRENT_BATHTUB.width / 2;
        cat.y = CURRENT_BATHTUB.y + CURRENT_BATHTUB.height / 2 - 20; 
        cat.vx = 0; cat.vy = 0;

        drawBathtub(ctx, true); 
        drawCat(ctx, cat);

        if (frameCount.current % 10 === 0) {
             spawnParticles(CURRENT_BATHTUB.x + CURRENT_BATHTUB.width/2, CURRENT_BATHTUB.y + CURRENT_BATHTUB.height/2, '#bdc3c7', 2);
        }
        particlesRef.current.forEach((p, i) => {
            p.x += p.vx; p.y += p.vy; p.life -= 0.04;
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
            ctx.fill();
            ctx.globalAlpha = 1;
        });
        particlesRef.current = particlesRef.current.filter(p => p.life > 0);

        if (tubBrokenSequenceRef.current === 1) {
             onGameOver(TRANSLATIONS[language].fat_tub_msg, 'tub');
             return;
        }
        animationFrameId = requestAnimationFrame(loop);
        return;
      }

      if (isRollingAwayRef.current) {
          const cat = catRef.current;
          cat.x += 8; 
          cat.angle += 0.1;

          drawBathtub(ctx); 

          const rect = canvas.getBoundingClientRect();
          const scaleX = rect.width / GAME_WIDTH;
          const scaleY = rect.height / GAME_HEIGHT;

          oCtx.save();
          oCtx.translate(rect.left, rect.top);
          oCtx.scale(scaleX, scaleY);
          drawCat(oCtx, cat);
          oCtx.restore();

          const catScreenX = rect.left + cat.x * scaleX;
          const catRadiusScreen = (CAT_RADIUS * cat.scale) * scaleX;

          if (catScreenX - catRadiusScreen > window.innerWidth) {
               onGameOver(TRANSLATIONS[language].fat_roll_msg, 'roll');
               return; 
          }

          animationFrameId = requestAnimationFrame(loop);
          return;
      }

      const isGrabbing = !!keysPressed.current['Space'] || touchRef.current.isPinching;
      const cat = catRef.current;

      const distToFood = Math.hypot(cat.x - CURRENT_FOOD_BOWL.x, cat.y - CURRENT_FOOD_BOWL.y);
      const eatingReach = (CAT_RADIUS * cat.scale) + 60; 

      if (distToFood < eatingReach && cat.mode !== 'caught' && now - lastEatTime.current > 1000) {
          lastEatTime.current = now;
          audio.playEat();
          cat.scale += 0.3; 
          spawnParticles(CURRENT_FOOD_BOWL.x, CURRENT_FOOD_BOWL.y, '#8d6e63', 8);
          if (distToFood > 10) {
             cat.vx = (cat.x - CURRENT_FOOD_BOWL.x) * 0.1; 
             cat.vy = (cat.y - CURRENT_FOOD_BOWL.y) * 0.1;
          }
      }

      if (cat.scale > 7.5 && !isRollingAwayRef.current) {
          isRollingAwayRef.current = true;
          cat.mode = 'idle'; 
          audio.playBouncingSequence(); 
      }

      if (
        cat.x > CURRENT_BATHTUB.x && 
        cat.x < CURRENT_BATHTUB.x + CURRENT_BATHTUB.width && 
        cat.y > CURRENT_BATHTUB.y && 
        cat.y < CURRENT_BATHTUB.y + CURRENT_BATHTUB.height &&
        !isGrabbing &&
        cat.mode === 'caught'
      ) {
          if (cat.scale > 3.0) {
              if (tubBrokenSequenceRef.current === 0) {
                 audio.playCrack();
                 audio.playFailDescending(); 
                 tubBrokenSequenceRef.current = 120; 
              }
          } else {
            audio.playSplash();
            audio.playWinAscending(); 
            winSequenceRef.current = 180; 
          }
      }

      if (winSequenceRef.current === 0 && tubBrokenSequenceRef.current === 0 && bathExitSequenceRef.current === 0) {
          const distToHand = Math.hypot(cat.x - handRef.current.x, cat.y - handRef.current.y);

          const rugX = GAME_WIDTH / 2;
          const rugY = isMobile ? GAME_HEIGHT / 2 : GAME_HEIGHT / 2 + 100;

          const dx = cat.x - rugX;
          const dy = cat.y - rugY;
          const angle = isMobile ? -Math.PI/2 : -0.1;
          const rx = dx * Math.cos(angle) - dy * Math.sin(angle);
          const ry = dx * Math.sin(angle) + dy * Math.cos(angle);

          const onRug = (rx * rx) / (280 * 280) + (ry * ry) / (130 * 130) <= 1;

          if (onRug && (Math.abs(cat.vx) > 0.5 || Math.abs(cat.vy) > 0.5) && frameCount.current % 12 === 0) {
             pawPrintsRef.current.push({
                 x: rx, 
                 y: ry,
                 angle: Math.atan2(cat.vy, cat.vx) - (isMobile ? Math.PI/2 : 0.1), 
                 life: 1.0
             });
          }

          pawPrintsRef.current.forEach(p => p.life -= 0.005);
          pawPrintsRef.current = pawPrintsRef.current.filter(p => p.life > 0);

          const plantX = isMobile ? 300 : GAME_WIDTH - 100;
          const plantY = isMobile ? 250 : 180;

          if (!plantTrimmedRef.current) {
              const distToPlant = Math.hypot(cat.x - plantX, cat.y - plantY);
              if (distToPlant < 80) {
                  plantTrimmedRef.current = true;
                  spawnParticles(plantX, plantY, CRAYON.green, 15);
                  audio.playScratch(); 
              }
          }

          const adjustedCatchDist = (CAT_RADIUS * cat.scale) + (isMobile ? 50 : 30); 

          if (isGrabbing && distToHand < adjustedCatchDist) {
            if (cat.mode !== 'caught') {
                cat.mode = 'caught';
                manicTimer.current = 0;
                audio.playCaughtSound(); 
            }
            cat.x = handRef.current.x;
            cat.y = handRef.current.y + 40 * cat.scale; 
            cat.vx = 0; cat.vy = 0;
          } else {
            if (cat.mode === 'caught') {
                cat.mode = 'run';
                cat.vx = (Math.random() - 0.5) * 20;
                cat.vy = (Math.random() - 0.5) * 20;
            }
          }

          const manicProb = 0.1 + (temperament * 0.1);
          const manicThreshold = 1.0 - manicProb;

          if (frameCount.current % 600 === 0 && Math.random() > manicThreshold && cat.mode !== 'caught') {
            cat.mode = 'manic';
            manicTimer.current = 240;
            audio.playHiss();
            generateCatThought('manic', hpRef.current, language).then(setCatThought);
            lastThoughtTime.current = now;
          }

          if (manicTimer.current > 0) {
            manicTimer.current--;
            if (manicTimer.current <= 0) cat.mode = 'idle';
          }

          if (cat.mode !== 'caught') {
              let difficultyMultiplier = 1.0;
              if (temperament >= 8) difficultyMultiplier = 1.6;
              else if (temperament >= 5) difficultyMultiplier = 1.2;

              const speedMultiplier = (temperament / 3) * difficultyMultiplier;
              const moveSpeed = (cat.mode === 'manic' ? 9 : (cat.mode === 'run' ? 6 : 2)) * speedMultiplier;

              if (cat.mode === 'manic') {
                  const angle = Math.atan2(handRef.current.y - cat.y, handRef.current.x - cat.x);
                  cat.vx += Math.cos(angle) * 1 * speedMultiplier; 
                  cat.vy += Math.sin(angle) * 1 * speedMultiplier;

                  const hitRadius = 50 * cat.scale;
                  if (distToHand < hitRadius && (now - lastDamageTime.current > 800)) {
                      hpRef.current--;
                      setCurrentHp(hpRef.current);
                      lastDamageTime.current = now; 

                      const ouchMsgs = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
                      const idx = Math.floor(Math.random() * ouchMsgs.length);
                      setOwnerMessages(prev => [
                        ...prev, 
                        {
                          id: Date.now(),
                          type: 'ouch',
                          index: idx,
                          x: 20 + Math.random() * 20, 
                          y: GAME_HEIGHT - 100 
                        }
                      ]);

                      audio.playScratch();
                      spawnParticles(handRef.current.x, handRef.current.y, CRAYON.red, 8);
                      cat.vx *= -2; cat.vy *= -2;
                      if (hpRef.current <= 0) {
                          audio.playCatSinging(); 
                          onGameOver(TRANSLATIONS[language].caught_msg, 'caught'); 
                      }
                  }
              } else {
                  if (distToHand < 250) {
                      cat.mode = 'run';
                      const angle = Math.atan2(cat.y - handRef.current.y, cat.x - handRef.current.x);
                      cat.vx += Math.cos(angle) * 0.8 * speedMultiplier;
                      cat.vy += Math.sin(angle) * 0.8 * speedMultiplier;
                  } else if (cat.mode === 'run') {
                      cat.vx *= 0.92; cat.vy *= 0.92;
                      if (Math.abs(cat.vx) < 0.5) cat.mode = 'idle';
                  } else if (cat.mode === 'idle' && Math.random() < 0.02) {
                       cat.vx += (Math.random() - 0.5) * 4;
                       cat.vy += (Math.random() - 0.5) * 4;
                  }
              }
              cat.vx = Math.max(Math.min(cat.vx, moveSpeed), -moveSpeed);
              cat.vy = Math.max(Math.min(cat.vy, moveSpeed), -moveSpeed);
              cat.x += cat.vx;
              cat.y += cat.vy;

              const r = CAT_RADIUS * cat.scale;
              if (cat.x < r) { cat.x = r; cat.vx *= -1; }
              if (cat.x > GAME_WIDTH - r) { cat.x = GAME_WIDTH - r; cat.vx *= -1; }
              if (cat.y < r) { cat.y = r; cat.vy *= -1; }
              if (cat.y > GAME_HEIGHT - r) { cat.y = GAME_HEIGHT - r; cat.vy *= -1; }
          }
      }

      if (now - lastThoughtTime.current > 8000 && cat.mode !== 'caught' && winSequenceRef.current === 0) {
          if ((cat.mode === 'idle' && Math.random() > 0.6) || (cat.mode === 'run' && Math.random() > 0.7)) {
             generateCatThought(cat.mode, hpRef.current, language).then(setCatThought);
             lastThoughtTime.current = now;
             if (cat.mode === 'idle') audio.playVariedMeow(catType); 
          }
      }

      drawBathtub(ctx, tubBrokenSequenceRef.current > 0);
      drawCat(ctx, cat);
      drawHand(ctx, handRef.current.x, handRef.current.y, isGrabbing);

      particlesRef.current.forEach((p, i) => {
        p.x += p.vx; p.y += p.vy; p.life -= 0.04;
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y); ctx.lineTo(p.x + 5, p.y + 2); ctx.lineTo(p.x + 2, p.y + 5);
        ctx.fill();
        ctx.globalAlpha = 1;
      });
      particlesRef.current = particlesRef.current.filter(p => p.life > 0);

      animationFrameId = requestAnimationFrame(loop);
    };

    animationFrameId = requestAnimationFrame(loop);

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
        window.removeEventListener('resize', resizeOverlay);
        if (canvas) {
            canvas.removeEventListener('touchmove', handleTouchMove);
            window.removeEventListener('touchstart', onTouchStart); // Clean up custom handler
            window.removeEventListener('touchend', onTouchEnd);
            canvas.removeEventListener('click', handleCanvasClick);
        }

        cancelAnimationFrame(animationFrameId);
    };
  }, [onGameOver, onWin, catType, temperament, language, isMobile]);

  return (
    <div className={`relative w-full h-full flex items-center justify-center ${language === 'zh' ? "font-['ZCOOL_KuaiLe']" : language === 'ja' ? "font-['Kiwi_Maru']" : language === 'ru' ? "font-['Balsamiq_Sans']" : "font-['Chewy']"}`}>
      {/* Overlay Canvas for rolling out of screen logic */}
      <canvas 
        ref={overlayCanvasRef}
        className="fixed top-0 left-0 w-full h-full pointer-events-none z-50"
      />

      <canvas 
        ref={canvasRef} 
        width={isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH} 
        height={isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT}
        className="max-w-full max-h-full cursor-none touch-none"
        style={{ filter: 'contrast(1.05)' }}
      />

      {/* HP Bar */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 p-2 md:p-4 pointer-events-none bg-white/80 backdrop-blur-sm rounded-xl border-2 border-black rotate-1 shadow-md scale-75 md:scale-100 origin-top-left">
        <div className="text-4xl font-bold text-gray-800 flex items-center gap-4">
          <span className="font-sketch">HP:</span>
          <div className="flex gap-1">
            {Array.from({ length: MAX_HP }).map((_, i) => (
              <span key={i} className={`transform transition-all duration-300 ${i < currentHp ? 'text-[#ff6b6b] scale-100' : 'text-gray-300 scale-75 blur-sm'}`} style={{ textShadow: i < currentHp ? '2px 2px 0 #000' : 'none' }}>
                ♥
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Owner Messages (Floating Bubbles on Left) - DYNAMIC TEXT RENDERING */}
      {ownerMessages.map((msg) => {
        // Resolve text based on current language prop
        let text = "";
        if (msg.type === 'bath') {
           const list = TRANSLATIONS[language].bath_messages;
           const safeIndex = msg.index % list.length;
           text = list[safeIndex] + " ♥";
        } else {
           const list = TRANSLATIONS[language].ouch_messages || ["OUCH!"];
           const safeIndex = msg.index % list.length;
           text = list[safeIndex];
        }

        return (
        <div
          key={msg.id}
          onAnimationEnd={() => {
            setOwnerMessages(prev => prev.filter(m => m.id !== msg.id));
          }}
          className="absolute bg-white border-4 border-black px-4 py-2 md:px-6 md:py-4 rounded-2xl shadow-lg flex items-center gap-2 animate-[floatUpFade_3s_ease-out_forwards] pointer-events-none origin-bottom-left z-40"
          style={isMobile ? {
            top: '10%',
            left: '50%',
            transform: 'translateX(-50%)' // Center at top for mobile
          } : { 
             top: msg.y,
             left: msg.x
          }}
        >
          <span className="text-xl md:text-2xl font-bold font-sans text-gray-800 whitespace-nowrap">{text}</span>
          {!isMobile && <div className="absolute bottom-[-10px] left-4 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45"></div>}
        </div>
        );
      })}

      {/* Cat Thought Bubble */}
      {catThought && (
        <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-[50%] shadow-lg transition-all duration-500 animate-pulse z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            // On mobile, force thought bubbles higher so they aren't covered by thumb/cat
            top: isMobile 
                 ? '15%' 
                 : ((catRef.current.y - 90 * catRef.current.scale) / CANVAS_HEIGHT) * 100 + '%', 
            transform: 'translate(-50%, -100%) rotate(-2deg)'
          }}
        >
          <div className="text-lg md:text-xl font-bold text-black whitespace-nowrap font-sketch">{catThought}</div>
          <div className="absolute bottom-[-15px] left-1/2 w-6 h-6 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2 rounded-br-lg"></div>
        </div>
      )}

      {/* Bath Emote Bubble */}
      {bathEmote && (
         <div 
          className="absolute pointer-events-none bg-white border-4 border-black p-3 md:p-4 rounded-xl shadow-xl animate-bounce z-40"
          style={{
            left: (catRef.current.x / (isMobile ? MOBILE_CANVAS_WIDTH : CANVAS_WIDTH)) * 100 + '%',
            top: ((catRef.current.y - 120 * catRef.current.scale) / (isMobile ? MOBILE_CANVAS_HEIGHT : CANVAS_HEIGHT)) * 100 + '%',
            transform: 'translate(-50%, -100%)'
          }}
        >
          <div className="text-2xl md:text-3xl font-bold text-black whitespace-nowrap font-sans">{bathEmote}</div>
          <div className="absolute bottom-[-10px] left-1/2 w-4 h-4 bg-white border-r-4 border-b-4 border-black transform rotate-45 -translate-x-1/2"></div>
        </div>
      )}

      <style>{`
        @keyframes floatUpFade {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          10% { transform: translateY(-20px) scale(1.1); opacity: 1; }
          90% { transform: translateY(-150px) scale(1); opacity: 1; }
          100% { transform: translateY(-180px) scale(0.9); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

